import React, { useState, useEffect, useRef } from "react";

// ═══════════════════════════════════════════════════════════
// WIREREADY PRO — 462-QUESTION CA ELECTRICIAN EXAM PREP APP
// All questions original field knowledge, no NEC text reproduced
// ═══════════════════════════════════════════════════════════

const ALL_QUESTIONS = [
// MODULE 1: DEFINITIONS & GENERAL (30)
{id:1,mod:1,cat:"Definitions",diff:"Easy",q:"What is the definition of 'ampacity'?",opts:["Resistance per 1,000 feet","Cross-sectional area in circular mils","Current in amperes a conductor can carry continuously without exceeding its temperature rating","Max voltage a conductor can carry"],ans:2,ref:"NEC Article 100",exp:"Ampacity = current a conductor carries continuously without exceeding its temperature rating. Drives all conductor sizing decisions."},
{id:2,mod:1,cat:"Definitions",diff:"Easy",q:"Which article contains primary NEC definitions?",opts:["Article 90","Article 100","Article 110","Article 200"],ans:1,ref:"NEC Article 100",exp:"Article 100 = primary definitions. Article 90 = purpose/scope. Know Article 100 cold — foundation for every other article."},
{id:3,mod:1,cat:"Definitions",diff:"Easy",q:"What must a 'dwelling unit' have dedicated space for per the NEC?",opts:["Two or more separate living units","Human habitation","Any overnight occupancy","Eating, living, sleeping, AND permanent cooking facilities"],ans:3,ref:"NEC Article 100",exp:"Dwelling unit requires ALL four: eating, living, sleeping, permanent cooking. Hotel rooms don't qualify — no permanent cooking. Critical for determining which NEC rules apply."},
{id:4,mod:1,cat:"Definitions",diff:"Easy",q:"How is 'Authority Having Jurisdiction' (AHJ) defined in the NEC?",opts:["Organization or individual responsible for enforcing the NEC","Utility company","NFPA committee","Licensed contractor"],ans:0,ref:"NEC Article 100",exp:"AHJ = enforcing authority, typically the local electrical inspector. Has final say on code interpretation and can approve alternatives."},
{id:5,mod:1,cat:"Definitions",diff:"Easy",q:"What conductors make up a 'feeder'?",opts:["Conductors from transformer to meter","Conductors between two panels","All conductors between service equipment and the final branch circuit overcurrent device","Any conductor larger than 10 AWG"],ans:2,ref:"NEC Article 100",exp:"Feeder = conductors between service equipment and the final OCPD. Feeders supply panelboards; branch circuits supply loads."},
{id:6,mod:1,cat:"Definitions",diff:"Easy",q:"What conductors make up a 'branch circuit'?",opts:["Any conductor under 100A","Conductors between the final overcurrent device and the outlet(s)","Any wiring within a dwelling","Conductors from utility to service panel"],ans:1,ref:"NEC Article 100",exp:"Branch circuit = conductors between the FINAL overcurrent device and outlet(s). Determines which Article 210 rules apply."},
{id:7,mod:1,cat:"Definitions",diff:"Medium",q:"What does an 'individual branch circuit' supply?",opts:["A single appliance rated over 1,000 watts","Only lighting loads","Multiple general-purpose receptacles","Only one piece of utilization equipment"],ans:3,ref:"NEC Article 100",exp:"Individual branch circuit = one piece of utilization equipment only. Examples: dedicated refrigerator, single motor circuit."},
{id:8,mod:1,cat:"Definitions",diff:"Medium",q:"What qualifications does a 'qualified person' have per Article 100?",opts:["Skills, knowledge of electrical equipment, and safety training to recognize and avoid hazards","An electrical engineering degree","5+ years of experience","Any valid electrician license"],ans:0,ref:"NEC Article 100",exp:"Qualified person = training, knowledge, AND safety training for the specific voltage/equipment. Licensure alone isn't enough for every task."},
{id:9,mod:1,cat:"Definitions",diff:"Medium",q:"The minimum working space depth in front of a 480V panel (live parts one side, grounded parts other — Condition 2) is _____.",opts:["2.5 feet","4 feet","3.5 feet","3 feet"],ans:2,ref:"NEC 110.26(A)(1), Table 110.26(A)(1)",exp:"151–600V, Condition 2 = 3.5 feet. Condition 1 = 3 feet, Condition 3 = 4 feet. Table 110.26 is heavily tested on the CA exam."},
{id:10,mod:1,cat:"Definitions",diff:"Medium",q:"The minimum headroom required in front of service equipment is _____.",opts:["7 feet","6 feet 6 inches","6 feet 3 inches","6 feet"],ans:1,ref:"NEC 110.26(E)",exp:"Minimum headroom = 6 feet 6 inches for service equipment, switchboards, panelboards, and MCCs."},
{id:11,mod:1,cat:"Definitions",diff:"Medium",q:"Which is PERMITTED in the dedicated electrical working space?",opts:["Storing electrical materials","Foreign systems above the equipment","Piping and ducts in the space","None — must be completely clear"],ans:3,ref:"NEC 110.26(B) & 110.26(F)",exp:"Dedicated space must be free from piping, ducts, and foreign systems. Storage never permitted. Most commonly cited code violation during inspections."},
{id:12,mod:1,cat:"Definitions",diff:"Medium",q:"Under what condition is equipment required by the NEC considered acceptable?",opts:["Approved by the AHJ","Listed by a testing laboratory","Manufactured per industry standards","Approved by the installer"],ans:0,ref:"NEC 110.2",exp:"Equipment must be approved by the AHJ. Listed equipment is generally accepted but AHJ has ultimate authority."},
{id:13,mod:1,cat:"Definitions",diff:"Easy",q:"What is the stated purpose of the NEC per Article 90?",opts:["Comprehensive electrical design guide","Standardizing equipment for manufacturing","Practical safeguarding of persons and property from electrical hazards","Specifying the most economical methods"],ans:2,ref:"NEC 90.1",exp:"NEC purpose = practical safeguarding of persons and property from electrical hazards. Minimum safety requirements — better designs may exceed code."},
{id:14,mod:1,cat:"Definitions",diff:"Easy",q:"What is the standard residential service voltage in the US?",opts:["277/480V three-phase","120/240V single-phase three-wire","110/220V single-phase","208/120V three-phase"],ans:1,ref:"NEC Article 100",exp:"Standard residential = 120/240V single-phase three-wire. 240V for large appliances; 120V for lighting and receptacles."},
{id:15,mod:1,cat:"Definitions",diff:"Medium",q:"What is the required width of working space in front of electrical equipment?",opts:["At least 24 inches","At least 36 inches regardless of equipment width","Equal to width of equipment","Width of equipment or 30 inches, whichever is greater"],ans:3,ref:"NEC 110.26(A)(2)",exp:"Working space width = equipment width OR 30 inches, whichever is greater."},
{id:16,mod:1,cat:"Definitions",diff:"Hard",q:"How is 'continuous load' defined in the NEC?",opts:["Maximum current expected to continue for 3 hours or more","Never cycles off","Connected directly to service entrance","Operates 24 hours"],ans:0,ref:"NEC Article 100",exp:"Continuous load = maximum current for 3+ hours. Triggers the 80% loading rule. Examples: commercial lighting, HVAC, signs."},
{id:17,mod:1,cat:"Definitions",diff:"Medium",q:"What does 'listed' mean when applied to electrical equipment?",opts:["Tested by local inspector","Manufactured by a certified company","Included in a list by an organization confirming it meets applicable standards","Approved by NFPA"],ans:2,ref:"NEC Article 100",exp:"Listed = appears on a published list from a recognized testing organization (UL, ETL, CSA) confirming it meets applicable standards."},
{id:18,mod:1,cat:"Definitions",diff:"Easy",q:"What is the difference between 'grounded' and 'grounding' conductors?",opts:["Same — both are the neutral","Grounded conductor (neutral) carries normal current; grounding conductor (EGC) provides fault current path","No difference — interchangeable","Grounded = connected to earth; grounding = connected to neutral"],ans:1,ref:"NEC Article 100",exp:"Grounded conductor (neutral) = carries normal return current. EGC = safety conductor for fault current only, no normal current. Confusing these is a dangerous and common mistake."},
{id:19,mod:1,cat:"Definitions",diff:"Medium",q:"How is a 'separately derived system' defined?",opts:["A system with its own grounding electrode","Any transformer installation","Any generator-derived system","Electrical source with no direct metallic connection from its circuit conductors to circuit conductors of another system"],ans:3,ref:"NEC Article 100",exp:"Separately derived system = no direct metallic connection between its circuit conductors and another system's conductors (except through grounding). Requires its own grounding electrode."},
{id:20,mod:1,cat:"Definitions",diff:"Hard",q:"What illumination is required at electrical equipment working spaces?",opts:["Lighting must be provided for service equipment, switchboards, and panelboards","No minimum specified","Sufficient as determined by AHJ","50 foot-candles minimum"],ans:0,ref:"NEC 110.26(D)",exp:"Illumination required for service equipment, switchboards, panelboards, and MCC working spaces. Light switch must not require entering the working space to operate."},
{id:21,mod:1,cat:"Definitions",diff:"Medium",q:"Which installation is NOT covered by the NEC?",opts:["Recreational vehicles","Agricultural buildings","Ships and watercraft","Manufactured homes"],ans:2,ref:"NEC 90.2(B)",exp:"Ships and watercraft excluded from NEC scope, along with railway rolling stock, aircraft, and automotive vehicles. Agricultural buildings, manufactured homes, and RVs ARE covered."},
{id:22,mod:1,cat:"Definitions",diff:"Easy",q:"How is a 'panelboard' defined per Article 100?",opts:["Any panel rated over 200 amperes","Panel assembly accessible from the front, in a cabinet or cutout box, containing buses and overcurrent devices","Switchboard used in industrial facilities","Any metal enclosure containing electrical equipment"],ans:1,ref:"NEC Article 100",exp:"Panelboard = front-accessible panel assembly with buses and overcurrent devices in a cabinet. Differs from switchboards (accessible front and rear)."},
{id:23,mod:1,cat:"Definitions",diff:"Medium",q:"What encroachment is permitted in dedicated electrical space?",opts:["25% of required width","Space above equipment may have encroachments","Only prohibited directly in front of equipment","None — no encroachment permitted"],ans:3,ref:"NEC 110.26(F)(1)",exp:"Dedicated electrical space (floor to 6 feet above equipment or ceiling, whichever is lower) must be completely free. No encroachments permitted. Period."},
{id:24,mod:1,cat:"Definitions",diff:"Hard",q:"What is the termination temperature rating rule under Article 110.14?",opts:["Ampacity at terminations based on LOWEST temperature rating of conductor, termination, or device","Always use 60°C column at terminations","Temperature ratings need not be matched if conductors are properly sized","Always use 75°C column"],ans:0,ref:"NEC 110.14(C)",exp:"Termination rule: lowest temperature rating wins. A 90°C conductor at a 60°C lug = use 60°C ampacity from Table 310.16. This causes many undersized connections in the field."},
{id:25,mod:1,cat:"Definitions",diff:"Medium",q:"What does 'in sight from' mean per the NEC?",opts:["Visible from any point in the building","Able to be seen without optical instruments","Visible AND not more than 50 feet distant","Within 10 feet direct line of sight"],ans:2,ref:"NEC Article 100",exp:"In sight from = visible AND ≤50 feet. Both conditions required. A disconnect 75 feet away even if visible is NOT 'in sight from' the motor."},
{id:26,mod:1,cat:"Definitions",diff:"Easy",q:"The nominal voltage of commercial lighting on a 277/480V three-phase system is _____.",opts:["240V","277V","120V","208V"],ans:1,ref:"NEC Article 100",exp:"In 480V three-phase commercial systems, lighting circuits operate at 277V (phase-to-neutral). Hence commercial 277V fluorescent and LED fixtures."},
{id:27,mod:1,cat:"Definitions",diff:"Hard",q:"What requirement must field-installed wire connectors meet?",opts:["Splices only in boxes","Any approved wire nut for any conductor","Only copper conductors may be spliced","Listed and suitable for the application, conductor material, and temperature rating"],ans:3,ref:"NEC 110.14(A)",exp:"Wire connectors must be listed and suitable for: specific application, conductor material (copper vs aluminum), and temperature rating. Wrong connector on aluminum = fire hazard."},
{id:28,mod:1,cat:"Definitions",diff:"Medium",q:"Service conductors must maintain a minimum clearance of _____ from an openable window.",opts:["3 feet","Service conductors may not pass near openable windows","24 inches","12 inches"],ans:0,ref:"NEC 230.9(A)",exp:"Service entrance conductors = 3 feet minimum from openable windows, doors, porches, balconies, and fire escapes. Conductors passing above the top of a window are exempt."},
{id:29,mod:1,cat:"Definitions",diff:"Easy",q:"Who publishes the NEC?",opts:["OSHA","ANSI","NFPA (National Fire Protection Association)","IEEE"],ans:2,ref:"NEC 90.1",exp:"NEC published by NFPA (National Fire Protection Association). ANSI approves it as ANSI/NFPA 70. Updated every 3 years. NFPA publishes; AHJ enforces."},
{id:30,mod:1,cat:"Definitions",diff:"Medium",q:"Under what condition may conductors of different voltage systems share a raceway?",opts:["Never — different voltage systems must be separate","All conductors are insulated for the maximum voltage present","Separated by a metallic barrier","Combined load doesn't exceed fill limit"],ans:1,ref:"NEC 300.3(C)(1)",exp:"Different voltage systems may share a raceway if ALL conductors are insulated for the maximum voltage present. 120V and 277V can share a conduit if all are rated ≥277V."},
// MODULE 2: WIRING & OVERCURRENT (45)
{id:31,mod:2,cat:"Wiring & Overcurrent",diff:"Easy",q:"A dwelling unit kitchen requires a minimum of _____ small appliance branch circuits rated at 20A.",opts:["One circuit","At least two 20A circuits","Three per California code","No specific number required"],ans:1,ref:"NEC 210.11(C)(1)",exp:"At least two 20-ampere small appliance branch circuits are required for kitchen, dining room, pantry, and similar areas. Cannot supply loads other than small appliances in these rooms."},
{id:32,mod:2,cat:"Wiring & Overcurrent",diff:"Easy",q:"The maximum continuous load on a 20A, 120V branch circuit is _____.",opts:["1,440 watts","2,000 watts","1,920 watts","2,400 watts"],ans:2,ref:"NEC 210.20(A)",exp:"Continuous loads = 80% max. 20A × 120V × 0.80 = 1,920 VA. The 80%/125% rule for continuous loads is one of the most tested calculation concepts on the CA exam."},
{id:33,mod:2,cat:"Wiring & Overcurrent",diff:"Medium",q:"In which dwelling locations does the 2020 NEC require GFCI protection?",opts:["All receptacles in the dwelling","Bathrooms and kitchens only","Living rooms only","Bathrooms, garages, outdoors, crawl spaces, unfinished basements, kitchen near sinks, and boathouses"],ans:3,ref:"NEC 210.8(A)",exp:"2020 NEC expanded GFCI locations. Full list: bathrooms, garages, outdoors, crawl spaces, unfinished basements, kitchen countertop surfaces within 6 feet of sinks, boathouses, and washing machine locations."},
{id:34,mod:2,cat:"Wiring & Overcurrent",diff:"Medium",q:"In which dwelling rooms does the 2020 NEC require AFCI protection for 120V 15A/20A circuits?",opts:["All rooms in the dwelling unit","Bedrooms and living rooms only","Bedrooms only","Only rooms with sleeping occupants"],ans:0,ref:"NEC 210.12(A)",exp:"2020 NEC expanded AFCI to ALL rooms in dwelling units — not just bedrooms as in earlier editions. Includes living rooms, dining rooms, kitchens, hallways, closets."},
{id:35,mod:2,cat:"Wiring & Overcurrent",diff:"Medium",q:"What is the maximum spacing allowed between dwelling unit wall receptacle outlets?",opts:["12 feet","No point along the floor line more than 6 feet from an outlet","No point along the floor line more than 12 feet from an outlet","6 feet"],ans:1,ref:"NEC 210.52(A)(1)",exp:"No point along the floor line can be more than 6 feet from an outlet, measured along the floor. Results in outlets no more than 12 feet apart. Any wall space 2 feet or wider requires an outlet."},
{id:36,mod:2,cat:"Wiring & Overcurrent",diff:"Medium",q:"What is the countertop receptacle spacing rule for kitchens per 210.52(C)(1)?",opts:["Within 2 feet along the wall","No point along the countertop wall line may be more than 24 inches from a receptacle","Within 24 inches of the sink edge","No minimum — anywhere on countertop"],ans:1,ref:"NEC 210.52(C)(1)",exp:"No point along the kitchen countertop wall line may be more than 24 inches measured horizontally from a receptacle. This is a wall-line spacing rule — not a sink proximity rule. Receptacles are NOT required directly behind a sink (that area is exempted per the Exception)."},
{id:37,mod:2,cat:"Wiring & Overcurrent",diff:"Easy",q:"Where must bathroom receptacle outlets be located?",opts:["Adjacent to the mirror","Anywhere in the bathroom","Adjacent to the toilet","Within 36 inches of the outside edge of each basin"],ans:3,ref:"NEC 210.52(D)",exp:"At least one receptacle within 36 inches of the outside edge of EACH basin — measured from the basin edge, not along the wall. Corner vanities need a receptacle within 36 inches of each basin."},
{id:38,mod:2,cat:"Wiring & Overcurrent",diff:"Medium",q:"Under what condition does the 'next size up' rule allow a larger standard overcurrent device?",opts:["Conductor ampacity doesn't correspond to a standard overcurrent device rating AND the circuit isn't a motor branch circuit or feeder","Calculated load exceeds conductor ampacity","For any residential circuit up to 30 amperes","When the inspector approves a larger device"],ans:0,ref:"NEC 240.4(B)",exp:"Next-size-up rule: conductor ampacity doesn't match a standard size → use next larger standard size. Conditions: not a motor branch circuit, next size doesn't exceed 800A."},
{id:39,mod:2,cat:"Wiring & Overcurrent",diff:"Hard",q:"Which common residential sizes are listed as standard overcurrent device ratings in Article 240?",opts:["Only UL-listed ratings","15, 20, 25, 30, 35, 40, 45, 50, 60, 70, 80, 90, 100, 110, 125, 150, 175, 200 amperes and more","Any round number","Any rating matching the connected load"],ans:1,ref:"NEC 240.6(A)",exp:"Standard sizes are specified. Know the common residential sizes: 15, 20, 25, 30, 35, 40, 45, 50, 60, 70, 80, 90, 100, 110, 125, 150, 175, 200A. Critical for next-size-up rule application."},
{id:40,mod:2,cat:"Wiring & Overcurrent",diff:"Medium",q:"What rating must a circuit breaker have when used as a switch for 125V fluorescent lighting?",opts:["A GFCI type","A separate disconnect is required — breakers can't be switches","Rated SWD (Switching Duty) for this application","Any breaker may be used as a switch"],ans:2,ref:"NEC 240.83(D)",exp:"Circuit breakers used as switches for fluorescent lighting must be rated SWD (Switching Duty). Standard breakers aren't rated for repeated switching cycles under load."},
{id:41,mod:2,cat:"Wiring & Overcurrent",diff:"Medium",q:"What is required for a dedicated circuit supplying a household dishwasher?",opts:["Match the dishwasher nameplate rating","15A circuit is sufficient","Dishwashers must use small appliance circuits","20A individual branch circuit required"],ans:3,ref:"NEC 422.16(B)(2)",exp:"Dishwashers require a 20-ampere individual branch circuit. Cannot supply other loads. One of several appliances requiring individual circuits per NEC."},
{id:42,mod:2,cat:"Wiring & Overcurrent",diff:"Hard",q:"The maximum fuse rating for a 12 AWG copper THWN conductor is _____.",opts:["20 amperes","15 amperes","30 amperes","25 amperes"],ans:0,ref:"NEC 240.4(D)(5)",exp:"12 AWG THWN copper ampacity = 20A (Table 310.16, 75°C). Overcurrent device cannot exceed conductor ampacity. 20A is the absolute maximum. Using 25A or 30A on 12 AWG is dangerous overprotection."},
{id:43,mod:2,cat:"Wiring & Overcurrent",diff:"Medium",q:"What else may the laundry circuit for a dwelling supply?",opts:["A gas dryer","An adjacent receptacle outlet in the laundry area","Lighting in the laundry room","Nothing else — individual circuit required"],ans:1,ref:"NEC 210.11(C)(2)",exp:"The NEC requires at least one 20A circuit for laundry purposes. It can supply the laundry area receptacles (not individual circuit required for laundry unless for specific appliances like dishwashers or disposals)."},
{id:44,mod:2,cat:"Wiring & Overcurrent",diff:"Hard",q:"A household electric range rated at 8¾ kW or more requires a minimum circuit rating of _____.",opts:["30 amperes","60 amperes","40 amperes","50 amperes"],ans:2,ref:"NEC 210.19(A)(3)",exp:"Electric range rated ≥8¾ kW requires a branch circuit rated not less than 40A and not more than 50A. 50A is the typical residential range circuit."},
{id:45,mod:2,cat:"Wiring & Overcurrent",diff:"Medium",q:"What protection is required for 125V single-phase 15/20A receptacles in a commercial garage?",opts:["No special protection","Only receptacles within 6 feet of a drain","Only near water sources","GFCI protection for all 125V single-phase 15 and 20A receptacles"],ans:3,ref:"NEC 511.12",exp:"In commercial garages for vehicle service, ALL 125V, single-phase, 15 and 20-ampere receptacles require GFCI protection. Water from vehicle washing creates serious shock hazard."},
{id:46,mod:2,cat:"Wiring & Overcurrent",diff:"Medium",q:"A 4,500-watt, 240V residential electric water heater requires a minimum circuit ampacity of _____.",opts:["25 amperes","Size by nameplate only","30 amperes","20 amperes"],ans:0,ref:"NEC 422.13 & 210.20(A)",exp:"4,500W ÷ 240V = 18.75A × 125% (continuous) = 23.4A minimum. Next standard size = 25A. Water heaters are continuous loads."},
{id:47,mod:2,cat:"Wiring & Overcurrent",diff:"Hard",q:"What requirement must multiwire branch circuit breakers meet?",opts:["Standard individual breakers may be used","Have handle ties or two-pole breaker so all ungrounded conductors open simultaneously","Only one GFCI breaker needed","Connect to separate phases — individual breakers are fine"],ans:1,ref:"NEC 210.4(B)",exp:"2020 NEC: multiwire branch circuits must have a means to simultaneously disconnect all ungrounded conductors. Handle-tied pair or two-pole breaker required. Prevents dangerous partial de-energization."},
{id:48,mod:2,cat:"Wiring & Overcurrent",diff:"Medium",q:"Overhead conductors above a residential driveway must maintain a minimum clearance of _____.",opts:["15 feet","10 feet","18 feet","12 feet"],ans:3,ref:"NEC 230.24(B)(2)",exp:"Overhead service conductors over residential property and driveways require 12 feet minimum clearance. The 18-foot clearance applies to public streets, alleys, roads, and driveways on other than residential property. Know the difference — this is a common exam trap."},
{id:49,mod:2,cat:"Wiring & Overcurrent",diff:"Easy",q:"What circuit size is required for a dedicated bathroom receptacle circuit?",opts:["No dedicated circuit required","15 amperes minimum","Based on load calculation","20 amperes minimum"],ans:3,ref:"NEC 210.11(C)(3)",exp:"20-ampere circuit required for bathroom receptacle outlets. Cannot supply receptacles in other rooms. May serve receptacles in a single bathroom including bathroom lighting."},
{id:50,mod:2,cat:"Wiring & Overcurrent",diff:"Medium",q:"Where does the 2020 NEC require tamper-resistant receptacles?",opts:["In all 125V, 15 and 20A non-locking receptacles throughout the entire dwelling","Only in areas accessible to children","Only on circuits below 20A","Only in bathrooms and kitchens"],ans:0,ref:"NEC 406.12",exp:"Tamper-resistant receptacles required for ALL 125V, 15 and 20-ampere non-locking receptacles throughout the entire dwelling unit. All rooms, not just those with children."},
{id:51,mod:2,cat:"Wiring & Overcurrent",diff:"Hard",q:"Is it permitted for a 60A overcurrent device to protect a circuit with 55A-rated conductors?",opts:["Only with AHJ approval","Yes — next-size-up rule permits 60A since 55A doesn't correspond to a standard size","Yes — 60A is within 10% of the conductor ampacity","No — OCPD must not exceed conductor ampacity"],ans:1,ref:"NEC 240.4(B)",exp:"55A doesn't match a standard size (standard sizes: 50A and 60A). Next-size-up rule permits the 60A device here. Classic exam scenario — 55A conductor, 60A breaker is code-compliant."},
{id:52,mod:2,cat:"Wiring & Overcurrent",diff:"Medium",q:"The maximum cord length for a household garbage disposal is _____.",opts:["2 feet","18 inches","3 feet","4 feet"],ans:2,ref:"NEC 422.16(B)(1)",exp:"Maximum cord length for a garbage disposal = 3 feet. Must be connected to a 20A, 120V individual branch circuit."},
{id:53,mod:2,cat:"Wiring & Overcurrent",diff:"Hard",q:"What does 'inverse time' mean when describing a circuit breaker?",opts:["Doesn't trip on overloads, only short circuits","Takes longer to trip at higher currents","Resets automatically after a set time","Trips faster at higher overload currents"],ans:3,ref:"NEC Article 100 & 240.6",exp:"Inverse time = trips FASTER at higher currents. Small overload = minutes to trip; heavy overload = seconds; short circuit = nearly instantaneous. Allows current surges while protecting against sustained overheating."},
{id:54,mod:2,cat:"Wiring & Overcurrent",diff:"Medium",q:"A 5,000-watt, 240V residential clothes dryer requires a minimum circuit rating of _____.",opts:["30 amperes","20 amperes","125% of nameplate","40 amperes"],ans:0,ref:"NEC 210.23(B) & 220.54",exp:"Clothes dryers require minimum 30-ampere branch circuit (four-wire in new installations). NEC minimum of 30A governs even if the calculation yields less."},
{id:55,mod:2,cat:"Wiring & Overcurrent",diff:"Medium",q:"What outdoor receptacle is required for a single-family dwelling?",opts:["One at front or back","At least one at the front AND one at the back accessible at grade level","One per 1,000 sq ft of exterior wall","Two front and two back"],ans:1,ref:"NEC 210.52(E)(1)",exp:"At least one receptacle at the front AND one at the rear of single-family dwellings, accessible at grade level. Both must be GFCI protected. Balconies, decks, and porches also require receptacles."},
{id:56,mod:2,cat:"Wiring & Overcurrent",diff:"Hard",q:"What is special about a 20A receptacle versus a 15A receptacle?",opts:["Larger physical size","Requires a 4-wire connection","T-shaped (horizontal) slot on one hot slot to accept 20A plugs","Three slots instead of two"],ans:2,ref:"NEC 406.3(B)",exp:"20A receptacle has a T-shaped slot on one hot terminal to accept 20A plugs while still accepting standard 15A plugs. Required on 20A circuits where single-outlet use is expected."},
{id:57,mod:2,cat:"Wiring & Overcurrent",diff:"Easy",q:"How many circuits are required for the laundry area of a single-family dwelling?",opts:["One 15A circuit","No dedicated circuit required","Two — one for washer, one for dryer","At least one 20A circuit for laundry appliances"],ans:3,ref:"NEC 210.11(C)(2)",exp:"At least one 20-ampere branch circuit must serve laundry appliances. Cannot supply outlets in other areas."},
{id:58,mod:2,cat:"Wiring & Overcurrent",diff:"Medium",q:"In hotels and motels, what else may the bathroom receptacle circuit serve?",opts:["No more than one guest room bathroom","A dedicated 20A circuit for each room","Multiple rooms — same rules as dwelling units","GFCI receptacles on any circuit"],ans:0,ref:"NEC 210.11(C)(3) Exception",exp:"Hotel/motel bathroom circuits may serve the bathroom of no more than one guest room. Different from dwelling unit rules where one circuit can serve multiple bathrooms."},
{id:59,mod:2,cat:"Wiring & Overcurrent",diff:"Hard",q:"What is the general lighting load per square foot for an office building per Article 220?",opts:["2 VA per square foot","3.5 VA per square foot","10 VA per square foot","1 VA per square foot"],ans:1,ref:"NEC Table 220.12",exp:"Office buildings = 3.5 VA/sq ft per Table 220.12. Dwelling units = 3 VA/sq ft. Warehouses = 0.25 VA/sq ft. Schools = 3 VA/sq ft. Know these values — essential for commercial load calculations."},
{id:60,mod:2,cat:"Wiring & Overcurrent",diff:"Medium",q:"What does a GFCI detect, and at what current level does it trip?",opts:["Overloads and short circuits","Equipment voltage surges","Small ground fault currents (approximately 5mA) and trips to protect people from electrocution","It provides a ground connection for equipment"],ans:2,ref:"NEC 210.8 & Article 100",exp:"GFCI detects current imbalance between hot and neutral (~5mA) indicating current flowing through a person. GFCI protects people; standard overcurrent devices protect conductors and equipment."},
{id:61,mod:2,cat:"Wiring & Overcurrent",diff:"Medium",q:"What is the minimum height for wall switches in a dwelling unit per the NEC?",opts:["4 feet","6 feet 7 inches maximum","3 feet","No minimum height specified — switches must be accessible"],ans:3,ref:"NEC 404.8(A)",exp:"NEC doesn't specify a minimum height for switches, only that they be accessible. Maximum is 6 feet 7 inches. ADA requirements may impose specific heights in commercial applications."},
{id:62,mod:2,cat:"Wiring & Overcurrent",diff:"Hard",q:"A feeder has a demand load of 28,000 VA at 240V. What is the minimum feeder ampacity?",opts:["117 amperes","125 amperes","150 amperes","100 amperes"],ans:0,ref:"NEC 215.2(A)(1)",exp:"28,000VA ÷ 240V = 116.7A ≈ 117A minimum feeder ampacity. The conductor must have at least 117A ampacity. Next standard overcurrent device would be 125A."},
{id:63,mod:2,cat:"Wiring & Overcurrent",diff:"Medium",q:"What does it mean when a receptacle is rated 15/20A?",opts:["Rated 15A with 20A feed-through GFCI","Listed for installation on 15A or 20A circuits and provides GFCI protection for downstream devices","Protects both 15A and 20A circuits","All of the above"],ans:1,ref:"NEC 210.8 & 406.4(D)",exp:"15/20A GFCI = suitable for installation on 15A or 20A circuits, and when used in feed-through mode, provides GFCI protection to downstream outlets on the same circuit."},
{id:64,mod:2,cat:"Wiring & Overcurrent",diff:"Hard",q:"A 60A feeder must not have overcurrent protection rated more than _____.",opts:["100 amperes","70 amperes","60 amperes","80 amperes"],ans:2,ref:"NEC 215.3 & 240.4",exp:"60A feeder = maximum 60A overcurrent device. Standard fuse ratings include 60A as a listed size. Overcurrent device cannot exceed feeder's calculated load or conductor ampacity."},
{id:65,mod:2,cat:"Wiring & Overcurrent",diff:"Medium",q:"An arc fault circuit interrupter (AFCI) protects against:",opts:["Voltage surges from lightning","Overloads exceeding conductor ampacity","Ground faults to people (same as GFCI)","Parallel arcing faults in conductors that can cause fires"],ans:3,ref:"NEC 210.12",exp:"AFCIs detect arcing fault waveform patterns — the type that starts fires in walls and ceilings without tripping standard breakers. AFCI = fire protection; GFCI = shock protection."},
{id:66,mod:2,cat:"Wiring & Overcurrent",diff:"Easy",q:"What is the maximum voltage for circuits using 14 AWG copper branch circuit conductors?",opts:["120/240V","Up to 600V","120V only","Any voltage"],ans:0,ref:"NEC 240.4(D)(3)",exp:"14 AWG copper (ampacity 15A) is used almost exclusively on 120V and 240V residential circuits. The limitation is practical ampacity, not voltage rating of the insulation."},
{id:67,mod:2,cat:"Wiring & Overcurrent",diff:"Medium",q:"In a sub-panel, the neutral must:",opts:["Connect to the main breaker terminal only","Connect to an isolated neutral bus — NOT bonded to equipment ground","Bond to the equipment ground just like the main panel","Connect to either the neutral or ground bus"],ans:1,ref:"NEC 408.40",exp:"Sub-panel: neutral bus must be ISOLATED from equipment ground. Neutral and EGC only bonded at the service. Bonding neutral to ground in sub-panels creates dangerous parallel neutral current paths."},
{id:68,mod:2,cat:"Wiring & Overcurrent",diff:"Hard",q:"A circuit has a 35A continuous load. What is the minimum overcurrent device rating?",opts:["35 amperes","40 amperes","43.75 amperes (125% of 35A)","50 amperes"],ans:2,ref:"NEC 210.20(A) & 240.4",exp:"Continuous loads × 125% = 35A × 1.25 = 43.75A minimum. 43.75A doesn't match a standard size, so next standard size = 45A. The conductor must also be rated 43.75A minimum."},
{id:69,mod:2,cat:"Wiring & Overcurrent",diff:"Medium",q:"Receptacles within _____ of a swimming pool's inside walls must be GFCI protected.",opts:["10 feet","15 feet","25 feet","20 feet"],ans:3,ref:"NEC 680.22(A)(1)",exp:"Per Article 680, receptacle outlets within 20 feet of inside walls of a pool must be GFCI protected. Receptacles must be at least 6 feet from pool edge."},
{id:70,mod:2,cat:"Wiring & Overcurrent",diff:"Hard",q:"What does the 2020 NEC require for GFCI protection in commercial and institutional kitchens?",opts:["GFCI required for all receptacles in commercial kitchens","AFCI required in commercial kitchens","Standard circuit protection only — not required in commercial kitchens","GFCI required within 6 feet of a sink only"],ans:0,ref:"NEC 210.8(B)(2)",exp:"2020 NEC: GFCI protection required for ALL receptacles in commercial and institutional kitchens. Major expansion from previous editions. Water, wet surfaces, and high current appliances = serious shock hazard."},
{id:71,mod:2,cat:"Wiring & Overcurrent",diff:"Medium",q:"What receptacle requirement applies to dwelling unit hallways 10 feet or more in length?",opts:["One for every 10 feet of length","At least one receptacle outlet","No receptacle outlets","Two receptacle outlets — one at each end"],ans:1,ref:"NEC 210.52(H)",exp:"Dwelling unit hallways ≥10 feet long require at least one receptacle outlet. Ensures appliances like vacuums can be used without extension cords."},
{id:72,mod:2,cat:"Wiring & Overcurrent",diff:"Medium",q:"Holiday lighting illuminated for 3 weeks — which loading rule applies?",opts:["No limit for seasonal decorative lighting","80% only applies to commercial circuits","Continuous load rules — maximum 12A on a 15A circuit","Standard 100% loading — only a few weeks"],ans:2,ref:"NEC Article 100 & 210.20(A)",exp:"Holiday lighting on for 3+ hours continuously = continuous load. 80% rule applies: 15A × 0.80 = 12A maximum continuous load. Even seasonal loads follow continuous load rules. Classic exam trap."},
{id:73,mod:2,cat:"Wiring & Overcurrent",diff:"Hard",q:"What does a 20A circuit breaker rating represent in terms of continuous load?",opts:["Maximum load in watts","The short circuit current rating","Maximum fault current it can interrupt","Continuous current rating — will carry 20A continuously without tripping"],ans:3,ref:"NEC Article 100 & 240.6",exp:"20A rating = continuous current rating. NOT the trip point (breakers typically trip at 100-125% of rating). Interrupting capacity (fault current the breaker can safely break) is a separate rating, often 10,000 AIC for residential."},
{id:74,mod:2,cat:"Wiring & Overcurrent",diff:"Medium",q:"What requirement must the disconnecting means for a dwelling unit 240V air conditioner meet?",opts:["Within sight of and readily accessible from the air conditioning equipment","Lockable regardless of sight distance","Only required if unit is more than 50 feet from panel","Panel breaker serves as disconnect — no additional disconnect needed"],ans:0,ref:"NEC 440.14",exp:"Readily accessible disconnecting means must be within sight of and within 50 feet of A/C equipment. Allows service personnel to de-energize before working on the unit."},
{id:75,mod:2,cat:"Wiring & Overcurrent",diff:"Easy",q:"Does a residential sump pump require a dedicated circuit?",opts:["Not required — any available circuit acceptable","15A circuit is sufficient","Must share a circuit with other laundry equipment","A dedicated 20A circuit is required"],ans:0,ref:"NEC 210.52 (no sump pump req.)",exp:"The NEC does NOT require a dedicated circuit for residential sump pumps. Good practice to dedicate a circuit, but not required. Know what the NEC doesn't require — as important as what it does require."},
// MODULE 3: SERVICES & FEEDERS (35)
{id:76,mod:3,cat:"Services & Feeders",diff:"Easy",q:"A new single-family dwelling must have a minimum service ampacity of _____.",opts:["100 amperes","150 amperes","80 amperes","60 amperes"],ans:0,ref:"NEC 230.79(C)",exp:"Minimum service for a single-family dwelling = 100 amperes. In practice, 200A is standard for new construction, but 100A is the NEC minimum."},
{id:77,mod:3,cat:"Services & Feeders",diff:"Easy",q:"The maximum number of service disconnects permitted for a single building is _____.",opts:["Four","One only","No maximum","Six"],ans:3,ref:"NEC 230.71(A) & 230.71(B)",exp:"NEC 2020 changed 230.71: the default is now ONE service disconnect. Up to six are permitted only when specific configurations are used — each in a separate enclosure with its own main disconnect, or in separate switchboard sections with barriers. The maximum is six but it is no longer automatic."},
{id:78,mod:3,cat:"Services & Feeders",diff:"Medium",q:"Service drop conductors above a residential driveway must maintain a minimum clearance of _____.",opts:["10 feet","12 feet","18 feet","15 feet"],ans:1,ref:"NEC 230.24(B)(2)",exp:"Over residential property and driveways: 12 feet minimum. The 18-foot clearance applies to public streets, alleys, roads, and driveways on other than residential property. The 10-foot clearance applies at service entrances and pedestrian-only areas."},
{id:79,mod:3,cat:"Services & Feeders",diff:"Medium",q:"Service entrance conductors above a roof surface must maintain a minimum clearance of _____.",opts:["8 feet","3 feet","10 feet","6 feet"],ans:1,ref:"NEC 230.24(A) Exception 2",exp:"Service conductors over a roof = 8 feet clearance minimum, EXCEPT where voltage ≤300V to ground AND roof slope ≥4 in 12, then 3 feet is acceptable. The 3-foot exception for steep residential roofs is commonly tested."},
{id:80,mod:3,cat:"Services & Feeders",diff:"Medium",q:"Where must the service disconnect be located?",opts:["At a readily accessible location outside or inside nearest the point of entrance of service conductors","In the center of the building","In a locked room only","Any inside location is acceptable"],ans:0,ref:"NEC 230.70(A)(1)",exp:"Service disconnect must be readily accessible — outside or inside nearest to point of entry of service conductors. 'Readily accessible' = no ladder, moving obstacles, or unlocking enclosures required."},
{id:81,mod:3,cat:"Services & Feeders",diff:"Hard",q:"Service conductors must be at least _____ from an openable window.",opts:["12 inches","Service conductors may not pass near openable windows","24 inches","3 feet"],ans:3,ref:"NEC 230.9(A)",exp:"Service entrance conductors must maintain at least 3 feet clearance from openable windows, doors, porches, balconies, and fire escapes. Conductors passing above the top of a window are exempt."},
{id:82,mod:3,cat:"Services & Feeders",diff:"Medium",q:"When two or more sets of service conductors are used, the combined ampacity must:",opts:["The largest set must equal the total service ampacity","Each set must carry exactly one-half the service load","Combined ampacity of all sets must equal at least the required service ampacity","Each set must be sized for the total load"],ans:2,ref:"NEC 230.40 & 310.10(G)",exp:"Multiple sets of service conductors: combined ampacity of all sets must equal or exceed the required service ampacity. Each set need not carry the full load independently."},
{id:83,mod:3,cat:"Services & Feeders",diff:"Medium",q:"The minimum size copper service entrance conductor for a 200A residential service is _____.",opts:["1 AWG","2/0 AWG","2 AWG","3/0 AWG"],ans:1,ref:"NEC Table 310.16 & 240.4(B)",exp:"For 200A service, 2/0 AWG copper (195A at 75°C) or 4/0 AWG aluminum. Per next-size-up rule, 2/0 AWG copper is acceptable for 200A service. Standard residential service conductor size."},
{id:84,mod:3,cat:"Services & Feeders",diff:"Hard",q:"What are service lateral conductors?",opts:["Service entrance conductors — meet all service conductor requirements","Utility property not covered by NEC","Feeder conductors sized per Article 215","Low voltage conductors not requiring protection"],ans:0,ref:"NEC Article 100 & 230.2",exp:"Service lateral conductors = underground service entrance conductors. Carry full service current and must meet all service conductor requirements including sizing, protection, and grounding."},
{id:85,mod:3,cat:"Services & Feeders",diff:"Medium",q:"Why must service conduit be sealed at its entrance to the service equipment?",opts:["Prevent insects from entering","Prevent condensation-causing air circulation","Prevent water from entering","All of the above"],ans:3,ref:"NEC 230.8",exp:"Service conduit must be sealed at the service head and service equipment to prevent water infiltration, insects, and air circulation that causes condensation. Condensation in service equipment causes corrosion and failure."},
{id:86,mod:3,cat:"Services & Feeders",diff:"Hard",q:"How is demand calculated using the optional method for a single-family dwelling?",opts:["10,000 VA plus loads exceeding 10 kW","8,000 VA minimum regardless","First 10 kVA at 100% plus remainder at 40%","Optional method cannot be used with electric heat"],ans:2,ref:"NEC 220.82(B)",exp:"Optional method: 100% of first 10 kVA of all loads + 40% of remainder. Electric heat and A/C — the larger of the two included. Often results in lower calculated demand than standard method."},
{id:87,mod:3,cat:"Services & Feeders",diff:"Medium",q:"Service lateral conductors installed in rigid metal conduit must be buried a minimum of _____.",opts:["18 inches","6 inches","12 inches","24 inches"],ans:1,ref:"NEC Table 300.5",exp:"RMC and IMC may be buried at minimum 6 inches depth. PVC conduit requires 18 inches; direct burial cable requires 24 inches. RMC's heavy steel construction allows shallower burial."},
{id:88,mod:3,cat:"Services & Feeders",diff:"Easy",q:"How is 'service point' defined in the NEC?",opts:["Point of connection between the serving utility's facilities and the premises wiring","The grounding electrode connection point","Location of the main service disconnect","The metering location"],ans:0,ref:"NEC Article 100",exp:"Service point = connection between utility's facilities and customer's premises wiring. Everything from the service point inward is covered by the NEC. Utility equipment up to service point is covered by NESC."},
{id:89,mod:3,cat:"Services & Feeders",diff:"Medium",q:"PVC conduit installed under a residential driveway (not subject to truck traffic) must be buried a minimum of _____.",opts:["24 inches","18 inches","6 inches","12 inches"],ans:3,ref:"NEC Table 300.5",exp:"Under residential driveways (not subject to truck traffic), all conduit (including PVC) must be buried minimum 12 inches. Under truck traffic areas: 24 inches. Know burial depths by location and conduit type."},
{id:90,mod:3,cat:"Services & Feeders",diff:"Hard",q:"What are California's meter pulling requirements for electrical services?",opts:["All meters must be capable of being pulled","California utilities require pull-out capability for emergency","Meter pulling is a utility requirement, not NEC","Only when disconnect is not adjacent to meter"],ans:2,ref:"CEC / Utility Requirements",exp:"Metering and meter pulling are utility requirements, not NEC requirements. California utilities (SCE, PG&E, SDG&E) have their own requirements. Always coordinate with the serving utility on California services."},
{id:91,mod:3,cat:"Services & Feeders",diff:"Medium",q:"What must a feeder to a detached garage include?",opts:["Any configuration with GFCI protection","An equipment grounding conductor in addition to the neutral, unless certain conduit conditions are met","Only ungrounded conductors if garage has its own electrode","Only ungrounded conductors and neutral"],ans:1,ref:"NEC 250.32(B)",exp:"Feeder to a separate structure must include an EGC. May be omitted ONLY if: no EGC in existing feeder, no grounding-type receptacles in structure, and no metallic path back to main building. New installations require an EGC."},
{id:92,mod:3,cat:"Services & Feeders",diff:"Medium",q:"When service conductors run in parallel, each raceway must contain:",opts:["All phase conductors and neutral in each raceway","Same size conductors only","All phases, neutral, and EGC must each be in one of the raceways","One phase per raceway"],ans:0,ref:"NEC 310.10(G)(1)",exp:"Parallel service conductors: each raceway must contain all phase conductors, neutral (if needed), and EGC. Running all phases in one raceway prevents inductive heating in metal raceways."},
{id:93,mod:3,cat:"Services & Feeders",diff:"Hard",q:"What is the maximum total ampere rating of branch circuit breakers allowed in a 200A panel?",opts:["Must be limited to 42 circuits","200 amperes — sum cannot exceed 200A","Cannot exceed 200A of connected load","May exceed 200A based on demand factors and load diversity"],ans:3,ref:"NEC 408.54",exp:"Branch circuit breaker total CAN exceed the main breaker rating. This is load diversity — not all circuits are fully loaded simultaneously. Panel sized on calculated demand, not sum of all breaker ratings."},
{id:94,mod:3,cat:"Services & Feeders",diff:"Medium",q:"Where must the service head be located?",opts:["At the highest point on the roof","At the utility's service point","Above the point where service drop conductors attach, with drip loops formed","Above the service equipment"],ans:2,ref:"NEC 230.54(C)",exp:"Service head must be ABOVE the point where service drop conductors attach. Allows drip loops — downward curves preventing water from flowing along conductors into the service head."},
{id:95,mod:3,cat:"Services & Feeders",diff:"Easy",q:"How must the grounded service conductor (neutral) be identified by color?",opts:["Black","White or gray","Any color with white tape at terminations","Green"],ans:1,ref:"NEC 200.6",exp:"Grounded conductor (neutral) must be white or gray. Green = EGC. Black = typically hot (ungrounded). Color coding prevents dangerous cross-connections. For conductors >6 AWG, white tape at terminals is acceptable."},
{id:96,mod:3,cat:"Services & Feeders",diff:"Hard",q:"A 600A service uses four parallel sets of 350 kcmil copper conductors each rated 350A. Is this adequate?",opts:["Yes — 4 sets × 350A = 1,400A combined ampacity, exceeding 600A","No — parallel conductors must be same size as single conductors","Yes, but only if all four conduits are same size","No — each parallel set must handle the full service"],ans:0,ref:"NEC 310.10(G)",exp:"Parallel conductors valid when combined ampacity meets or exceeds required service ampacity. 4 × 350A = 1,400A combined > 600A required. Parallel conductors must be same size, material, insulation type, and length."},
{id:97,mod:3,cat:"Services & Feeders",diff:"Medium",q:"What must each parallel conduit for service conductors contain?",opts:["Two conductors per conduit maximum","All phase conductors, neutral, and grounding conductor in same conduit","One conductor per conduit to prevent heating","One complete set per conduit — all phases, neutral, and EGC in each conduit"],ans:3,ref:"NEC 310.10(G)(1)",exp:"Each parallel conduit must contain one complete set: all phase conductors + neutral (if required) + EGC. Balances current in each raceway and prevents inductive heating in metallic conduits."},
{id:98,mod:3,cat:"Services & Feeders",diff:"Medium",q:"What is the minimum neutral size when the largest service entrance conductor is 3/0 AWG copper?",opts:["At least 1/0 AWG copper","Same size as ungrounded conductors","Based on actual neutral load, not phase conductors","At least 6 AWG copper"],ans:2,ref:"NEC 220.61 & 250.24(C)",exp:"Neutral sized based on maximum unbalanced load — not automatically same as phase conductors. Large services often use reduced-size neutrals. But minimums apply: neutral cannot be smaller than required GEC size for that service ampacity."},
{id:99,mod:3,cat:"Services & Feeders",diff:"Hard",q:"What is the minimum aluminum conductor size for a 200A underground service lateral?",opts:["2 AWG","4/0 AWG","1/0 AWG","250 kcmil"],ans:1,ref:"NEC Table 310.16 & 240.4(B)",exp:"For 200A service using aluminum, 4/0 AWG aluminum (180A at 75°C) is commonly accepted minimum using demand factors. 250 kcmil aluminum = exactly 200A at 75°C. Most AHJs accept 4/0 aluminum for 200A residential service."},
{id:100,mod:3,cat:"Services & Feeders",diff:"Medium",q:"What clearance is required between service conductors and a sign on a building?",opts:["3 feet — same as from openable windows","3 feet above, 1 foot to sides","1 foot minimum from all points","Signs must be removed"],ans:0,ref:"NEC 230.9(A)",exp:"Service conductors must maintain at least 3 feet clearance from windows, doors, porches, balconies, ladders, stairs, fire escapes, and attachment points where a person could contact them."},
{id:101,mod:3,cat:"Services & Feeders",diff:"Medium",q:"What enclosure must service entrance conductors between the service head and service disconnect be in?",opts:["Service conductors protected by main breaker only","No protection required — service conductors are heavy gauge","Rigid metal conduit only","Service entrance cable (SE) or approved raceway"],ans:3,ref:"NEC 230.43",exp:"Service entrance conductors must be in SE cable or approved raceway. Protected by the main overcurrent device at the service disconnect. Must be kept as short as practical within the building."},
{id:102,mod:3,cat:"Services & Feeders",diff:"Hard",q:"What is the demand factor for 5 to 7 electric clothes dryers per NEC 2020 Table 220.54?",opts:["5 dryers = 70%, 6–7 = 65%","5 dryers = 75%, 6–7 = 70%","5 dryers = 80%, 6–7 = 70%","All 5–7 dryers calculated at 100%"],ans:2,ref:"NEC Table 220.54",exp:"NEC 2020 Table 220.54: 1–4 dryers = 100%, 5 dryers = 80%, 6–7 dryers = 70%. Note that 4 or fewer dryers are always calculated at 100% — no demand reduction. Minimum nameplate or 5,000W per dryer, whichever is larger."},
{id:103,mod:3,cat:"Services & Feeders",diff:"Easy",q:"Service lateral conductors run underground from the utility to the service entrance. What is permitted?",opts:["Underground feeder (UF) cable only","Direct buried cables or in conduit","Service entrance (SE) cable only","Direct buried cables only"],ans:1,ref:"NEC 230.30 & 230.32",exp:"Service lateral conductors may be direct buried cables or in conduit depending on utility and AHJ requirements. California utilities have specific requirements for service lateral installations."},
{id:104,mod:3,cat:"Services & Feeders",diff:"Medium",q:"What is the minimum requirement every electrical service must have?",opts:["At least one disconnecting means","No minimum — some buildings may not need a disconnect","One disconnect for every 100A of capacity","One disconnect per service"],ans:0,ref:"NEC 230.70(A)",exp:"Every service must have at least one disconnecting means to allow de-energizing the entire premises. Maximum is six. The disconnect must be accessible to emergency responders."},
{id:105,mod:3,cat:"Services & Feeders",diff:"Hard",q:"What is the minimum copper conductor size for a 75A feeder at 75°C terminations?",opts:["4 AWG — next size meeting 75A","3 AWG (100A) for safety margin","6 AWG (65A — insufficient)","4 AWG (85A ampacity)"],ans:3,ref:"NEC Table 310.16",exp:"6 AWG copper at 75°C = 65A (insufficient). 4 AWG copper at 75°C = 85A (sufficient). Minimum conductor for 75A demand = 4 AWG copper. Ampacity must equal or exceed demand load."},
{id:106,mod:3,cat:"Services & Feeders",diff:"Medium",q:"How many service disconnects are permitted for a 1,200A commercial building service?",opts:["Only one for services over 1,000A","As many as needed with AHJ approval","Up to six grouped at one location","Two — one per 600A of capacity"],ans:2,ref:"NEC 230.71(B)",exp:"NEC 2020: up to six service disconnects are permitted under 230.71(B), but each must have its own main disconnect and be in a separate enclosure, separate panelboard, or separate switchboard section with barriers. The 2020 NEC changed the default to one disconnect — six requires specific configurations."},
{id:107,mod:3,cat:"Services & Feeders",diff:"Medium",q:"What protection is required for exterior branch circuits and feeders subject to physical damage?",opts:["Must be in rigid metal conduit on all exterior surfaces","Where subject to physical damage, conductors shall be protected","Must be in Schedule 80 PVC conduit","No additional protection required"],ans:1,ref:"NEC 225.22",exp:"Article 225 requires exterior conductors be protected from physical damage where exposed to it. The AHJ determines what constitutes 'subject to physical damage.' Conduit is generally used for exposed exterior wiring."},
{id:108,mod:3,cat:"Services & Feeders",diff:"Hard",q:"For a 400A service with only ground rod electrodes, maximum GEC size required?",opts:["6 AWG copper (maximum for ground rods)","2 AWG copper","4 AWG copper","GEC must match service conductor size"],ans:0,ref:"NEC 250.66(A)",exp:"For ground rod and concrete-encased electrodes only, the GEC never needs to exceed 6 AWG copper regardless of service size. Table 250.66 caps the GEC at 6 AWG copper for ground rod electrodes. The 'large service, small GEC' rule surprises many electricians."},
{id:109,mod:3,cat:"Services & Feeders",diff:"Medium",q:"In California, who must approve the service installation before the utility connects power?",opts:["Utility company only","The licensed electrical contractor","Both the AHJ and the utility","The local electrical inspector (AHJ)"],ans:2,ref:"CEC & Utility Requirements",exp:"California: local electrical inspector (AHJ) must approve and sign off the service installation, AND the utility must be satisfied before energizing. Utilities have their own standards for metering, clearances, and conductor sizing that may exceed NEC minimums."},
{id:110,mod:3,cat:"Services & Feeders",diff:"Easy",q:"What is the difference between SE cable and USE cable?",opts:["SE = 120V services; USE = 240V services","SE = above-grade service entrance use; USE (Underground Service Entrance) = listed for direct burial","SE = aluminum; USE = copper","They are interchangeable — marketing terms only"],ans:1,ref:"NEC Article 338",exp:"SE (Service Entrance) cable = above-grade use. USE (Underground Service Entrance) cable = listed for underground direct burial. Using standard SE cable underground without burial rating is a code violation."},
// MODULE 4: GROUNDING & BONDING (40)
{id:111,mod:4,cat:"Grounding & Bonding",diff:"Easy",q:"What is the purpose of equipment grounding conductors (EGC)?",opts:["Provide voltage reference for electronic equipment","Provide a low-impedance fault current path to facilitate overcurrent device operation","Connect equipment to earth for lightning protection","Carry normal return current back to source"],ans:1,ref:"NEC 250.4(A)(5)",exp:"EGC provides a low-impedance fault current path allowing enough current to flow during a ground fault to trip the OCPD. Does NOT carry normal current — only fault current."},
{id:112,mod:4,cat:"Grounding & Bonding",diff:"Easy",q:"A single ground rod tests at 28 ohms resistance. What must be done?",opts:["Single rod is acceptable","Replace with concrete-encased electrode","Drive a second rod in the same hole","Install a second rod at least 6 feet from the first"],ans:3,ref:"NEC 250.56",exp:"Single ground rod exceeding 25 ohms → second supplemental electrode required at least 6 feet away. The two-rod system does NOT need to be tested — just installing the second rod satisfies the requirement."},
{id:113,mod:4,cat:"Grounding & Bonding",diff:"Medium",q:"A ground rod must be a minimum of _____ long.",opts:["8 feet","6 feet","4 feet","10 feet"],ans:0,ref:"NEC 250.52(A)(5)",exp:"Ground rods must be at least 8 feet long and driven to full depth. If rock prevents full depth, rod may be driven at up to 45-degree angle, or buried horizontally in a trench at least 30 inches deep."},
{id:114,mod:4,cat:"Grounding & Bonding",diff:"Medium",q:"A steel ground rod must have a minimum diameter of _____.",opts:["1/4 inch","3/8 inch","1/2 inch","5/8 inch"],ans:3,ref:"NEC 250.52(A)(5)",exp:"Steel ground rods must be at least 5/8 inch diameter. Copper or copper-clad rods = 1/2 inch minimum. Know the difference: 5/8\" steel, 1/2\" copper."},
{id:115,mod:4,cat:"Grounding & Bonding",diff:"Medium",q:"What must a concrete-encased grounding electrode (Ufer ground) consist of at minimum?",opts:["10 feet of bare 6 AWG copper encased in footing","6 feet of copper rod in concrete","20 feet of 4 AWG or larger bare copper or 20 feet of 1/2-inch rebar encased in footing concrete","Any metal embedded in foundation qualifies"],ans:2,ref:"NEC 250.52(A)(3)",exp:"Concrete-encased electrode: at least 20 feet of 4 AWG (or larger) bare copper conductor OR at least 20 feet of 1/2-inch (or larger) steel reinforcing bar in concrete footing. One of the best available grounding electrodes."},
{id:116,mod:4,cat:"Grounding & Bonding",diff:"Medium",q:"What is the function of the main bonding jumper in a service panel?",opts:["Connects service conductors to main breaker","Connects the grounded conductor (neutral) to the panel enclosure and EGC at the SERVICE only","Connects GEC to panel enclosure","Provides path for normal neutral current"],ans:1,ref:"NEC 250.28",exp:"Main bonding jumper connects neutral to EGC and service enclosure AT THE SERVICE ONLY. Allows fault current to return to source via neutral to trip the OCPD. Must NOT be duplicated in downstream sub-panels."},
{id:117,mod:4,cat:"Grounding & Bonding",diff:"Hard",q:"The minimum size copper EGC for a circuit protected by a 60A overcurrent device is _____.",opts:["12 AWG","8 AWG","14 AWG","10 AWG"],ans:3,ref:"NEC Table 250.122",exp:"Per Table 250.122: 60A OCPD → 10 AWG copper EGC. Key values to memorize: 15A=14AWG, 20A=12AWG, 30A=10AWG, 60A=10AWG, 100A=8AWG, 200A=6AWG."},
{id:118,mod:4,cat:"Grounding & Bonding",diff:"Medium",q:"When must GEC connections be accessible for inspection, and what is the exception?",opts:["Connections to concrete-encased or buried electrodes need not be accessible","Grounding connections must be inside the panel only","All GEC connections must be accessible","Connections may be buried if in a junction box"],ans:0,ref:"NEC 250.68(A) Exception",exp:"Connections to concrete-encased or underground electrodes need not be accessible — cannot be practically accessed once buried. Connections to accessible electrodes (ground rods above grade, water pipes) must remain accessible."},
{id:119,mod:4,cat:"Grounding & Bonding",diff:"Hard",q:"A 200A service using a metal underground water pipe as a grounding electrode requires a GEC sized at minimum _____.",opts:["6 AWG copper","2 AWG copper","4 AWG copper","8 AWG copper"],ans:2,ref:"NEC Table 250.66",exp:"Per Table 250.66: service conductors 2/0-3/0 AWG copper (typical for 200A) → GEC must be 4 AWG copper. For metal water pipe electrode, GEC must be full size (unlike ground rods which cap at 6 AWG)."},
{id:120,mod:4,cat:"Grounding & Bonding",diff:"Medium",q:"When is the grounded conductor (neutral) permitted to serve as EGC?",opts:["In dwelling units with copper wiring only","Only at the service equipment where the main bonding jumper is installed","When AHJ approves","Never — must always be separate"],ans:1,ref:"NEC 250.142(A)",exp:"Neutral may carry fault current back to source ONLY at the service, through the main bonding jumper. Downstream of service, neutral and EGC must be SEPARATE. Critical — sub-panel rule."},
{id:121,mod:4,cat:"Grounding & Bonding",diff:"Easy",q:"What color must equipment grounding conductors be?",opts:["White or gray","Red","Black with green tape","Green, green with yellow stripe, or bare"],ans:3,ref:"NEC 250.119",exp:"EGC must be green, green with yellow stripes, or bare. Critical color coding — accidentally connecting green to line voltage creates lethal hazards."},
{id:122,mod:4,cat:"Grounding & Bonding",diff:"Hard",q:"Why must a metal water pipe as grounding electrode be supplemented?",opts:["Metal water pipes are likely to be replaced with plastic, interrupting the grounding path","Water pipes are supplemental electrodes only — don't qualify as primary","Water pipes only acceptable in commercial buildings","Water pipes have too high resistance"],ans:0,ref:"NEC 250.53(D)(2)",exp:"Metal water pipes are likely to be replaced with non-metallic pipe, which would interrupt the grounding path. Must be supplemented with at least one other electrode to ensure continuity after pipe replacement."},
{id:123,mod:4,cat:"Grounding & Bonding",diff:"Medium",q:"How must interior metal gas piping be treated regarding electrical bonding?",opts:["Connected to ground through the appliance EGC — no additional bonding","Never used as part of the grounding system","Bonded to the electrical grounding system through an approved bonding connection","Only high-pressure gas lines require bonding"],ans:2,ref:"NEC 250.104(B)",exp:"Interior metal gas piping must be bonded to the electrical grounding system. Prevents dangerous voltage differences between gas appliances and electrical grounding that could cause sparks or shock."},
{id:124,mod:4,cat:"Grounding & Bonding",diff:"Hard",q:"What size bonding jumper is required to bond metal water pipe to the service entrance?",opts:["Same size as main bonding jumper","Per Table 250.102(C)(1) based on service entrance conductor size","Always 6 AWG copper for residential","8 AWG minimum regardless of service size"],ans:1,ref:"NEC Table 250.102(C)(1)",exp:"Bonding jumper for metal water piping sized per Table 250.102(C)(1), based on service entrance conductor size — same table as for GECs. Ensures bond is adequate for available fault current."},
{id:125,mod:4,cat:"Grounding & Bonding",diff:"Medium",q:"Where are bare copper EGCs permitted?",opts:["Never — all EGCs must be insulated","Only in conduit or otherwise protected","Only for conductors 6 AWG and larger","Bare EGCs permitted in conduit, cable assemblies, or other approved locations"],ans:3,ref:"NEC 250.119",exp:"Bare EGCs permitted when protected — in conduit, in cable assemblies, or other locations. The bare wire in 12/2 NM cable with ground is the EGC. Bare EGCs are common and code-compliant when properly protected."},
{id:126,mod:4,cat:"Grounding & Bonding",diff:"Hard",q:"Where must the system bonding jumper for a transformer (separately derived system) be installed?",opts:["At the transformer itself or at the first disconnecting means on the secondary","Transformers do not require system bonding jumpers","At any convenient point in the secondary","At the main service panel"],ans:0,ref:"NEC 250.30(A)(1)",exp:"System bonding jumper for a separately derived system must be installed at the source (transformer) or at the first means of disconnect and OCPD on the secondary. Equivalent to the main bonding jumper at a service."},
{id:127,mod:4,cat:"Grounding & Bonding",diff:"Medium",q:"What does bonding service equipment enclosures ensure?",opts:["Compliance with utility metering requirements","Protection from corrosion","Electrical continuity of the grounding path and ability to conduct safely any fault current","Voltage stability"],ans:2,ref:"NEC 250.92",exp:"Bonding ensures electrical continuity of the grounding path and that fault current can safely flow to operate overcurrent devices. Loose or corroded connections prevent adequate fault current flow."},
{id:128,mod:4,cat:"Grounding & Bonding",diff:"Easy",q:"What ground rod resistance reading requires installation of a second rod?",opts:["10 ohms","25 ohms","50 ohms","100 ohms"],ans:1,ref:"NEC 250.56",exp:"25 ohms is the threshold. A single ground rod exceeding 25 ohms requires a second supplemental electrode. California soil varies widely — desert soils may have very high resistance, coastal soils typically lower."},
{id:129,mod:4,cat:"Grounding & Bonding",diff:"Hard",q:"How must the neutral and ground be configured in a sub-panel fed by a 4-wire feeder?",opts:["Feeder neutral may serve as both neutral and EGC","Use green screw to bond neutral to enclosure","Bond neutral to ground like main panel","Keep neutral ISOLATED from equipment ground — no bonding jumper"],ans:3,ref:"NEC 408.40",exp:"Sub-panel with 4-wire feeder: neutral bus must be ISOLATED from panel enclosure — no bonding jumper. EGC connects to enclosure. Bonding neutral to ground in sub-panel creates dangerous parallel neutral current paths."},
{id:130,mod:4,cat:"Grounding & Bonding",diff:"Medium",q:"What is the minimum length of a ground ring electrode?",opts:["At least 50 feet of bare copper buried at least 30 inches deep","At least 20 feet","At least 100 feet around building perimeter","At least 10 feet"],ans:0,ref:"NEC 250.52(A)(4)",exp:"Ground ring = at least 50 feet of 2 AWG (or larger) bare copper encircling the building, buried at least 30 inches deep. Large circumference provides large soil contact area."},
{id:131,mod:4,cat:"Grounding & Bonding",diff:"Hard",q:"Where are aluminum or copper-clad aluminum GECs prohibited?",opts:["They require corrosion-inhibiting compound at all connections","They may be used anywhere copper is used","In contact with masonry or earth, or subject to corrosive conditions","They must be 2 sizes larger than copper equivalents"],ans:2,ref:"NEC 250.64(A)",exp:"Aluminum/copper-clad aluminum GECs cannot be used where they contact masonry, earth, or corrosive environments. Aluminum oxidizes rapidly in these conditions, creating high-resistance connections that fail the grounding system."},
{id:132,mod:4,cat:"Grounding & Bonding",diff:"Medium",q:"May an isolated EGC run in the same conduit as current-carrying conductors?",opts:["No — must be in separate conduit","Yes — an isolated EGC may run in the same conduit as the conductors it grounds","Only in commercial buildings","Only if conduit isn't used as an EGC"],ans:1,ref:"NEC 250.146(D)",exp:"An isolated EGC (for sensitive electronics) is permitted in the same conduit as the circuit conductors it serves. Runs back to service panel or transformer for a clean ground path separate from the conduit system."},
{id:133,mod:4,cat:"Grounding & Bonding",diff:"Medium",q:"What are the requirements for GEC connection methods?",opts:["Sheet metal screws are acceptable","Sheet metal screws acceptable only for concrete-encased electrodes","Sheet metal screws may be used for temporary connections","Must use approved clamps, exothermic welds, or listed connections"],ans:3,ref:"NEC 250.70",exp:"GEC connections must use approved means: listed clamps, exothermic welding (Cadweld), listed lugs, or other approved connectors. Sheet metal screws create high-resistance connections that can fail under fault current."},
{id:134,mod:4,cat:"Grounding & Bonding",diff:"Hard",q:"A building has multiple grounding electrodes — metal water pipe, two ground rods, and a concrete-encased electrode. How must they be connected?",opts:["All electrodes must be bonded together to form a grounding electrode system","Only the best electrode needs connection","Only the two lowest-resistance electrodes need connection","Each electrode serves a different circuit — no interconnection needed"],ans:0,ref:"NEC 250.50",exp:"When multiple grounding electrodes exist, ALL must be bonded together to form a single grounding electrode system. Prevents voltage differences between electrodes that could create dangerous potential differences."},
{id:135,mod:4,cat:"Grounding & Bonding",diff:"Medium",q:"What size bonding bushing is required to bond metal conduit to a service panel?",opts:["6 AWG","4 AWG","Per Table 250.102","8 AWG"],ans:2,ref:"NEC Table 250.102(C)(1) & 250.92",exp:"Bonding jumpers at service equipment sized per Table 250.102 based on service entrance conductors. Undersized bonding means during a fault the high current may vaporize the bonding conductor before the OCPD trips."},
{id:136,mod:4,cat:"Grounding & Bonding",diff:"Hard",q:"Where does California require direct bonding for CSST gas piping?",opts:["Only in commercial buildings","Within 6 feet of the gas meter or building entry point because lightning-induced currents can cause CSST to arc through, creating gas leaks","CSST is not electrically conductive — no bonding needed","Using 2 AWG copper bonding conductor regardless of service size"],ans:1,ref:"NEC 250.104(B) & CEC Amendment",exp:"California requires CSST to be directly bonded within 6 feet of the point where gas piping enters the building. Lightning-induced current can arc through thin CSST wall, creating a gas leak. Direct bonding provides a safe path for lightning current."},
{id:137,mod:4,cat:"Grounding & Bonding",diff:"Medium",q:"A 100A service with 1 AWG copper service entrance conductors requires a GEC sized at _____.",opts:["8 AWG copper","4 AWG copper","10 AWG copper","6 AWG copper"],ans:3,ref:"NEC Table 250.66",exp:"Per Table 250.66: 1 AWG copper service entrance conductors → GEC = 6 AWG copper. Key table entries: 2 AWG SE = 8 AWG GEC, 1/0 AWG SE = 6 AWG GEC, 2/0-3/0 AWG SE = 4 AWG GEC."},
{id:138,mod:4,cat:"Grounding & Bonding",diff:"Easy",q:"Which of the following is a grounding electrode?",opts:["A metal underground water pipe with at least 10 feet in contact with earth","The equipment grounding conductor","The green wire in a cable assembly","The service neutral conductor"],ans:0,ref:"NEC 250.52(A)(1)",exp:"Metal underground water pipe with ≥10 feet earth contact = grounding electrode. Grounding electrodes include: metal underground water pipes, metal building frames, concrete-encased electrodes, ground rings, ground rods, and plate electrodes."},
{id:139,mod:4,cat:"Grounding & Bonding",diff:"Hard",q:"What does a generator used as a separately derived system require?",opts:["Generator grounding only required for permanent standby systems","Generators <15 kW exempt from grounding requirements","Its own grounding electrode system and system bonding jumper at the generator or first disconnect","EGC connects back to main panel ground — no new electrode needed"],ans:2,ref:"NEC 250.30(A)",exp:"Generator operating as a separately derived system (transfer switch opens the neutral) requires its own grounding electrode and system bonding jumper. If transfer switch doesn't switch the neutral, it may not be a separately derived system."},
{id:140,mod:4,cat:"Grounding & Bonding",diff:"Medium",q:"What is the purpose of bonding metal water pipes, gas pipes, and structural steel to the electrical grounding system?",opts:["To satisfy utility company bonding requirements","To ensure all conductive surfaces are at the same potential, preventing dangerous voltage differences","To provide multiple paths for lightning current","To use these as additional grounding electrodes"],ans:1,ref:"NEC 250.104",exp:"Bonding all metallic systems = equipotential. All metal surfaces in building stay at same voltage. Without bonding, a fault could energize one metal system while another is at different potential — shock hazard at junction points."},
{id:141,mod:4,cat:"Grounding & Bonding",diff:"Medium",q:"What identifies the main bonding jumper screw in a service panel?",opts:["Red screw indicating main bonding jumper","White screw","No color coding required","Green bonding screw"],ans:3,ref:"NEC 250.28(D)",exp:"Main bonding jumper screw connecting neutral bar to panel enclosure is traditionally green. Visual identifier that bonding is complete at the service. Green screw only in service panel — must be absent in sub-panels."},
{id:142,mod:4,cat:"Grounding & Bonding",diff:"Hard",q:"In a 3-phase 4-wire wye system, what is typical voltage between phase conductor and neutral?",opts:["120V on 208/120V system; 277V on 480/277V system","Always 120V regardless of phase-to-phase voltage","208V on both systems","Phase-to-neutral voltage equals phase-to-phase voltage"],ans:0,ref:"NEC Article 100",exp:"Wye system: phase-to-neutral = phase-to-phase / 1.732. For 208V: 208/1.732 = 120V. For 480V: 480/1.732 = 277V. Standard commercial voltages: 120/208V and 277/480V three-phase wye systems."},
{id:143,mod:4,cat:"Grounding & Bonding",diff:"Medium",q:"Under what conditions may FMC serve as an EGC?",opts:["Never — separate EGC always required with FMC","Always — FMC is metallic and provides a grounding path","Listed for grounding, ≤6 feet total length, with listed fittings, and circuit ≤20A for equipment","Only for circuits 30A and below"],ans:2,ref:"NEC 250.118(5)",exp:"FMC as EGC conditions: (1) listed for grounding, (2) total length ≤6 feet, (3) listed fittings, (4) circuit ≤20A for equipment circuits. Beyond 6 feet, a separate EGC is required. Classic 6-foot FMC rule."},
{id:144,mod:4,cat:"Grounding & Bonding",diff:"Medium",q:"What copper conductor size is required for bonding metal water pipe when service entrance conductors are 350 kcmil copper?",opts:["4 AWG copper","2 AWG copper","6 AWG copper","1/0 AWG copper"],ans:1,ref:"NEC Table 250.66",exp:"Per Table 250.66: 350 kcmil copper service conductors → GEC (and water pipe bonding jumper) = 2 AWG copper. As service conductors get larger, GEC requirement increases to handle higher fault currents."},
{id:145,mod:4,cat:"Grounding & Bonding",diff:"Hard",q:"What is a 'ground fault' and why is it dangerous?",opts:["Current flowing through grounding electrode to earth — safe because earth absorbs it","A fault when grounding electrode is disconnected","An overload that trips the GFCI","Current flowing through an unintended path to ground, potentially through a person or creating arcing that can cause fire"],ans:3,ref:"NEC Article 100 & 250.4(A)(5)",exp:"Ground fault = unintended current flow through a path to ground — through a person, building structure, or creating an arc. Dangerous because: may not carry enough current to trip standard breakers, can electrocute people, and arcing ground faults cause fires."},
{id:146,mod:4,cat:"Grounding & Bonding",diff:"Easy",q:"What color must an EGC be in a flexible cord?",opts:["Green or green with yellow stripe","Black","Bare copper","White or gray"],ans:0,ref:"NEC 250.119(A)",exp:"In flexible cord, EGC must be green or green with yellow stripes. Same as for fixed wiring. Three-wire grounded cord: black (hot), white (neutral), green (EGC)."},
{id:147,mod:4,cat:"Grounding & Bonding",diff:"Hard",q:"Is aluminum EGC permitted in direct contact with concrete?",opts:["Permitted if coated with aluminum-compatible compound","Permitted only if coated or sleeved","Not permitted — aluminum corrodes in alkaline concrete environment","Permitted — aluminum is durable in concrete"],ans:2,ref:"NEC 250.64(A) & 250.120(B)",exp:"Aluminum and copper-clad aluminum EGCs cannot contact masonry (concrete, brick, mortar) — the alkaline environment causes rapid corrosion. Same restriction as for GECs. Always use copper where contact with concrete or earth occurs."},
{id:148,mod:4,cat:"Grounding & Bonding",diff:"Medium",q:"How must building structural steel that does not contact earth directly be treated?",opts:["Cannot be used as a grounding electrode","Bonded to another grounding electrode","Qualified if bonded to metal water pipe","Building must install a separate ground ring"],ans:1,ref:"NEC 250.52(A)(2)",exp:"Building structural steel not directly contacting earth must be bonded to the grounding electrode system through service grounding connections. Steel frame becomes part of the grounding electrode system through bonding."},
{id:149,mod:4,cat:"Grounding & Bonding",diff:"Medium",q:"A ground ring electrode must be buried a minimum of _____.",opts:["30 inches","18 inches","24 inches","6 inches"],ans:0,ref:"NEC 250.52(A)(4)",exp:"Ground ring must be buried at least 30 inches deep. Depth ensures conductor stays in moist soil and avoids freeze/thaw damage. The 30-inch depth + 50-foot minimum length + 2 AWG minimum copper are all required."},
{id:150,mod:4,cat:"Grounding & Bonding",diff:"Hard",q:"When multiple sets of service entrance conductors run in parallel, main bonding jumper sizing:",opts:["Total cross-sectional area determines one combined jumper","One jumper sized for the entire service","Separate bonding jumper for each parallel set, each sized based on that set's conductor size","Main bonding jumpers not required with parallel conductors"],ans:2,ref:"NEC 250.28(D)(2)",exp:"Parallel service conductors: a separate main bonding jumper is required for each set (each service section), with each jumper sized based on the conductor size in that raceway."},
// MODULE 5: WIRING METHODS (55)
{id:151,mod:5,cat:"Wiring",diff:"Easy",q:"The maximum conduit fill percentage for a single conductor is _____.",opts:["31 percent","40 percent","53 percent","60 percent"],ans:2,ref:"NEC Chapter 9, Table 1",exp:"One conductor = 53% max fill. Two conductors = 31%. Three or more = 40%. From Chapter 9 Table 1. The 53% single-conductor rule allows efficient packing of a round conductor in a round conduit."},
{id:152,mod:5,cat:"Wiring",diff:"Easy",q:"The maximum total degrees of bends between pull points in a conduit run is _____.",opts:["360 degrees","No limit on bends","270 degrees","180 degrees"],ans:0,ref:"NEC 358.26 (EMT)",exp:"360 degrees maximum between pull points — equivalent to four 90-degree bends. More bends make it impossible to pull wire. Universal rule regardless of conduit type or size."},
{id:153,mod:5,cat:"Wiring",diff:"Medium",q:"NM cable must be supported within _____ of every box or fitting.",opts:["6 inches","12 inches","18 inches","8 inches"],ans:1,ref:"NEC 334.30(A)",exp:"NM cable must be supported within 12 inches of every electrical box, cabinet, or fitting, and at intervals not exceeding 4.5 feet. The 12-inch rule ensures the cable is secured before entering the box."},
{id:154,mod:5,cat:"Wiring",diff:"Medium",q:"Where is NM cable (Romex) NOT permitted?",opts:["Wood-frame construction","Attics with insulation","Buildings less than three stories","Concealed spaces of masonry, concrete, or adobe"],ans:3,ref:"NEC 334.12",exp:"NM cable prohibited in masonry, concrete, adobe construction, areas with corrosive fumes, embedded in concrete, or exposed where subject to physical damage. NM cable's plastic jacket is not rated for these conditions."},
{id:155,mod:5,cat:"Wiring",diff:"Hard",q:"Schedule 40 PVC conduit under a residential driveway (not subject to truck traffic) must be buried a minimum of _____.",opts:["6 inches","18 inches","12 inches","24 inches"],ans:2,ref:"NEC Table 300.5",exp:"Under residential driveways (not subject to truck traffic), conduit must be buried at least 12 inches per Table 300.5. In open trenches, PVC requires 18 inches. Know burial depths by location and conduit type."},
{id:156,mod:5,cat:"Wiring",diff:"Medium",q:"Where is EMT NOT permitted?",opts:["Where subject to severe physical damage or in concrete","In walls of commercial buildings","In 2-inch diameter or less","Exposed on rooftops in direct sunlight"],ans:0,ref:"NEC 358.12",exp:"EMT not permitted where subject to severe physical damage, embedded in concrete, or in direct contact with earth. EMT's thin walls make it vulnerable to corrosion in soil and crushing under concrete. Use RMC or IMC in these conditions."},
{id:157,mod:5,cat:"Wiring",diff:"Medium",q:"What is the maximum number of 90-degree bends permitted in a run of EMT between pull points?",opts:["Number of bends doesn't matter — only conductor size determines pull points","Four 90-degree bends — 360 degrees total","Three 90-degree bends","Two 90-degree bends"],ans:1,ref:"NEC 358.26",exp:"Four 90-degree bends = 360 degrees maximum. Universal conduit bend rule regardless of conduit type or size. Four 90s are the absolute maximum before a pull box or conduit body is required."},
{id:158,mod:5,cat:"Wiring",diff:"Easy",q:"What is the maximum support spacing for EMT?",opts:["Every 3 feet","Every 6 feet","Every 2 feet","Every 10 feet — within 3 feet of boxes/fittings"],ans:3,ref:"NEC 358.30(A)",exp:"EMT must be secured at intervals not exceeding 10 feet and within 3 feet of each outlet box, junction box, device box, cabinet, conduit body, or other termination."},
{id:159,mod:5,cat:"Wiring",diff:"Hard",q:"What does the minimum bending radius for rigid metal conduit (RMC) depend on?",opts:["Trade size only","Trade size AND number of conductors inside","Trade size, insulation type, and bending method (one-shot vs. hand)","Outside diameter only"],ans:2,ref:"NEC 344.24 & Chapter 9 Table 2",exp:"Minimum bending radius for RMC depends on trade size, conductor insulation type (lead-covered requires larger radius), and whether a one-shot bender or hand bender is used. Bending too tightly can crack conductor insulation."},
{id:160,mod:5,cat:"Wiring",diff:"Medium",q:"What is required when conduit enters a wet location box from below?",opts:["A sealing fitting is required to prevent moisture migration","A drain fitting must be installed","No special requirements — water doesn't flow upward","Flexible conduit must be used for the last 18 inches"],ans:0,ref:"NEC 314.15",exp:"When conduit enters an enclosure from below in a wet location, a sealing fitting or other approved means must prevent moisture from entering. Condensation and water can travel through conduit by capillary action."},
{id:161,mod:5,cat:"Wiring",diff:"Medium",q:"The maximum support spacing for 1/2-inch trade size RMC is _____.",opts:["6 feet","10 feet","5 feet","8 feet"],ans:1,ref:"NEC Table 344.30(B)(2)",exp:"RMC 1/2-inch to 3/4-inch trade size must be supported within 3 feet of outlets and at intervals not exceeding 10 feet. For 1-inch to 1¼-inch, support every 12 feet. Know support intervals by conduit type."},
{id:162,mod:5,cat:"Wiring",diff:"Hard",q:"A 1/2-inch EMT conduit can hold a maximum of _____ 12 AWG THWN conductors per Annex C.",opts:["3","4","5","7"],ans:3,ref:"NEC Annex C, Table C1",exp:"Per Annex C (Table C1 for EMT): 1/2-inch EMT = 7 conductors of 12 AWG THWN. Direct table lookup at the test site — the fastest way to answer fill questions on the exam. Memorize: 1/2\" EMT holds 7×12AWG or 9×14AWG THWN."},
{id:163,mod:5,cat:"Wiring",diff:"Medium",q:"What is the key difference between Schedule 40 PVC and Schedule 80 PVC conduit?",opts:["Schedule 40 for underground; Schedule 80 for above-ground","Schedule 40 is gray; Schedule 80 is white","Schedule 80 rated for higher voltage","Schedule 80 has same OD but thicker walls and smaller ID — better crush resistance"],ans:3,ref:"NEC 352.10 & 352.12",exp:"Schedule 80 = same outside diameter (OD) as Schedule 40 but thicker walls → smaller interior diameter (ID). Stronger, required where exposed to physical damage. Holds fewer conductors than Schedule 40 of the same trade size."},
{id:164,mod:5,cat:"Wiring",diff:"Hard",q:"When must expansion fittings be used with PVC conduit?",opts:["Always — PVC always requires expansion fittings","Expansion fittings optional for residential","When temperature change would cause expansion exceeding 1/4 inch based on coefficient of expansion","When run exceeds 10 feet"],ans:2,ref:"NEC 352.44",exp:"PVC has high coefficient of thermal expansion — much higher than metal conduit. Expansion fittings required when conduit length change due to temperature changes exceeds allowable limits. Long straight runs in California's temperature extremes can buckle without expansion fittings."},
{id:165,mod:5,cat:"Wiring",diff:"Medium",q:"What termination is required for MC cable?",opts:["Connectors specifically listed for MC cable","Only anti-short bushings","No connector needed — armor provides its own seal","Standard NM cable connectors"],ans:0,ref:"NEC 330.40",exp:"MC cable must be terminated with connectors specifically listed for MC cable. These connectors grip the armor correctly and provide the transition from armored cable to the box. Wrong connector can damage conductor insulation."},
{id:166,mod:5,cat:"Wiring",diff:"Easy",q:"What is the purpose of the anti-short bushing used with armored cable (AC/BX)?",opts:["Prevent moisture from entering the cable","Protect wire insulation from sharp edges of cut armor at the termination","Secure the cable to the junction box","Provide the grounding path through the armor"],ans:1,ref:"NEC 320.40",exp:"Anti-short bushing ('red head') inserted between cut armor end and conductors to protect wire insulation from sharp metal edges. Missing anti-short bushings = one of the most common AC/BX cable inspection failures."},
{id:167,mod:5,cat:"Wiring",diff:"Hard",q:"Each 12 AWG conductor entering a box requires _____ of box fill volume.",opts:["3.00 cubic inches","2.00 cubic inches","2.50 cubic inches","2.25 cubic inches"],ans:3,ref:"NEC Table 314.16(B)",exp:"Per Table 314.16(B): 12 AWG = 2.25 cubic inches per conductor. 14 AWG = 2.0 cu in, 10 AWG = 2.5 cu in. Each conductor entering the box (regardless of whether it's spliced) counts as one conductor for fill."},
{id:168,mod:5,cat:"Wiring",diff:"Hard",q:"A box with four 12 AWG conductors, one EGC, and one duplex receptacle requires a minimum box volume of _____.",opts:["13.5 cubic inches","9 cubic inches","15.75 cubic inches","11.25 cubic inches"],ans:2,ref:"NEC 314.16(B)",exp:"Box fill: 4 conductors × 2.25 = 9.0 cu in + EGC group (1 conductor's worth = 2.25 cu in) + device (2 conductors' worth = 4.50 cu in) = 15.75 cu in minimum."},
{id:169,mod:5,cat:"Wiring",diff:"Medium",q:"Where is LFMC (Liquidtight Flexible Metal Conduit) commonly used?",opts:["Motor and HVAC equipment requiring vibration isolation and liquidtight protection","Underground services only","Fluorescent lighting fixtures in commercial buildings","Panel-to-panel connections in wet locations"],ans:0,ref:"NEC 350.10",exp:"LFMC ideal for motors, HVAC, and other vibrating equipment in wet or oily locations. Standard connection method for rooftop HVAC units and compressors. Flexible construction absorbs vibration; liquidtight jacket prevents oil and moisture."},
{id:170,mod:5,cat:"Wiring",diff:"Medium",q:"What does 'trade size' refer to when describing conduit?",opts:["Actual outside diameter","Nominal designation approximating the inside diameter for conductor fill purposes","Maximum conductor size that fits","Wall thickness"],ans:1,ref:"NEC Chapter 9, Note 1",exp:"Trade size = nominal designation (approximate inside diameter) used for standardization. Actual inside diameter differs from trade size. Trade size determines which Annex C fill tables to use."},
{id:171,mod:5,cat:"Wiring",diff:"Hard",q:"What must underground raceways do when entering buildings?",opts:["No special treatment required at building entry","Transition to RMC at the building wall","Have an expansion fitting installed","Be sealed at their entry point to prevent moisture, gases, and insects from entering the building"],ans:3,ref:"NEC 300.5(G)",exp:"Underground raceways entering buildings must be sealed at entry point to prevent moisture, gases, and insects from migrating into the building. Especially important in California where natural gas can accumulate in conduits from underground utility leaks."},
{id:172,mod:5,cat:"Wiring",diff:"Medium",q:"FMC may serve as the EGC when the total length does not exceed _____.",opts:["10 feet","3 feet","6 feet","25 feet"],ans:2,ref:"NEC 250.118(5)",exp:"FMC as EGC maximum = 6 feet total length (for circuits up to 20A, or 60A with listed fittings for larger circuits). Beyond 6 feet, separate EGC required. Longer FMC has too much impedance for reliable fault current flow."},
{id:173,mod:5,cat:"Wiring",diff:"Medium",q:"What wiring method is preferred for conduit runs in a concrete slab poured on grade?",opts:["PVC Schedule 40 is preferred","Any conduit is acceptable in concrete","RMC or IMC — or Schedule 80 PVC","EMT preferred for thin walls"],ans:0,ref:"NEC 352.10(C) & 344.10",exp:"PVC Schedule 40 preferred for concrete-encased installations — doesn't corrode, concrete provides protection. RMC also acceptable. EMT not listed for direct burial in earth or concrete."},
{id:174,mod:5,cat:"Wiring",diff:"Medium",q:"Where NM cable passes through a wood stud with less than 1-1/4 inch from the stud edge, what is required?",opts:["The cable must be in conduit through the stud","A 1/16-inch thick steel plate (nail plate) must protect the cable","No protection required for NM cable in wood studs","Reroute cable to maintain minimum edge distance"],ans:1,ref:"NEC 300.4(A)(1)",exp:"Where NM cable or any wiring passes through a stud with less than 1¼-inch clearance from the edge, a 1/16-inch thick steel nail plate must protect the cable from drywall nails and screws."},
{id:175,mod:5,cat:"Wiring",diff:"Easy",q:"NM cable must be supported at intervals not exceeding _____.",opts:["6 feet","2.5 feet","18 inches","4.5 feet"],ans:3,ref:"NEC 334.30",exp:"NM cable must be supported at intervals not exceeding 4.5 feet (54 inches) and within 12 inches of every box, cabinet, or fitting. Prevents sagging and protects cable from damage."},
{id:176,mod:5,cat:"Wiring",diff:"Medium",q:"What is the key difference between underground feeder (UF) cable and NM cable?",opts:["UF and NM are interchangeable","UF uses aluminum conductors only","UF has solid PVC jacket suitable for direct burial in earth","UF rated for higher voltages"],ans:2,ref:"NEC Article 340",exp:"UF cable has solid PVC jacket encapsulating individual conductors, making it suitable for direct burial. NM cable's outer jacket is NOT rated for direct soil contact. Use UF for direct burial; NM for in-wall applications."},
{id:177,mod:5,cat:"Wiring",diff:"Medium",q:"What is the purpose of a pull box in a conduit system?",opts:["Allow conductors to be pulled through conduit runs with many bends or long straight sections","Provide access for splice connections","Connect conduit at 90-degree angles","Provide weatherproof enclosure"],ans:0,ref:"NEC 314.28",exp:"Pull boxes allow conductors to be pulled through long or complex conduit runs. Required when bends exceed 360 degrees. Must remain accessible. Need not contain splices."},
{id:178,mod:5,cat:"Wiring",diff:"Hard",q:"When more than 4 current-carrying conductors are installed in a single conduit, what adjustment factor applies per Table 310.15(C)(1)?",opts:["4-6 conductors: 70%; 7-9 conductors: 50%","4-6 conductors: 80% of ampacity; 7-9 conductors: 70%","3-5 conductors: 80%; 6-8 conductors: 60%","No derating required for 4 conductors"],ans:1,ref:"NEC 2020 Table 310.15(C)(1)",exp:"Standard derating table: 4-6 current-carrying conductors = 80%; 7-9 = 70%; 10-20 = 50%; 21-30 = 45%; 31-40 = 40%; 41+ = 35%. These factors account for mutual heating of multiple loaded conductors in the same raceway."},
{id:179,mod:5,cat:"Wiring",diff:"Medium",q:"Direct-buried conductors under residential property (not subject to vehicle traffic) must be buried a minimum of _____.",opts:["12 inches","18 inches","30 inches","24 inches"],ans:3,ref:"NEC Table 300.5",exp:"Direct-buried conductors (not in conduit) require 24 inches of cover under general conditions. Reduced to 18 inches for most raceway applications and 6 inches for RMC. The 24-inch depth protects from routine digging like garden spading."},
{id:180,mod:5,cat:"Wiring",diff:"Hard",q:"What is required when conductors in a raceway have different temperatures on opposite ends (temperature differentials)?",opts:["Made of PVC to handle thermal expansion","Expansion fittings at the temperature boundary","Sealed with appropriate compound to prevent condensation and air flow through the raceway","Installed horizontally to prevent condensation drain"],ans:2,ref:"NEC 300.7(A)",exp:"Raceways between areas with significant temperature differences must be sealed to prevent warm moist air flowing toward the cold end where it condenses. Critical for California buildings crossing temperature-controlled boundaries."},
{id:181,mod:5,cat:"Wiring",diff:"Easy",q:"What is the main advantage of RMC over EMT?",opts:["RMC can be used in concrete, in fill, and in direct contact with earth — where EMT is not permitted","RMC is less expensive","RMC conducts electricity better","RMC is easier to bend"],ans:0,ref:"NEC 344.10 vs 358.12",exp:"RMC's thick galvanized steel walls allow direct earth contact, embedding in concrete, and use where subject to severe physical damage — all applications where EMT is prohibited. Tradeoff = higher cost and more difficult installation."},
{id:182,mod:5,cat:"Wiring",diff:"Hard",q:"How must PVC conduit cut ends be prepared before making connections?",opts:["Only factory-cut ends may be used","Cut ends must be reamed and all burrs removed to prevent conductor insulation damage","PVC ends must be flame-polished to seal the cut edge","Cut ends can be connected without preparation"],ans:1,ref:"NEC 352.28",exp:"After cutting PVC conduit, cut end must be reamed to remove burrs that could damage conductor insulation during pulling. Also true for metal conduits. Failing to ream is a primary cause of insulation damage during wire pulling."},
{id:183,mod:5,cat:"Wiring",diff:"Medium",q:"May MC cable armor serve as the equipment grounding conductor?",opts:["Never — separate EGC always required","Always — metal armor provides a grounding path","Only for circuits up to 20A","Only when the armor is listed as a grounding means and proper listed connectors are used"],ans:3,ref:"NEC 250.118(10)",exp:"MC cable armor may serve as EGC when the cable is listed for that purpose AND proper listed connectors are used. Some MC cable types require a separate EGC within the cable assembly. Always check listing information."},
{id:184,mod:5,cat:"Wiring",diff:"Medium",q:"What requirement must junction box covers meet?",opts:["Bond the box to the conduit with a grounding screw","Have a minimum of 10 cubic inches capacity","Be secured with screws and the box must remain accessible","Be marked with the circuit number"],ans:2,ref:"NEC 314.28(C) & 314.29",exp:"Junction box covers must be secured AND the box must remain accessible — cannot be covered with building finishes without providing access. Boxes behind drywall with no access panel are code violations."},
{id:185,mod:5,cat:"Wiring",diff:"Medium",q:"What must EMT fittings be in wet locations?",opts:["Standard compression fittings are acceptable","EMT not permitted in wet locations","Raintight or weatherproof fittings listed for wet locations","Set-screw fittings if painted"],ans:2,ref:"NEC 358.42",exp:"In wet locations, EMT fittings must be raintight type listed for wet locations. Set-screw fittings are suitable for dry locations only. EMT itself is permitted in wet locations with appropriate raintight fittings."},
{id:186,mod:5,cat:"Wiring",diff:"Medium",q:"What type of cable is used for Type MC in healthcare facilities (patient care areas)?",opts:["Residential applications only","MC cable with full-size insulated neutral and EGC where permitted by Article 517","Any application where NM cable is permitted","Commercial buildings only"],ans:1,ref:"NEC Article 330",exp:"MC cable is widely used in commercial construction and can be used in healthcare facilities, patient care areas, and similar applications where metallic protection is required but rigid conduit would be impractical."},
{id:187,mod:5,cat:"Wiring",diff:"Hard",q:"What is the minimum trade size conduit permitted for connecting to luminaires?",opts:["1/2 inch is absolute minimum for all applications","1/4 inch FMC for 6 feet or less","1/2 inch — smaller sizes not listed for branch circuit wiring","3/8 inch — may be used for short sections connecting to luminaires"],ans:3,ref:"NEC 348.20(A)(1) Exception",exp:"3/8-inch trade size flexible metal conduit is permitted for short sections (up to 6 feet) connecting to luminaires. For general wiring, 1/2-inch is the minimum. The 3/8-inch FMC exception is specific to fixture connections."},
{id:188,mod:5,cat:"Wiring",diff:"Medium",q:"How must NM cable in an unfinished basement be installed when exposed on the surface of joists?",opts:["Only if accessible from a floor below","All exposed basement wiring must be in conduit","Protected from physical damage when exposed","Only if within 7 feet of the floor requires protection"],ans:2,ref:"NEC 334.15",exp:"NM cable in unfinished basements must be protected from physical damage when exposed. Many inspectors require NM cable to run through drilled holes in joists rather than along surfaces to ensure protection."},
{id:189,mod:5,cat:"Wiring",diff:"Hard",q:"When multiple conduits run together in a parallel bank with little spacing — what applies?",opts:["For more than 3 current-carrying conductors in a bundle, ampacity adjustment factors apply","Conduits must touch each other to save space","No spacing requirement for parallel conduits","Only conduits carrying 200A+ require spacing"],ans:0,ref:"NEC 2020 Table 310.15(C)(1)",exp:"When conductors are bundled or multiple conduits run closely together, mutual heating occurs. Table 310.15(C)(1) derating applies when more than 3 current-carrying conductors are bundled. Significant for densely routed conduit banks."},
{id:190,mod:5,cat:"Wiring",diff:"Hard",q:"Which conductors are NOT counted as current-carrying for derating purposes?",opts:["Neutral conductors are never current-carrying","EGCs and certain neutral conductors are not current-carrying for derating purposes","All conductors in a raceway count for derating","When neutral carries only unbalanced load in 3-phase system, it is not counted as current-carrying"],ans:1,ref:"NEC 2020 310.15(E)(1)",exp:"For derating purposes: EGCs never count. A neutral carrying only unbalanced current in a 3-phase system is NOT counted. However, if the neutral carries significant harmonic currents (common with electronic loads), it DOES count. This nuance appears on advanced exam questions."},
{id:191,mod:5,cat:"Wiring",diff:"Easy",q:"What is the most commonly used conduit type for exposed residential wiring in garages and basements?",opts:["PVC Schedule 80","RMC (Rigid Metal Conduit)","FMC (Flexible Metal Conduit)","EMT (Electrical Metallic Tubing)"],ans:3,ref:"NEC Article 358",exp:"EMT = most common conduit for exposed residential and light commercial wiring. Lightweight, easy to bend, good protection. Not rated for direct burial in earth, but excellent for exposed above-grade applications."},
{id:192,mod:5,cat:"Wiring",diff:"Hard",q:"Does the NEC mandate specific conductor colors for ungrounded conductors in 3-phase systems above 50V?",opts:["Brown, orange, yellow for phases; gray for neutral — required","Red, black, and blue for phases is the only acceptable scheme","No mandatory color code for ungrounded conductors above 50V — only grounded and EGC conductors have mandatory colors","Phase A=black, B=red, C=blue; Neutral=white — required"],ans:2,ref:"NEC 210.5(C)",exp:"NEC does NOT mandate specific color codes for ungrounded (hot) conductors above 50V. Grounded conductors must be white or gray; EGCs must be green. Industry uses black-red-blue (120/208V) and brown-orange-yellow (277/480V) as conventions, not code requirements."},
{id:193,mod:5,cat:"Wiring",diff:"Medium",q:"What is the maximum ambient temperature rating for Type THWN-2 cable?",opts:["90°C in both wet and dry locations","75°C in wet locations only","60°C in dry locations only","THWN-2 is only rated for dry at 75°C"],ans:0,ref:"NEC Table 310.4",exp:"THWN-2 = 90°C in BOTH wet and dry locations. Regular THWN = 75°C wet, 90°C dry. THHN = 90°C dry only. For conductors in wet locations, THWN or THWN-2 required. Temperature rating determines which Table 310.16 column to use."},
{id:194,mod:5,cat:"Wiring",diff:"Medium",q:"What is the purpose of reducing washers when installing conduit into a knockout?",opts:["Only provide the grounding bond","Fill the gap between an oversized knockout and smaller conduit — maintaining enclosure integrity AND providing grounding bond","Reduce the conduit trade size at entry","Only fill the gap"],ans:1,ref:"NEC 250.97 & 314.21",exp:"Reducing washer fills space between oversized knockout and smaller conduit, maintaining box enclosure AND contributing to the grounding bond between conduit and box. Wrong-size conduit in knockout without reducing washer fails both enclosure integrity and grounding."},
{id:195,mod:5,cat:"Wiring",diff:"Hard",q:"What minimum conduit trade size is permitted for general wiring in NEC?",opts:["1/2 inch — smaller sizes not listed for branch circuit wiring","1/2 inch is absolute minimum for all applications","1/4 inch FMC permitted for 6 feet or less","3/8 inch FMC may be used for short sections connecting to luminaires"],ans:3,ref:"NEC 348.20(A)(1)",exp:"For general wiring, 1/2-inch is the minimum. However, 3/8-inch FMC is permitted for limited applications — short sections up to 6 feet connecting to luminaires. The 3/8-inch exception is specific."},
{id:196,mod:5,cat:"Wiring",diff:"Hard",q:"Under what condition may a conduit body (LB, LL, LR, T-body) be used for splices?",opts:["Conduit bodies may always be used for splices","Conduit bodies shall not be used as junction boxes — only pull boxes","Only when the cubic inch capacity is marked and adequate AND the body is listed for that use","Splices are never permitted in conduit bodies"],ans:2,ref:"NEC 314.16(C)(2)",exp:"Conduit bodies may only be used for splices when listed for that use AND marked with fill capacity in cubic inches. If not marked for splicing, may only be used as a pull point. Most standard conduit bodies are NOT listed for splicing."},
{id:197,mod:5,cat:"Wiring",diff:"Medium",q:"The maximum support interval for 1-inch PVC conduit is _____.",opts:["Every 3 feet","Every 6 feet — within 3 feet of boxes","Every 10 feet for all PVC sizes","Every 5 feet — within 3 feet of boxes"],ans:0,ref:"NEC Table 352.30(B)",exp:"PVC conduit support intervals vary by trade size. 1/2-inch to 1-inch PVC must be supported every 3 feet. Larger sizes allow longer spacing. PVC is less rigid than metal conduit and requires more frequent support to prevent sagging."},
{id:198,mod:5,cat:"Wiring",diff:"Hard",q:"What requirements apply to pull boxes for conductors 4 AWG and larger?",opts:["No size requirements — any accessible box qualifies","Be large enough to permit the minimum conductor bending radius based on conduit sizes entering the box","Only be required when more than three conduits enter the box","Be larger than the standard junction box — minimum size required by code"],ans:1,ref:"NEC 314.28(A)",exp:"Pull boxes for conductors 4 AWG+ must meet specific dimension requirements based on conduit sizes entering the box. The minimum dimensions ensure conductors aren't bent too sharply, which would damage insulation."},
{id:199,mod:5,cat:"Wiring",diff:"Medium",q:"What materials are permitted for cable trays in industrial facilities?",opts:["Aluminum or steel only","Steel only","Fiberglass or metallic materials as approved","Any listed material including non-metallic"],ans:3,ref:"NEC 392.10(A)",exp:"Cable trays may be metal (steel, aluminum, stainless steel) or non-metallic (fiberglass) as long as listed for the application. Fiberglass cable trays are common in corrosive environments like chemical plants."},
{id:200,mod:5,cat:"Wiring",diff:"Hard",q:"What derating factor applies when 12 current-carrying conductors are in a single conduit?",opts:["70% (7-9 conductors)","80% (4-6 conductors)","50% (10-20 conductors)","35% (21-30 conductors)"],ans:2,ref:"NEC 2020 Table 310.15(C)(1)",exp:"Per Table 310.15(C)(1): 10-20 current-carrying conductors = 50% adjustment factor. Conductor normally rated 30A must be derated to 30 × 0.50 = 15A. Severe derating for many conductors reflects substantial mutual heating."},
{id:201,mod:5,cat:"Wiring",diff:"Medium",q:"What conduit type is recommended for corrosive industrial environments?",opts:["PVC Schedule 80 or stainless steel RMC","Standard galvanized EMT","Aluminum conduit preferred for corrosive environments","Flexible metal conduit (FMC)"],ans:0,ref:"NEC 352.10 & 344.10",exp:"PVC Schedule 80 or stainless steel RMC for corrosive industrial environments. Standard galvanized steel and aluminum conduit corrode in chemical atmospheres. In California food processing facilities, stainless steel conduit is often specified."},
{id:202,mod:5,cat:"Wiring",diff:"Hard",q:"What is the maximum length of LFNC (Liquidtight Flexible Nonmetallic Conduit) for a single connection?",opts:["12 feet","6 feet","No length restriction","3 feet"],ans:1,ref:"NEC 356.60",exp:"LFNC maximum = 6 feet for general use. Beyond 6 feet, a rigid conduit system should be used. The 6-foot limit prevents LFNC from substituting for permanent raceway installations."},
{id:203,mod:5,cat:"Wiring",diff:"Medium",q:"What is the maximum length of LFMC that may serve as an EGC?",opts:["10 feet","3 feet","25 feet","6 feet"],ans:3,ref:"NEC 250.118(6)",exp:"LFMC as EGC: same 6-foot maximum rule as FMC for circuits up to 20A. Beyond 6 feet, a separate EGC is required. Longer flexible conduit has too much impedance for reliable fault current flow."},
{id:204,mod:5,cat:"Wiring",diff:"Medium",q:"When bundling conductors for derating, which conductors are counted as current-carrying?",opts:["EGCs never count; neutrals may or may not count depending on loading conditions","Only phase conductors count — neutrals are never current-carrying","All conductors count","Only conductors over 10 AWG need to be counted"],ans:0,ref:"NEC 2020 310.15(E)(1)",exp:"EGCs never count for derating. Neutral conductors: count when carrying unbalanced current in single-phase systems; may not count in balanced 3-phase systems with linear loads. Neutrals in systems with non-linear loads (harmonics) DO count."},
{id:205,mod:5,cat:"Wiring",diff:"Hard",q:"What is the maximum ambient temperature rating for standard THWN (not THWN-2) in a wet location?",opts:["60°C in wet locations","75°C in wet locations","90°C in both wet and dry locations","THWN is only rated for dry locations at 75°C"],ans:1,ref:"NEC Table 310.4",exp:"THWN (not -2): 75°C in wet locations; 90°C in dry locations. THWN-2: 90°C in both wet and dry locations. For wet locations requiring 90°C ampacity, THWN-2 is required. Know the insulation type designations and their ratings."},
// MODULE 6: EQUIPMENT GENERAL USE (35)
{id:206,mod:6,cat:"Equipment General Use",diff:"Easy",q:"Which is a permitted use of flexible cord?",opts:["Permanently supplying a ceiling fan","Connecting portable appliances that are frequently moved","Running cord through a wall between rooms","Using cord as feeder between two panels"],ans:1,ref:"NEC 400.7 & 400.8",exp:"Portable appliances frequently moved = primary permitted use of flexible cord. Cord cannot substitute for fixed wiring — cannot be concealed in walls, passed through holes in walls, or used as permanent wiring."},
{id:207,mod:6,cat:"Equipment General Use",diff:"Medium",q:"What clearance must a luminaire in a clothes closet maintain from storage areas?",opts:["18 inches","3 inches","24 inches","6 inches for fluorescent; 12 inches for incandescent with enclosed lamp"],ans:3,ref:"NEC 410.16(A) & (B)",exp:"Incandescent and LED with enclosed lamp = 12 inches clearance. Surface-mounted fluorescent or LED without exposed lamp = 6 inches. Pendant and track luminaires prohibited in clothes closets."},
{id:208,mod:6,cat:"Equipment General Use",diff:"Easy",q:"What box is required to support a ceiling fan?",opts:["Any metallic box attached directly to joists","Standard lighting box with fan brace","A box specifically listed for ceiling fan support","Any listed 4-inch octagonal box rated 35 lbs"],ans:2,ref:"NEC 314.27(C)",exp:"Ceiling fans must be supported by a box specifically listed for fan support. Standard lighting boxes cannot handle dynamic loads (vibration, rotation, lateral movement) of a ceiling fan. Required by listing, not just weight rating."},
{id:209,mod:6,cat:"Equipment General Use",diff:"Medium",q:"Is it permitted to run an extension cord permanently through a doorway to supply a freezer on a porch?",opts:["Prohibited — permanent use of extension cords through building elements","Acceptable — extension cords are safe up to 12 feet","Requires only GFCI protection to be acceptable","Acceptable if the cord is rated for outdoor use"],ans:0,ref:"NEC 400.8(5)",exp:"Running extension cords permanently through doorways, windows, or similar openings is prohibited. Extension cords are for temporary, portable use. Permanent routing creates wear and shock hazards."},
{id:210,mod:6,cat:"Equipment General Use",diff:"Medium",q:"What rating must the switch controlling a bathroom fan-heater combination have?",opts:["A standard single-pole switch","Listed for the specific heater load and voltage","A timer switch","A double-pole switch"],ans:1,ref:"NEC 424.19 & 404.14(A)",exp:"Switches controlling bathroom heating devices must be listed for the specific load. Fan-heater combinations with heating elements require switches rated for the heater's current and voltage. Using an under-rated switch can cause switch failure or fire."},
{id:211,mod:6,cat:"Equipment General Use",diff:"Hard",q:"What is the maximum cord length for a cord-supported pendant luminaire without supplemental support?",opts:["3 feet","10 feet for pendants over 50 watts","No maximum — limited by the listing","6 feet of cord maximum without additional support"],ans:3,ref:"NEC 410.36(G)",exp:"Cord-connected pendant luminaires must not have more than 6 feet of cord from the box unless supplemental support is provided. The cord must be suitable for the purpose and the luminaire weight must not exceed cord rating."},
{id:212,mod:6,cat:"Equipment General Use",diff:"Medium",q:"What rating must a switch have when controlling a fluorescent lighting circuit at 120V?",opts:["A 277V rated switch must be used for any fluorescent circuit","No specific switch rating required for fluorescent","SWD (Switching Duty) rated switch or breaker","Standard AC general-use snap switch is sufficient"],ans:2,ref:"NEC 404.14(B)(1)",exp:"Switches controlling fluorescent lighting loads must be rated SWD (Switching Duty). Standard AC switches are not rated for the repetitive switching cycles with fluorescent lighting. SWD rating ensures the switch can handle inductive switching stress."},
{id:213,mod:6,cat:"Equipment General Use",diff:"Easy",q:"How may a freestanding electric range in a dwelling be connected?",opts:["Cord-and-plug connected using a 4-wire range cord","Hardwired with 8 AWG minimum","Cord-and-plug with a 3-wire cord for older outlet compatibility","Permanently hardwired only — cord-and-plug prohibited"],ans:0,ref:"NEC 422.16(B)(3)",exp:"Electric ranges may be cord-and-plug connected using a 4-wire range cord (in new installations). The four wires: hot, hot, neutral, and EGC. New installations since 1996 require 4-wire cords. Old 3-wire connections in existing dwellings may remain."},
{id:214,mod:6,cat:"Equipment General Use",diff:"Hard",q:"Per Table 220.55, what is the demand factor for one household electric range rated 11 kW?",opts:["11,000 × 80% = 8,800 VA","Column C for one range: 8,000 VA","11,000 VA at 100%","8,000 VA per NEC Table 220.55"],ans:1,ref:"NEC Table 220.55",exp:"For one household range 8¾ kW to 12 kW, Table 220.55 Column C = 8,000 VA demand. The actual 11 kW nameplate is irrelevant — the table value governs. For ranges over 12 kW, add 5% per kW above 12 kW to the 8 kW base."},
{id:215,mod:6,cat:"Equipment General Use",diff:"Medium",q:"What must the disconnecting means for a dwelling unit 240V central A/C meet?",opts:["Panel breaker is sufficient — no additional disconnect","Lockable disconnect at equipment regardless of sight distance","Only required if unit is more than 50 feet from panel","Within sight of and accessible from the equipment"],ans:3,ref:"NEC 440.14",exp:"Readily accessible disconnecting means within sight of air conditioning and heat pump equipment. 'Within sight' = visible and within 50 feet. May be a fusible switch, non-fused disconnect, or circuit breaker."},
{id:216,mod:6,cat:"Equipment General Use",diff:"Medium",q:"What requirement must electric space heaters in bathrooms meet?",opts:["Permanently installed and maximum 1,500 watts","GFCI protected","Permanently installed — cord-and-plug connected heaters prohibited in bathrooms","Approved for wet locations"],ans:2,ref:"NEC 424.16 & 424.58",exp:"Electric space heaters in bathrooms must be permanently installed — cord-and-plug connected space heaters are prohibited in bathrooms. Prevents dangerous use of moveable electric heaters near water."},
{id:217,mod:6,cat:"Equipment General Use",diff:"Hard",q:"What listing is required for luminaires in bathtub or shower zones?",opts:["Listed and marked suitable for the zone — wet locations within tub/shower space require wet-location listing","AFCI protected","No special protection if mounted on the ceiling","A GFCI circuit is required but fixture needs no special rating"],ans:0,ref:"NEC 410.10(D)",exp:"Luminaires in zone 1 (inside tub or shower) must be listed and marked suitable for wet locations. Zone 2 (immediately outside tub) requires damp-location listing. Using a standard dry-rated fixture in a shower is dangerous."},
{id:218,mod:6,cat:"Equipment General Use",diff:"Easy",q:"What is the maximum overcurrent protection permitted for a panelboard?",opts:["A 200A panel may have no more than a 200A main breaker","The feeder OCPD must not exceed the panelboard's bus bar rating","Total of all branch circuit breakers cannot exceed the bus rating","The panelboard overcurrent protection may not exceed the panelboard bus rating"],ans:1,ref:"NEC 408.36",exp:"Overcurrent device protecting a panelboard feeder must not exceed the rating of the panelboard's bus bar. Protects bus bars from overload. Exception: main lugs only panels protected by the building's service OCPD."},
{id:219,mod:6,cat:"Equipment General Use",diff:"Medium",q:"What is the maximum cord length for a household garbage disposal?",opts:["18 inches","2 feet","4 feet","3 feet"],ans:3,ref:"NEC 422.16(B)(1)",exp:"Garbage disposals: maximum 3-foot cord length. Must be connected to a 20A, 120V individual branch circuit. 3-foot limit keeps cord under the sink and prevents hazards."},
{id:220,mod:6,cat:"Equipment General Use",diff:"Medium",q:"How can a single GFCI outlet protect multiple bathroom receptacles?",opts:["Multiple GFCIs must be installed — one per outlet","A dedicated panel GFCI breaker only","The load-side terminals of the GFCI outlet","Only one GFCI per circuit — additional protection not possible"],ans:2,ref:"NEC 406.4(D)(2)",exp:"A single GFCI outlet or GFCI breaker can protect multiple downstream outlets through the load-side connections. One GFCI at the first outlet can protect additional bathroom outlets in the same bathroom. Economical and common practice."},
{id:221,mod:6,cat:"Equipment General Use",diff:"Hard",q:"What is the difference between IC-rated and non-IC recessed luminaires in an attic?",opts:["IC-rated fixtures may have insulation against them; non-IC fixtures must maintain clearance","At least 6 inches from all insulation","No clearance required for modern LED recessed fixtures","3 inches minimum from all sides if rated IC"],ans:0,ref:"NEC 410.116(B)",exp:"IC-rated (Insulation Contact) recessed fixtures: insulation may be placed directly against them. Non-IC rated fixtures: must maintain clearance from insulation per their listing. Using a non-IC fixture covered with insulation is a fire hazard."},
{id:222,mod:6,cat:"Equipment General Use",diff:"Medium",q:"What do MCA and MOCP values on HVAC equipment nameplates determine?",opts:["MCA = minimum current allowed; MOCP = maximum operating current permitted","MCA = minimum circuit ampacity (conductor size); MOCP = maximum overcurrent protection (breaker/fuse size)","Both values are advisory only — use 125% FLA for all HVAC sizing","MCA = motor current; MOCP = motor overload protection"],ans:1,ref:"NEC 440.4(B) & 440.22",exp:"MCA (Minimum Circuit Ampacity) determines conductor sizing. MOCP (Maximum Overcurrent Protection) determines maximum breaker or fuse size. The MOCP on the nameplate governs — not a percentage calculation. Never exceed the MOCP rating."},
{id:223,mod:6,cat:"Equipment General Use",diff:"Medium",q:"A 1,500W, 120V portable space heater is a continuous load. How much current does it draw?",opts:["20 amperes","15 amperes","10 amperes","12.5 amperes"],ans:3,ref:"NEC Article 100 & 210.20(A)",exp:"1,500W ÷ 120V = 12.5A. On a 15A circuit, 80% continuous limit = 12A. 12.5A exceeds 12A continuous limit — technically requires a 20A circuit. In practice, this is why dedicated circuits for space heaters prevent tripped breakers."},
{id:224,mod:6,cat:"Equipment General Use",diff:"Easy",q:"What does 'listed' mean when applied to electrical equipment?",opts:["Recommended by the manufacturer","Certified by the installing electrician","Included in a published list from an organization like UL or ETL that verified it meets applicable standards","Approved by local building department"],ans:2,ref:"NEC Article 100",exp:"Listed = appears in a published list from a recognized testing lab (UL, ETL, CSA, etc.) confirming the product meets applicable safety standards. The listing mark on products indicates testing. NEC generally requires listed equipment throughout."},
{id:225,mod:6,cat:"Equipment General Use",diff:"Medium",q:"A 120V, 20A appliance circuit supplies a 1,500-watt countertop microwave. Is this code compliant?",opts:["Yes — 12.5A is under 15A and well within the 20A circuit","Microwave requires a 30A circuit due to startup current","Microwaves are not continuous loads — appliance cycles on and off","Not unless microwave is connected to a dedicated 20A circuit"],ans:0,ref:"NEC 210.20(A)",exp:"1,500W ÷ 120V = 12.5A. On a 20A circuit, continuous load limit = 16A (80%). Microwaves generally are NOT continuous loads (don't run 3+ hours). 12.5A on a 20A circuit is code compliant. "},
{id:226,mod:6,cat:"Equipment General Use",diff:"Hard",q:"What is the minimum clearance between a cooking surface and the bottom of an overhead combustible cabinet?",opts:["24 inches","30 inches","18 inches","No NEC requirement — kitchen design standards govern"],ans:1,ref:"NEC 410.10(C)",exp:"30 inches minimum between cooking surface and bottom of combustible overhead cabinets. Prevents fires from range-top cooking. Kitchen vent hoods also need specific clearances from the cooking surface."},
{id:227,mod:6,cat:"Equipment General Use",diff:"Hard",q:"What is the required box fill for a single-gang box with one single-pole switch, four 14 AWG conductors, and one EGC?",opts:["12 cubic inches","Box fill depends on connections, not conductor count","18 cubic inches","14 cubic inches"],ans:3,ref:"NEC 314.16(B)",exp:"Box fill: 4 conductors × 2.0 (14 AWG) = 8.0 cu in + device (2 conductors = 4.0 cu in) + EGC group (1 × 2.0 = 2.0 cu in) = 14.0 cu in minimum. Standard 2×4×1.875 device boxes are 13.5 cu in — this installation needs a deeper box."},
{id:228,mod:6,cat:"Equipment General Use",diff:"Medium",q:"What is the maximum ampere rating for a standard household receptacle outlet?",opts:["15 amperes","30 amperes","20 amperes","No maximum — match circuit rating"],ans:2,ref:"NEC 406.3",exp:"Standard household receptacles are rated 15A or 20A. A 15A receptacle may be used on a 20A circuit. 30A and 50A receptacles are for large appliances but are not 'standard household' receptacles."},
{id:229,mod:6,cat:"Equipment General Use",diff:"Hard",q:"When replacing a non-grounding (2-prong) outlet on a circuit without an EGC, the NEC permits:",opts:["Replace with another non-grounding type; replace with a GFCI receptacle marked 'No Equipment Ground'; or install grounding-type if a grounding path is provided","Only licensed electricians may work on circuits without EGC","Circuit must be rewired before any outlet replacement","Must replace with grounding-type outlet — no exceptions"],ans:0,ref:"NEC 406.4(D)(2)",exp:"Three options for replacing non-grounding outlet: (1) Another non-grounding outlet, (2) GFCI outlet marked 'No Equipment Ground,' (3) Grounding-type outlet if a grounding path is provided. Option 2 (GFCI) is most practical in old homes."},
{id:230,mod:6,cat:"Equipment General Use",diff:"Medium",q:"What type of outlet is required for a new clothes dryer installation?",opts:["3-wire, 30A, 240V outlet (NEMA 10-30)","4-wire, 30A, 240V outlet (NEMA 14-30)","50A, 240V outlet (NEMA 6-50)","2-wire plus ground, 240V receptacle"],ans:1,ref:"NEC 250.140 & 406.9",exp:"New installations require 4-wire (hot, hot, neutral, ground) 30-ampere, 240V NEMA 14-30 outlet for clothes dryers. The separate grounding wire (4th wire) was required for new installations after 1996. Existing 3-wire installations may remain."},
{id:231,mod:6,cat:"Equipment General Use",diff:"Medium",q:"What information must a panelboard circuit directory show for every circuit?",opts:["Circuit numbers and ampere ratings only","Only circuit numbers","Circuit numbers and installation date","The purpose or load description for each circuit, clearly identified"],ans:3,ref:"NEC 408.4(A)",exp:"Every circuit must be identified on the circuit directory inside the panel door with the purpose or load for each circuit. Vague labels like 'circuit 1' or 'bedroom' are insufficient — specific identification required."},
{id:232,mod:6,cat:"Equipment General Use",diff:"Medium",q:"Why must snap switches (standard wall switches) have snap action?",opts:["Ensures the switch can be operated with one hand","Must be spring-loaded to prevent accidental operation","Make positive, fast-acting contact to prevent arcing at the contacts","Must be self-locking in both on and off positions"],ans:2,ref:"NEC 404.13",exp:"Snap switches must make contact quickly with positive snap action. Slow-making switches allow arc formation at contacts during switching, which erodes contacts and can cause fires. Positive snap-action minimizes arcing duration."},
{id:233,mod:6,cat:"Equipment General Use",diff:"Easy",q:"What type of outlet box is required for a ceiling fan?",opts:["Marked with its maximum fan weight rating","Labeled 'Fan Only' to prevent light fixture installation","Stamped with the fan manufacturer's name","Not required — the listing of the box provides the information"],ans:0,ref:"NEC 314.27(C)",exp:"Outlet boxes listed for fan support must be marked with their maximum fan weight rating. This allows installers and inspectors to verify the installed fan doesn't exceed the box's rated capacity."},
{id:234,mod:6,cat:"Equipment General Use",diff:"Medium",q:"What listing must luminaires in wet locations have?",opts:["Only UL-listed fixtures permitted in wet locations","Suitable for wet locations","Wet-location fixtures required only within 3 feet of water source","Damp locations only"],ans:1,ref:"NEC 410.10(A)",exp:"Luminaires in wet locations must be listed and marked as suitable for wet locations. Wet locations include: exposed to weather, embedded in masonry, exposed to water spray. 'Damp location' ratings insufficient for wet locations."},
{id:235,mod:6,cat:"Equipment General Use",diff:"Hard",q:"A 120V, 20A GFCI circuit supplies a bathroom with a 1,800-watt load. Is this compliant?",opts:["No — bathroom circuits limited to 1,500 watts","No — bathroom circuits may not exceed 1,440 watts","Yes — as long as load is not continuous","Yes — 1,800W ÷ 120V = 15A, within 80% (1,920 VA) continuous limit"],ans:3,ref:"NEC 210.20(A) & 210.11(C)(3)",exp:"1,800W ÷ 120V = 15A. On a 20A circuit, continuous limit = 16A (80% × 20A). If load is non-continuous, can use full 20A. If continuous (3+ hours), 15A < 16A continuous limit = compliant. 80% rule only restricts CONTINUOUS loads."},
{id:236,mod:6,cat:"Equipment General Use",diff:"Hard",q:"What is the temperature rating of Type THHN cable?",opts:["75°C dry; 60°C wet","90°C in both wet and dry locations","90°C in dry locations only","75°C in both wet and dry locations"],ans:2,ref:"NEC Table 310.4",exp:"THHN = 90°C in dry locations ONLY. For wet locations, THWN (75°C wet, 90°C dry) or THWN-2 (90°C wet and dry) must be used. Many conduit installations use THWN or dual-rated THHN/THWN-2 conductors to cover all installation environments."},
{id:237,mod:6,cat:"Equipment General Use",diff:"Medium",q:"Is a 1,500W continuous-load heating unit at 120V on a 15A circuit code compliant?",opts:["Not for continuous loads — 15A × 80% = 12A max continuous; 12.5A exceeds this","Yes — heating loads are not classified as continuous","Yes, because 1,500W heaters are exempt from continuous load rules","Yes — 1,500W ÷ 120V = 12.5A, within circuit rating"],ans:0,ref:"NEC 210.20(A)",exp:"1,500W ÷ 120V = 12.5A. Continuous load limit on 15A circuit = 15A × 80% = 12A. 12.5A > 12A = NOT compliant on a 15A circuit. A 20A circuit (80% = 16A) properly handles the 12.5A continuous heating load."},
{id:238,mod:6,cat:"Equipment General Use",diff:"Medium",q:"What are the requirements for a cord-and-plug connected electric water heater?",opts:["Only tankless heaters may be cord-and-plug","May be cord-and-plug connected if listed for this purpose","240V water heaters may use a 30A dryer cord","Residential water heaters must be permanently hardwired — cord-and-plug prohibited"],ans:1,ref:"NEC 422.16(B)",exp:"Some small point-of-use water heaters are listed for cord-and-plug connection. Standard tank-type water heaters must be permanently connected. The listing determines what's permitted. Always follow equipment listing and manufacturer's installation instructions."},
{id:239,mod:6,cat:"Equipment General Use",diff:"Easy",q:"What is the minimum illumination level required for electrical equipment working spaces per the NEC?",opts:["50 foot-candles","25 foot-candles at the equipment face","The NEC requires lighting be provided but does not specify foot-candle levels","Illumination is optional — good practice but not required"],ans:2,ref:"NEC 110.26(D)",exp:"NEC requires illumination for working spaces about electrical equipment including service equipment, switchboards, panelboards, and MCCs. The NEC requires the lighting but doesn't specify foot-candle levels."},
{id:240,mod:6,cat:"Equipment General Use",diff:"Hard",q:"When a motor controller is to also serve as the disconnecting means, it must:",opts:["Be listed and rated for the purpose — not all controllers qualify as disconnects","A contactor-type controller always qualifies","Only manually operated controllers qualify","All motor controllers serve as disconnecting means"],ans:0,ref:"NEC 430.111",exp:"Not all motor controllers qualify as disconnecting means. A controller used as a disconnect must be listed and rated for the purpose, including being rated for horsepower and capable of opening under motor running current. Many contactors are NOT rated for use as disconnects."},
// MODULE 7: SPECIAL OCCUPANCIES (30)
{id:241,mod:7,cat:"Special Occupancies",diff:"Easy",q:"What do Class I, Division 1 hazardous locations contain?",opts:["Easily ignitable fibers","Flammable gases or vapors present continuously or intermittently under normal operating conditions","Combustible dust that can cause fires","Flammable gases present only under abnormal conditions"],ans:1,ref:"NEC 500.5(B)(1)",exp:"Class I, Division 1 = flammable gases/vapors NORMALLY present. Division 2 = only present under abnormal conditions. Class I equipment must be explosion-proof for the specific gas group."},
{id:242,mod:7,cat:"Special Occupancies",diff:"Easy",q:"What type of hazardous material is involved in Class II hazardous locations?",opts:["Easily ignitable fibers","Flammable gases","Combustible dust","Flammable liquids only"],ans:2,ref:"NEC 500.5(C)",exp:"Class II = combustible dust hazards. Examples: grain elevators, flour mills, coal handling, certain manufacturing. Dust clouds can explode with extreme violence."},
{id:243,mod:7,cat:"Special Occupancies",diff:"Medium",q:"What must equipment installed in Class I, Division 1 locations be?",opts:["Simply weatherproof","GFCI protected","Any listed equipment is acceptable","Explosion-proof and rated for the specific gas group and temperature class"],ans:3,ref:"NEC 501.5",exp:"Class I, Division 1 equipment must be explosion-proof AND rated for: (1) the specific hazardous gas group (A through D), and (2) the temperature class (T1 through T6). Wrong group or temperature class = fire hazard."},
{id:244,mod:7,cat:"Special Occupancies",diff:"Hard",q:"Which gas requires the most restrictive equipment rating in Class I hazardous locations?",opts:["Acetylene (Group A)","Propane (Group D)","Natural gas (Group D)","Hydrogen (Group B)"],ans:0,ref:"NEC Table 500.8(C)(1)",exp:"Group A (acetylene) requires the most restrictive equipment — acetylene is extremely explosive. Group B = hydrogen, manufactured gas. Group C = ethylene, cyclopropane. Group D = propane, gasoline, natural gas. Group A equipment will be rated for any Group."},
{id:245,mod:7,cat:"Special Occupancies",diff:"Medium",q:"Where are conduit seals required in Class I hazardous locations?",opts:["Seals required only in Division 1 — not Division 2","Within 18 inches of each enclosure and at boundaries between classified and unclassified areas","Only at conduit entry to motors","Only for conduit runs over 100 feet"],ans:1,ref:"NEC 501.15",exp:"Conduit seals: within 18 inches of each enclosure entry AND at every boundary between classified and unclassified areas. Prevents flammable vapors from traveling through conduit to non-classified areas where they could ignite."},
{id:246,mod:7,cat:"Special Occupancies",diff:"Medium",q:"How are commercial garages used for vehicle service classified under the NEC?",opts:["Class II due to tire dust","Class I, Division 1 throughout","Class I, Division 2 within 18 inches of the floor and up to 18 inches from doors/vents","Unclassified — ventilation prevents hazardous atmosphere"],ans:2,ref:"NEC 511.3",exp:"Commercial garages: Class I, Division 2 within 18 inches of the floor (gasoline vapors settle at low levels), and within 18 inches of dispenser openings. Above 18 inches from floor is unclassified with adequate ventilation."},
{id:247,mod:7,cat:"Special Occupancies",diff:"Hard",q:"In the Article 505 Zone Classification System, what does Zone 0 approximately correspond to in the Division system?",opts:["Division 1 with continuous hazard presence","Division 2","Division 1","Division 1 where hazardous atmosphere is continuously present"],ans:3,ref:"NEC 505.5(A)",exp:"Zone 0 = flammable atmosphere continuously present (more restrictive than Division 1). Zone 1 ≈ Division 1. Zone 2 ≈ Division 2. Zone system is international standard (IEC); Division system is North American standard."},
{id:248,mod:7,cat:"Special Occupancies",diff:"Medium",q:"What is the hazardous zone classification within 20 feet of a gasoline dispenser at a dispensing station?",opts:["Class I, Division 2 within 20 feet horizontal radius of dispenser and to 18 inches above grade","Unclassified with ventilation","Class I, Division 1 at all dispensers","No hazardous classification for outdoor dispensers"],ans:0,ref:"NEC 514.3 & Table 514.3(B)(1)",exp:"Gas stations: Class I, Division 2 within 20 feet horizontal radius of each dispenser and within 18 inches above grade. Above 18 inches and beyond 20 feet horizontal = unclassified. Dispensers themselves and areas immediately around them are more restrictive."},
{id:249,mod:7,cat:"Special Occupancies",diff:"Hard",q:"What special wiring is required in healthcare patient care areas under Article 517?",opts:["GFCI protection for all circuits in patient care areas","Isolated power systems or GFCI protection plus equipotential bonding for invasive procedure rooms","Only Class 2 low-voltage circuits permitted near patients","Standard commercial wiring is acceptable in all patient care areas"],ans:1,ref:"NEC 517.160 & 517.20",exp:"Healthcare critical care areas with invasive procedures require isolated power systems OR GFCI plus equipotential bonding. Isolated power prevents ground faults from interrupting life support. Equipotential bonding minimizes voltage between exposed conductive surfaces."},
{id:250,mod:7,cat:"Special Occupancies",diff:"Easy",q:"What does Article 590 require for temporary construction wiring?",opts:["Permanent wiring methods","Temporary wiring must be removed within 90 days","GFCI protection for all receptacles — no time limit on temporary wiring during construction","Only conduit is acceptable for construction sites"],ans:2,ref:"NEC 590.6(A)",exp:"Construction sites: GFCI protection required for all 125V, 15 and 20A receptacle outlets. Cable assemblies may be used without boxes for temporary wiring. No 90-day limit during construction — temporary wiring stays for the project duration."},
{id:251,mod:7,cat:"Special Occupancies",diff:"Easy",q:"What time limit applies to holiday lighting and decorative displays under Article 590?",opts:["No limit for lighting on the exterior only","No time limit — decorative lighting is not covered by Article 590","Limited only by the duration of the permit","90 days — temporary wiring must be removed after 90 days for non-construction purposes"],ans:3,ref:"NEC 590.3(B)",exp:"Non-construction temporary wiring (including holiday lighting): maximum 90 days. Construction temporary wiring has no time limit. After 90 days, holiday lighting must either be removed or converted to permanent wiring methods."},
{id:252,mod:7,cat:"Special Occupancies",diff:"Hard",q:"What level of protection is required for Class II, Group E conductive metal dust?",opts:["Explosion-proof equipment (same as Class I equipment) because metal dust is electrically conductive","Standard dust-tight enclosures","Metal dust areas are unclassified if below the explosion concentration","Class II, Division 2 equipment only"],ans:0,ref:"NEC 502.5 & Table 500.6(B)(1)",exp:"Group E = conductive metal dusts (magnesium, aluminum, etc.). These require the most stringent Class II protection — explosion-proof equipment. Conductive dust can penetrate enclosures and create electrical faults in addition to explosion hazard."},
{id:253,mod:7,cat:"Special Occupancies",diff:"Medium",q:"How are intrinsically safe wiring systems grounded?",opts:["Standard NEC grounding rules","A specific control drawing from the equipment manufacturer that may require special grounding arrangements","Intrinsically safe systems don't require grounding","Earth grounding only — no connection to building ground"],ans:1,ref:"NEC 504.60",exp:"Intrinsically safe systems must be installed per the manufacturer's control drawing, which specifies the exact grounding requirements. Standard grounding methods may not apply — the control drawing governs the entire installation."},
{id:254,mod:7,cat:"Special Occupancies",diff:"Easy",q:"Which NEC article covers healthcare facilities?",opts:["Article 500","Article 700","Article 517","Article 505"],ans:2,ref:"NEC Article 517",exp:"Article 517 = healthcare facilities: hospitals, nursing homes, limited care facilities, clinics. Covers essential electrical systems, patient care areas, wet procedure locations, and life safety circuits."},
{id:255,mod:7,cat:"Special Occupancies",diff:"Medium",q:"Why does the NEC require GFCI protection for marina receptacles under Article 553?",opts:["Marina circuits supply 30A and 50A loads","Marine environments are wet locations","Marina electrical systems are outdoors","Electric shock drowning hazard — stray current in water can paralyze swimmers"],ans:3,ref:"NEC 553.10",exp:"Electric shock drowning (ESD) is a specific hazard in marinas — AC current leaking into water can paralyze swimmers within 30 feet. GFCI protection for all 125V 15 and 20A receptacles in marinas is a life-safety requirement."},
{id:256,mod:7,cat:"Special Occupancies",diff:"Hard",q:"Why does Article 547 require special wiring for agricultural buildings?",opts:["Moisture, dust, and corrosive gases from animal waste damage standard equipment","High voltage equipment is used","Only commercial-grade equipment is permitted","Agricultural buildings always have hazardous gas classifications"],ans:0,ref:"NEC 547.5",exp:"Agricultural buildings present moisture, dust/debris, and corrosive gases from animal waste that damage standard electrical equipment rapidly. Article 547 requires moisture-resistant, dust-tight enclosures and corrosion-resistant wiring methods."},
{id:257,mod:7,cat:"Special Occupancies",diff:"Medium",q:"What must electrical equipment inside a spray paint booth be?",opts:["No special equipment required if spraying is intermittent","Explosion-proof or otherwise approved for Class I, Division 1 locations","Standard commercial equipment with ventilation","Only GFCI protection required"],ans:1,ref:"NEC 516.10(A)",exp:"Spray paint booths = Class I, Division 1 (flammable solvents normally present). All electrical equipment inside the booth must be explosion-proof rated for the specific solvent group. Ventilation reduces but doesn't eliminate the hazard classification."},
{id:258,mod:7,cat:"Special Occupancies",diff:"Medium",q:"What is the minimum electrical service required at each site in an RV park under Article 551?",opts:["50A, 125/250V only","15A, 120V outlet is sufficient","At least one 20A, 125V receptacle and one 30A or 50A, 125/250V receptacle","20A, 120V and 30A outlets per site minimum"],ans:2,ref:"NEC 551.71(A) & (B)",exp:"RV parks: each site needs minimum one 20A, 125V receptacle. Sites designed for larger RVs also need 30A or 50A receptacles. GFCI protection required for outdoor receptacles."},
{id:259,mod:7,cat:"Special Occupancies",diff:"Medium",q:"What must stage portable cable for theatres meet under Article 520?",opts:["Standard NM cable is acceptable","Must be in rigid metal conduit","No special requirements — standard branch circuit rules apply","Be specifically listed for stage use — flexible, voltage rated, with construction for dragging and repeated flexing"],ans:3,ref:"NEC 520.68",exp:"Stage cables must be specifically listed for stage use: flexible, rated for voltage and current, and constructed for dragging on floors and repeated flexing. Standard cables fail quickly under stage use conditions."},
{id:260,mod:7,cat:"Special Occupancies",diff:"Easy",q:"Which NEC article covers swimming pools, fountains, and similar water features?",opts:["Article 680","Article 700","Article 500","Article 547"],ans:0,ref:"NEC Article 680",exp:"Article 680 = swimming pools, fountains, hot tubs, spas, and similar. Extensive requirements for bonding, GFCI protection, luminaire placement, underwater lighting, and equipment clearances."},
{id:261,mod:7,cat:"Special Occupancies",diff:"Hard",q:"What is the maximum voltage permitted between any two exposed conductive surfaces in a patient care area?",opts:["100 millivolts","20 millivolts","5 millivolts","500 millivolts"],ans:1,ref:"NEC 517.13(B)",exp:"Patient care areas: equipotential bonding must limit voltage between any two accessible conductive surfaces to less than 20 millivolts. Patients connected to medical equipment can experience ventricular fibrillation from micro-shock currents as low as 10 microamperes."},
{id:262,mod:7,cat:"Special Occupancies",diff:"Medium",q:"Within what distance of a pool inside wall must 125V, 15A and 20A receptacles have GFCI protection?",opts:["25 feet","15 feet","20 feet","10 feet"],ans:2,ref:"NEC 680.22(A)(1)",exp:"All 125V, 15A and 20A receptacles within 20 feet of inside pool walls require GFCI protection. At least one receptacle must be between 6 and 20 feet from the pool. No receptacle may be within 6 feet of the pool edge."},
{id:263,mod:7,cat:"Special Occupancies",diff:"Medium",q:"What protection must 125V, 15A and 20A receptacles have at carnivals and fairs under Article 525?",opts:["Both GFCI and AFCI","AFCI protection for all circuits","Standard circuit protection only","GFCI protection for all 125V, 15 and 20A receptacles"],ans:3,ref:"NEC 525.23(A)",exp:"Carnivals, circuses, fairs: GFCI required for all 125V, 15 and 20A receptacles. High foot traffic, outdoor environment, and amusement rides create serious shock hazards."},
{id:264,mod:7,cat:"Special Occupancies",diff:"Hard",q:"How does purged and pressurized equipment in Class I locations differ from explosion-proof equipment?",opts:["Purged/pressurized enclosures maintain positive internal pressure with clean air to keep hazardous atmosphere out, rather than containing an internal explosion","They are the same — interchangeable terms","Pressurized equipment operates at reduced voltage","Purged equipment uses water mist to suppress ignition"],ans:0,ref:"NEC 500.7(E) & NFPA 496",exp:"Purged/pressurized equipment: maintains positive pressure inside enclosure, preventing flammable atmosphere from entering. Explosion-proof: designed to contain any internal ignition. Both are valid for Class I — purging preferred for large enclosures."},
{id:265,mod:7,cat:"Special Occupancies",diff:"Medium",q:"What is the primary advantage of intrinsically safe equipment over explosion-proof equipment?",opts:["Less expensive","Limits electrical energy below ignition levels — inherently safe even with open circuits or sparks","Explosion-proof unavailable for small instruments","Easier to install"],ans:1,ref:"NEC 504.1 & 500.7(F)",exp:"Intrinsically safe systems limit energy in the hazardous area below ignition levels even under worst-case faults. Inherently safer than explosion-proof (which contains, not prevents, ignitions). Preferred for instrumentation and low-power devices."},
{id:266,mod:7,cat:"Special Occupancies",diff:"Easy",q:"A luminaire permanently installed over a pool must have a minimum clearance of _____.",opts:["7.5 feet","5 feet","12 feet","Luminaires may not be installed over pools"],ans:2,ref:"NEC 680.22(B)(1)",exp:"Luminaires over pools must be at least 12 feet above the water surface. Prevents contact by pool users, diving boards, or poles used in the pool."},
{id:267,mod:7,cat:"Special Occupancies",diff:"Hard",q:"What must pool bonding include under Article 680.26?",opts:["Only required when electrically operated equipment is installed","Only the pump motor","Only underwater luminaires and their conduit","Pool water, forming shell, all metal fittings, metal within 5 feet of pool, and equipment"],ans:3,ref:"NEC 680.26",exp:"Pool bonding: pool water, metal forming shell, all metal fittings within or attached to pool, metal parts of pool equipment within 5 feet, metal conduit, and pump motor. All must be bonded together to prevent voltage gradients in or near water."},
{id:268,mod:7,cat:"Special Occupancies",diff:"Medium",q:"Underwater pool luminaires must be installed at a minimum depth of _____.",opts:["18 inches below normal water level","No minimum — any depth acceptable","6 inches below water","24 inches below water"],ans:0,ref:"NEC 680.23(B)(1)",exp:"Underwater pool luminaire tops must be at least 18 inches below normal water level. Protects from swimmers' feet, equipment, and reduces electrical hazard if lens breaks."},
{id:269,mod:7,cat:"Special Occupancies",diff:"Medium",q:"In a hospital, the essential electrical system must restore power within how many seconds?",opts:["60 seconds","10 seconds","30 seconds","5 seconds"],ans:1,ref:"NEC 517.31(B)",exp:"Healthcare facilities: life safety and critical branch of the essential electrical system must restore power within 10 seconds of normal power failure. Life-supporting equipment, OR lighting, and exit lighting cannot wait longer."},
{id:270,mod:7,cat:"Special Occupancies",diff:"Hard",q:"How is the area adjacent to an open-top battery charging room classified?",opts:["Class I, Division 2 — hydrogen gas from charging can accumulate","Class III — battery separator fibers are ignitable","Unclassified — not enough gas to classify","Class II, Division 1 — battery acid is combustible"],ans:0,ref:"NEC 480.9(A)",exp:"Large lead-acid battery rooms = Class I, Division 2 (hydrogen gas, Group B — most dangerous gas). Proper ventilation reduces but doesn't eliminate classification. Battery room electrical equipment must meet Class I, Division 2, Group B requirements."},
// MODULE 8: MOTORS & TRANSFORMERS (40)
{id:271,mod:8,cat:"Motors & Transformers",diff:"Easy",q:"Motor branch circuit conductors must be rated at a minimum of _____ of the motor's FLA.",opts:["125%","100%","150%","115%"],ans:0,ref:"NEC 430.22(A)",exp:"Motor branch circuit conductors = minimum 125% of FLA. Accounts for continuous duty operation. Example: 40A FLA × 1.25 = 50A minimum conductor ampacity."},
{id:272,mod:8,cat:"Motors & Transformers",diff:"Medium",q:"What is the maximum inverse time breaker rating for a squirrel cage motor branch circuit?",opts:["400% of FLA","125% of FLA","250% of FLA","175% of FLA"],ans:2,ref:"NEC Table 430.52",exp:"Inverse time breakers: maximum 250% of motor FLA for branch circuit short-circuit and ground-fault protection. Large size allows motor to start (high inrush) without tripping. Separate from overload protection (115-125% FLA)."},
{id:273,mod:8,cat:"Motors & Transformers",diff:"Medium",q:"At what percentage of motor FLA must motor overload protection trip?",opts:["100% of FLA","125% of FLA","115% of FLA","150% of FLA"],ans:1,ref:"NEC 430.32(A)(1)",exp:"Overload protection: trip at no more than 125% of FLA (115% for motors with SF < 1.15 or temperature rise > 40°C). Separate from branch circuit overcurrent protection."},
{id:274,mod:8,cat:"Motors & Transformers",diff:"Medium",q:"If the motor disconnect cannot be within sight of the motor, what additional requirement applies?",opts:["A second disconnect at the motor","Motor cannot be installed in that location","A warning sign at the motor","The disconnect must be lockable in the open position"],ans:3,ref:"NEC 430.102(B) Exception",exp:"Motor disconnect not in sight of motor → must be capable of being locked in the open position. Workers lock disconnect remotely and are assured motor cannot start during maintenance."},
{id:275,mod:8,cat:"Motors & Transformers",diff:"Hard",q:"A motor feeder serves three motors: A=20A FLA, B=15A FLA, C=10A FLA. What is the minimum feeder ampacity?",opts:["50A (largest × 125% + others)","45A (sum of all FLA)","60A","56.25A"],ans:0,ref:"NEC 430.24",exp:"Largest motor × 125% + sum of others: 20 × 1.25 = 25A + 15A + 10A = 50A minimum feeder ampacity. Classic motor feeder calculation."},
{id:276,mod:8,cat:"Motors & Transformers",diff:"Easy",q:"What is the function of a motor controller?",opts:["Provide ground fault protection","Provide overcurrent protection","Start/stop the motor and vary speed or torque","Serve as the disconnecting means"],ans:2,ref:"NEC Article 100 (Controller)",exp:"Motor controller starts/stops motor and may vary speed, torque, or direction. Separate from disconnects (de-energize) and overcurrent devices (protect conductors)."},
{id:277,mod:8,cat:"Motors & Transformers",diff:"Medium",q:"What is the minimum copper THWN conductor size for a 5 HP, 230V single-phase motor with 28A FLA?",opts:["12 AWG (20A ampacity)","8 AWG (40A ampacity)","Nameplate determines sizing","10 AWG (30A — insufficient for 35A)"],ans:1,ref:"NEC 430.22(A) & Table 310.16",exp:"28A × 1.25 = 35A minimum. 10 AWG THWN = 30A (insufficient). 8 AWG THWN = 40A (meets requirement). 8 AWG is minimum."},
{id:278,mod:8,cat:"Motors & Transformers",diff:"Hard",q:"What is the maximum dual-element time-delay fuse rating for a squirrel cage motor branch circuit?",opts:["225% of FLA","125% of FLA","150% of FLA","175% of FLA"],ans:3,ref:"NEC Table 430.52",exp:"Dual-element time-delay fuses: maximum 175% of motor FLA for squirrel cage motors. Less than 250% permitted for inverse time breakers because dual-element fuses have built-in time delay to accommodate starting."},
{id:279,mod:8,cat:"Motors & Transformers",diff:"Medium",q:"What does a motor service factor (SF) of 1.15 mean?",opts:["Motor can operate continuously at 115% of rated horsepower","Ratio of starting current to running current","Motor efficiency at full load","Motor's power factor under full load"],ans:0,ref:"NEC 430.32(A)(1)",exp:"SF = 1.15 → motor can operate at 115% of rated HP continuously. SF ≥ 1.15 = overload protection can be set at 125% FLA. SF < 1.15 = 115% max overload protection."},
{id:280,mod:8,cat:"Motors & Transformers",diff:"Medium",q:"Where must the motor disconnecting means be located?",opts:["Within 6 feet of motor","At the panelboard serving the circuit","Within sight of motor — visible and not more than 50 feet away","At the motor starter only"],ans:2,ref:"NEC 430.102(B)",exp:"Motor disconnect must be in sight = visible AND ≤50 feet from motor. Both conditions required. Service personnel must visually confirm disconnect is open before working on motor."},
{id:281,mod:8,cat:"Motors & Transformers",diff:"Hard",q:"What special consideration applies to variable frequency drive (VFD) output conductors?",opts:["VFD output conductors must be shielded cable","VFD output carries non-sinusoidal current with harmonics — may need derating","Size at 125% of motor FLA same as standard motor conductors","VFDs eliminate separate overload protection need"],ans:1,ref:"NEC 430.22(A) & manufacturer req.",exp:"VFD output conductors carry non-sinusoidal waveforms with harmonic content, creating additional heating. May need derating. Shielded cable often recommended to prevent EMI. Follow VFD manufacturer instructions for conductor type and length."},
{id:282,mod:8,cat:"Motors & Transformers",diff:"Medium",q:"What is the purpose of a motor starter's thermal overload relay?",opts:["Provide ground fault protection","Protect branch circuit conductors","Limit starting current","Protect motor windings from overheating from sustained overload or locked rotor"],ans:3,ref:"NEC 430.32",exp:"Thermal overload relay protects motor windings from overheating. Senses current proportional to heat in windings and trips if current exceeds nameplate for sustained period. Mimics thermal behavior of motor windings."},
{id:283,mod:8,cat:"Motors & Transformers",diff:"Hard",q:"Under what condition may branch circuit OCPD serve as motor overload protection?",opts:["Motor ≤ 1/8 HP, manually started, continuously supervised","When OCPD rated ≤ 125% of FLA","Never — must always be separate","Portable motors only"],ans:0,ref:"NEC 430.32(B)(1)",exp:"Separate overload protection may be omitted for motors ≤ 1/8 HP that are manually started and continuously supervised. Most motors require separate overload protection. Motors marked 'thermally protected' also qualify."},
{id:284,mod:8,cat:"Motors & Transformers",diff:"Medium",q:"What is the rated secondary current for a 45 kVA transformer with a 480V primary and 120/240V secondary?",opts:["93.75A","Equals primary current","187.5A","375A"],ans:2,ref:"NEC 450.3 (sizing basis)",exp:"Secondary current = kVA × 1,000 / secondary voltage = 45,000 / 240 = 187.5A at 240V."},
{id:285,mod:8,cat:"Motors & Transformers",diff:"Medium",q:"What overcurrent protection is required for a 480V primary, 45 kVA dry-type transformer?",opts:["No overcurrent protection required for transformers under 50 kVA","No more than 125% of primary FLA","No more than 250% of primary FLA","100% of primary FLA"],ans:1,ref:"NEC 450.3(B)",exp:"Primary FLA = 45,000 / 480 = 93.75A × 1.25 = 117A maximum primary protection. Primary overcurrent protection for transformers under 600V: maximum 125% of primary FLA."},
{id:286,mod:8,cat:"Motors & Transformers",diff:"Hard",q:"What enclosure is required for a dry-type transformer rated over 112.5 kVA installed indoors?",opts:["Dedicated electrical room with working space","Outdoor location only","Transformer room with fire-rated walls","Fire-resistant transformer room or vault"],ans:3,ref:"NEC 450.21(B)",exp:"Dry-type transformers > 112.5 kVA must be in a transformer room or vault of fire-resistant construction when installed indoors. Smaller dry-type (≤112.5 kVA) with Class 155+ insulation may be in open areas."},
{id:287,mod:8,cat:"Motors & Transformers",diff:"Medium",q:"For conductor sizing, do you use NEC Table FLA values or nameplate FLA values for motors?",opts:["Use NEC Table 430.248/250 FLA for conductor sizing; nameplate FLA for overload protection","Either — they should be close","Nameplate only when lower than table value","Always use nameplate FLA for conductor sizing"],ans:0,ref:"NEC 430.6(A)(1) & 430.22",exp:"NEC Tables 430.248/250 used for conductor and overcurrent device sizing. Nameplate FLA used for overload protection sizing. Critical distinction — using wrong value results in under-protected conductors or nuisance overload tripping."},
{id:288,mod:8,cat:"Motors & Transformers",diff:"Easy",q:"What is the purpose of the motor disconnecting means?",opts:["Provide overcurrent protection","Control motor speed","De-energize motor circuit for maintenance","Start/stop motor during normal operation"],ans:2,ref:"NEC 430.102",exp:"Motor disconnect = safety device to de-energize circuit for maintenance and repair. NOT for starting/stopping (controller) and NOT for fault protection (OCPD)."},
{id:289,mod:8,cat:"Motors & Transformers",diff:"Hard",q:"The secondary FLA of a 75 kVA, 120/208V three-phase transformer is _____.",opts:["180A","208.2A","300A","360A"],ans:1,ref:"NEC 450.3 (sizing basis)",exp:"Secondary FLA = 75,000 / (208 × 1.732) = 75,000 / 360.3 = 208.2A. Conductor minimum = 208.2 × 1.25 = 260.3A minimum ampacity."},
{id:290,mod:8,cat:"Motors & Transformers",diff:"Medium",q:"What is the maximum inverse time breaker for a 10 HP, 3-phase 208V motor with 30.8A FLA?",opts:["80A breaker (250% of FLA — rounds to 80A)","40A breaker (125% of FLA)","50A breaker","70A breaker (next size ≤ 250% of FLA)"],ans:3,ref:"NEC Table 430.52 & 430.52(C)(1) Exception",exp:"30.8 × 250% = 77A. Standard size ≤ 77A = 70A. If 70A causes nuisance tripping, may increase to 80A. 70A is the code answer unless starting issues documented."},
{id:291,mod:8,cat:"Motors & Transformers",diff:"Medium",q:"What clearance is required around dry-type transformers?",opts:["Clearance per installation instructions and Article 110 working space rules","12 inches on all sides","No clearance required if in enclosure","6 feet in front for working space"],ans:0,ref:"NEC 450.13 & 110.26",exp:"Transformer clearance: per installation instructions AND NEC Article 110 working space requirements. Both govern. Must provide adequate ventilation and access for inspection."},
{id:292,mod:8,cat:"Motors & Transformers",diff:"Hard",q:"What is the maximum dual-element fuse rating for a wound-rotor AC motor?",opts:["125% of FLA","250% of FLA","150% of FLA","175% of FLA"],ans:2,ref:"NEC Table 430.52",exp:"Wound-rotor AC motors: maximum dual-element fuse = 150% FLA — less than 175% for squirrel cage motors. Different starting characteristics require different protection headroom."},
{id:293,mod:8,cat:"Motors & Transformers",diff:"Easy",q:"For what purpose are NEC Table 430.250 FLA values used?",opts:["Motor nameplate verification","Branch circuit conductors and overcurrent protection devices","Overload protection only","Only when nameplate is missing"],ans:1,ref:"NEC 430.6(A)(1) & 430.22/430.52",exp:"Table 430.250 used for: (1) branch circuit conductors (FLA × 125%) and (2) branch circuit OCPDs (FLA × 250% for inverse time breakers). Nameplate FLA used for overload protection."},
{id:294,mod:8,cat:"Motors & Transformers",diff:"Medium",q:"When two or more motors share a single branch circuit, required conditions?",opts:["Only motors under 1 HP may share","Combined FLA cannot exceed 20A","Shared motor circuits never permitted","Each motor must have individual overload protection and circuit rated for total load"],ans:3,ref:"NEC 430.53",exp:"Multiple motors on shared circuit: each motor needs individual overload protection, and circuit rated for the combination. Circuit protected at no more than values permitted for the smallest motor on circuit."},
{id:295,mod:8,cat:"Motors & Transformers",diff:"Hard",q:"What does transformer impedance %Z = 5% mean?",opts:["At 5% of rated voltage, full rated current flows (short-circuit condition)","5% of turns are for tap adjustment","At full load, voltage drops 5% from no-load to full-load","5% of input power lost as heat"],ans:0,ref:"NEC 450.3 & IEEE C57",exp:"%Z = percentage of rated primary voltage needed to drive full short-circuit current. 5% Z = only 5% of normal voltage drives full-rated fault current. Lower %Z = higher fault current. Critical for short-circuit analysis and breaker interrupting capacity selection."},
{id:296,mod:8,cat:"Motors & Transformers",diff:"Medium",q:"What enclosure type must a motor in a wet or damp location have?",opts:["GFCI protection on branch circuit required for all wet location motors","Open drip-proof (ODP) is acceptable everywhere","Enclosure suitable for the location — drip-proof, splash-proof, TEFC, or weatherproof as appropriate","Only TEFC motors permitted in wet locations"],ans:2,ref:"NEC 430.11",exp:"Motor enclosure type must match environment. ODP for clean, dry indoor only. Splash-proof or TEFC for wet/damp. Explosion-proof for hazardous. Using ODP in wet location allows water ingress causing winding failure and shock hazard."},
{id:297,mod:8,cat:"Motors & Transformers",diff:"Hard",q:"How does reduced voltage affect motor torque and current?",opts:["Increases motor efficiency","Reduces torque (proportional to voltage squared) while motor draws excess current trying to meet torque demand","No effect on performance","Reduces both proportionally"],ans:1,ref:"NEC 430.83 & motor theory",exp:"Motor torque ∝ voltage². 10% voltage reduction → ~19% torque reduction. If load needs full torque, motor draws excessive current = overheating. Voltage quality is critical for motor life."},
{id:298,mod:8,cat:"Motors & Transformers",diff:"Medium",q:"Does a motor marked 'thermally protected' require additional external overload protection?",opts:["Thermal protection must be tested annually","GFCI branch circuit protection required instead","Yes — additional overload required","No — built-in thermal protection satisfies overload protection requirement"],ans:3,ref:"NEC 430.32(A)(2)",exp:"'Thermally protected' motors have integral thermal cutouts that open when windings overheat. Satisfies Article 430 overload protection requirements. Simplifies installation for smaller motors."},
{id:299,mod:8,cat:"Motors & Transformers",diff:"Medium",q:"What are the grounding requirements for a 480V to 120/240V separately derived transformer system?",opts:["GEC must connect secondary to grounding electrode system AND system bonding jumper required","No grounding required — primary grounding adequate","Bonds to primary system ground through steel frame","Secondary neutral connects back to primary service neutral"],ans:0,ref:"NEC 250.30(A)",exp:"Separately derived system: (1) system bonding jumper connecting secondary neutral to secondary EGC, and (2) GEC connecting secondary to grounding electrode system. Equivalent to service grounding requirements."},
{id:300,mod:8,cat:"Motors & Transformers",diff:"Hard",q:"What is the maximum permitted length of conductor between a motor and its overload relay?",opts:["Relay must be at the motor","May be up to 25 feet from motor","Relay may be at controller — no length restriction","Must not exceed 6 feet"],ans:2,ref:"NEC 430.37",exp:"Overload relays are typically in the motor starter, not at the motor. No NEC restriction on conductor length between motor and overload relay — the relay senses current proportional to motor winding heat."},
{id:301,mod:8,cat:"Motors & Transformers",diff:"Medium",q:"To approximately what percentage of full-voltage starting current does wye-delta starting reduce the starting current?",opts:["Starting current unchanged","Approximately 1/3 of across-the-line starting current","Doubles starting current","1/2 of normal starting current"],ans:1,ref:"NEC 430.52 & motor theory",exp:"Wye-delta starting reduces current to approximately 1/3 of across-the-line starting (torque also reduced to 1/3). In wye, each winding receives ~58% of line voltage. Motor must start under reduced load."},
{id:302,mod:8,cat:"Motors & Transformers",diff:"Easy",q:"What does 'stalled rotor current' (locked rotor current) refer to?",opts:["Current at full load","Current during normal starting","Current when first energized","Current when rotor is stationary — approximately 6-10 times FLA"],ans:3,ref:"NEC Table 430.251(A) & (B)",exp:"Locked rotor current = motor's maximum current when energized at full voltage with rotor stationary — typically 6-10 × FLA. Motor controllers must be rated to interrupt this current safely."},
{id:303,mod:8,cat:"Motors & Transformers",diff:"Hard",q:"What does the motor nameplate Code Letter indicate?",opts:["Locked-rotor kVA per horsepower — affects overcurrent protection sizing","Efficiency rating","Motor insulation class","Single-phase or three-phase designation"],ans:0,ref:"NEC 430.7(A)(9) & Table 430.7(B)",exp:"Code Letter (A through V) = locked-rotor kilovolt-amperes per HP. Higher letters = higher starting kVA and inrush current. Used to properly size branch circuit overcurrent protection."},
{id:304,mod:8,cat:"Motors & Transformers",diff:"Medium",q:"What is the turns ratio of a 480V primary, 208V/120V delta-wye transformer?",opts:["480:120","4:1 (480/120)","2.31:1 (480/208)","480:208"],ans:2,ref:"NEC 450.3 (sizing basis)",exp:"Turns ratio = primary / secondary voltage. For 208V secondary: 480/208 = 2.31:1. For 120V secondary: 480/120 = 4:1. Delta-wye transformer ratio based on line voltages."},
{id:305,mod:8,cat:"Motors & Transformers",diff:"Medium",q:"For a controller to also serve as disconnecting means:",opts:["All controllers serve as disconnects","Controller must be listed and rated for the purpose — not all qualify","Only manually operated controllers qualify","Contactor always qualifies"],ans:1,ref:"NEC 430.111",exp:"Not all controllers qualify as disconnects. Controller used as disconnect must be listed and rated for the purpose including HP rating and ability to open under running current. Many contactors are NOT rated as disconnects."},
{id:306,mod:8,cat:"Motors & Transformers",diff:"Hard",q:"What protection is required for transformers installed outdoors on utility poles?",opts:["GFCI on all secondary circuits","Only fall protection for workers","No special protection needed","Weatherproof enclosures and physical damage protection required"],ans:3,ref:"NEC 450.22 & 450.13",exp:"Outdoor transformers must be weatherproof and protected from physical damage. Pad-mounted transformers must have tamper-resistant, lockable enclosures to prevent public access to energized parts."},
{id:307,mod:8,cat:"Motors & Transformers",diff:"Medium",q:"What is the purpose of a reduced voltage motor starter (soft starter)?",opts:["Gradually ramp up voltage during starting to reduce mechanical shock and electrical inrush","Step down voltage from 480V to 240V","Permanently reduce voltage for energy savings","Provide adjustable speed control throughout operation"],ans:0,ref:"NEC 430.52 & 430.83",exp:"Soft starters gradually increase voltage during starting, reducing inrush current and mechanical shock. NOT for speed control during running — once at full speed, full voltage applied. Common for conveyors, pumps, compressors."},
{id:308,mod:8,cat:"Motors & Transformers",diff:"Easy",q:"What is the motor Code Letter (locked rotor kVA designation) used for?",opts:["Determining conductor size","Identifying efficiency class","Selecting overcurrent protection to allow starting without nuisance tripping","Selecting overload relay heater"],ans:2,ref:"NEC 430.52(C)(1) & Table 430.7(B)",exp:"Code Letter affects overcurrent protection selection. Higher Code Letter motors may need larger overcurrent devices to handle starting current without tripping. NEC allows increasing up to specified maximums if nuisance tripping occurs."},
{id:309,mod:8,cat:"Motors & Transformers",diff:"Hard",q:"When one transformer fails in a delta transformer bank, what operating mode is still possible?",opts:["Reduced capacity wye operation","Open-delta (V-connection) at approximately 58% of original capacity","Single-phase operation only","Cannot operate with one failed transformer"],ans:1,ref:"NEC 450.3 & transformer theory",exp:"Open-delta (V-delta): remaining two transformers provide three-phase power at approximately 58% (1/√3) of original capacity. Emergency measure — reduced capacity, unbalanced phase voltages, poor regulation."},
{id:310,mod:8,cat:"Motors & Transformers",diff:"Medium",q:"What additional requirement applies when a motor is not in sight from its controller?",opts:["Separate in-sight disconnect must be at motor","No additional protection required","Motor must have built-in thermal cutout","Controller must be capable of being locked in the open position"],ans:3,ref:"NEC 430.87",exp:"Motor not in sight from controller: controller must be lockable in open (off) position. Prevents remote starting while maintenance personnel work on motor or driven machinery."},
// MODULE 9: COMMUNICATIONS & EMERGENCY (25)
{id:311,mod:9,cat:"Communications & Emergency",diff:"Easy",q:"How quickly must emergency systems restore power per Article 700?",opts:["10 seconds","60 seconds","5 seconds","30 seconds"],ans:0,ref:"NEC 700.12",exp:"Emergency systems must restore power within 10 seconds of normal failure. Applies to emergency lighting, exit signs, fire alarms, and life-safety systems."},
{id:312,mod:9,cat:"Communications & Emergency",diff:"Medium",q:"What is the key difference between emergency systems and legally required standby systems?",opts:["Emergency systems require 10-second transfer; legally required standby has no time requirement","Emergency systems use generators; legally required standby uses UPS","Same — interchangeable terms","Emergency systems = life-safety functions; legally required standby = public safety required by law but less immediately life-critical"],ans:3,ref:"NEC Article 700 vs Article 701",exp:"Emergency systems (Article 700) = life-safety systems. Legally required standby (Article 701) = systems required by law but not immediately life-critical such as refrigeration, communication systems."},
{id:313,mod:9,cat:"Communications & Emergency",diff:"Medium",q:"What is the maximum voltage for a Class 2 circuit under Article 725?",opts:["120V","30V AC or 60V DC","24V DC only","100V"],ans:1,ref:"NEC 725.121(A)(4) & Table 11",exp:"Class 2 circuits: maximum 30V AC or 60V DC with limited power (VA). Common for thermostats, doorbells, security systems, low-voltage lighting control."},
{id:314,mod:9,cat:"Communications & Emergency",diff:"Hard",q:"What is required for Class 2 conductors sharing a raceway with power conductors?",opts:["Always prohibited","6 inches separation","A solid fixed barrier separating Class 2 from power conductors","Power conductors must be rated 600V minimum"],ans:2,ref:"NEC 725.136(A)",exp:"Class 2 circuits sharing a raceway with power circuits require a solid fixed barrier separating them — or they must be in separate raceways. Prevents damage to low-voltage insulation and induction of harmful voltages."},
{id:315,mod:9,cat:"Communications & Emergency",diff:"Medium",q:"What must generators for emergency systems do?",opts:["Supply full emergency load within 10 seconds with sufficient fuel supply and automatic starting","Generators for emergency must be tested monthly only","Only natural gas generators may be used","Any standby generator is acceptable"],ans:0,ref:"NEC 700.12(B)",exp:"Emergency system generators: supply full load within 10 seconds of normal power failure, automatic starting, automatic transfer, minimum 2-hour fuel supply. In California, emissions regulations also apply to standby generators."},
{id:316,mod:9,cat:"Communications & Emergency",diff:"Easy",q:"How are fire alarm circuits classified under Article 760?",opts:["Class 3 circuits","High-impedance circuits","Class 1 — power limited only","Power-limited fire alarm (PLFA) or non-power-limited fire alarm (NPLFA) circuits"],ans:3,ref:"NEC 760.41 & 760.61",exp:"Article 760 fire alarm circuits: PLFA (Power-Limited Fire Alarm) or NPLFA (Non-Power-Limited). Classification determines permissible wiring methods, conduit requirements, and cable mixing rules."},
{id:317,mod:9,cat:"Communications & Emergency",diff:"Medium",q:"Why must a CATV system be grounded at the building entrance?",opts:["Electrical panel neutral bus","The grounding electrode system — typically the GEC or service equipment enclosure","Utility company's ground rod","Grounding not required — surge protectors used instead"],ans:1,ref:"NEC 820.100(B)",exp:"CATV shields and outer conductors must bond to building's grounding electrode system at building entrance. Prevents dangerous voltage differences between communications ground and electrical ground."},
{id:318,mod:9,cat:"Communications & Emergency",diff:"Hard",q:"Why do emergency systems require automatic transfer switches?",opts:["Manual switches acceptable if person is present 24/7","Transfer switches optional if generator manually started","Automatic operation required — 10-second restoration cannot be reliably met with manual switching","Circuit breaker interlock serves as acceptable transfer switch for emergency systems"],ans:2,ref:"NEC 700.5(A)",exp:"Emergency systems require ATSs that operate without manual intervention. The 10-second restoration requirement cannot reliably be met if a person must manually operate a switch."},
{id:319,mod:9,cat:"Communications & Emergency",diff:"Medium",q:"What must telephone system conductors have when entering a building per Article 800?",opts:["A listed protector to guard against lightning surges and power contact","Metallic conduit for physical protection","GFCI protection","Surge-protective device rated for telephone voltage"],ans:0,ref:"NEC 800.90(A)",exp:"Article 800 requires listed protectors (surge arrestors) at the building entrance of communications circuits. Guards against lightning surges and inadvertent contact with power lines."},
{id:320,mod:9,cat:"Communications & Emergency",diff:"Hard",q:"What type of cable must be used for fire alarm cables installed in plenums?",opts:["Standard THWN in conduit always acceptable","Any listed cable acceptable in plenums","NM cable in metal conduit suitable for plenums","Plenum-rated cables (FPLP) with low smoke and flame-spread characteristics"],ans:3,ref:"NEC 760.53(A)(1)",exp:"Fire alarm cables in plenums must be plenum-rated (FPLP type) with limited flame spread and low smoke emission. Non-plenum cable in plenums is a serious safety violation — can spread fire through air handling system."},
{id:321,mod:9,cat:"Communications & Emergency",diff:"Medium",q:"When must exit signs connected to emergency circuits be illuminated?",opts:["Only during power outages","At all times when the building is occupied","Only when emergency power is active","Only during normal business hours"],ans:1,ref:"NEC 700.16",exp:"Exit signs must be illuminated at ALL times the building is occupied. Connected to emergency circuit so they remain on during power outages."},
{id:322,mod:9,cat:"Communications & Emergency",diff:"Hard",q:"Emergency lighting units must provide illumination for a minimum of _____ after normal power fails.",opts:["Until generator starts","30 minutes","90 minutes","60 minutes"],ans:2,ref:"NEC 700.12(F)",exp:"Emergency lighting: minimum 90 minutes after normal power failure. Monthly 30-second tests verify unit starts. Annual 90-minute test verifies battery capacity. Failed batteries must be replaced."},
{id:323,mod:9,cat:"Communications & Emergency",diff:"Medium",q:"How must emergency circuit wiring be separated from normal power wiring?",opts:["Emergency and normal wiring must be in separate raceways, cable trays, or cables except in transfer equipment","Emergency wiring must be in dedicated room","No separation required","Only 12-inch physical separation required"],ans:0,ref:"NEC 700.10(B)(1)",exp:"Emergency wiring must be entirely independent of normal power wiring — separate raceways, cable assemblies, boxes, and cabinets except at transfer equipment. Ensures normal wiring fault can't simultaneously damage emergency system."},
{id:324,mod:9,cat:"Communications & Emergency",diff:"Easy",q:"At what voltage does low-voltage landscape lighting under Article 411 typically operate?",opts:["277V for efficiency","120V through transformer","24V DC","30V or less"],ans:3,ref:"NEC 411.2",exp:"Article 411 = low-voltage lighting systems operating at 30V or less. Typical landscape lighting uses 12V through step-down transformers. Lower voltage = reduced shock hazard and lighter wire gauge."},
{id:325,mod:9,cat:"Communications & Emergency",diff:"Hard",q:"How does an optional standby system (Article 702) differ from a legally required standby system?",opts:["Optional standby has no NEC requirements","Optional standby installed at owner's discretion for comfort/productivity; legally required standby mandated by law for safety","Optional must transfer within 60 seconds; legally required within 30 seconds","The terms mean the same thing"],ans:1,ref:"NEC Article 702 vs Article 701",exp:"Optional standby (Article 702) = voluntary, for comfort or business continuity. Legally required standby (Article 701) = mandated by codes for safety. Different reliability and time requirements."},
{id:326,mod:9,cat:"Communications & Emergency",diff:"Medium",q:"What special requirement must a fire alarm circuit breaker meet?",opts:["Gray to indicate low voltage","Standard breaker color is acceptable","Red in color to identify as life safety circuit","Green to indicate approved circuit"],ans:2,ref:"NEC 760.21",exp:"Fire alarm circuit breakers must be RED in color and identified as 'FIRE ALARM CIRCUIT CONTROL.' Red color provides quick visual identification to prevent inadvertent de-energization during electrical work."},
{id:327,mod:9,cat:"Communications & Emergency",diff:"Hard",q:"What is the key difference between PLFA and NPLFA fire alarm cable?",opts:["PLFA operates at limited power — allows less robust wiring methods; NPLFA has higher power requiring conduit or heavy cables","PLFA indoor only; NPLFA outdoor","They are the same — interchangeable terms","PLFA uses copper; NPLFA uses aluminum"],ans:0,ref:"NEC 760.41 & 760.61",exp:"PLFA (power-limited) = smaller, flexible cables with less restrictive wiring method requirements. NPLFA (non-power-limited) = higher power, requires wiring methods similar to power circuits. Classification determines what methods are permissible."},
{id:328,mod:9,cat:"Communications & Emergency",diff:"Medium",q:"May optical fiber cable and power conductors share the same raceway?",opts:["6-inch minimum separation required","No restrictions — fiber is non-conductive","Always prohibited","May share if optical fiber is listed for the purpose"],ans:3,ref:"NEC 770.133",exp:"Optical fiber cables may be in same raceway as power conductors only when specifically listed for such applications (composite cable types). Standard optical fiber cables cannot share raceways with power conductors."},
{id:329,mod:9,cat:"Communications & Emergency",diff:"Easy",q:"What type of cable is typically used for residential data networks?",opts:["Coaxial cable only","Category 5e or better UTP (unshielded twisted pair)","Fiber optic for all residential","NM cable with data conductors added"],ans:1,ref:"NEC Article 800 & 725",exp:"Residential data networks use Cat 5e, Cat 6, or Cat 6A UTP cable for Ethernet. Falls under Article 800 (communications) or Article 725 (Class 2/3 circuits). Requires separation from power conductors."},
{id:330,mod:9,cat:"Communications & Emergency",diff:"Hard",q:"What is the required annual test duration for emergency lighting units?",opts:["60 minutes","30 minutes","90 minutes — the full rated duration","Duration equals battery rating divided by load"],ans:2,ref:"NEC 700.3(B)",exp:"Emergency lighting must be tested for full rated duration (minimum 90 minutes) annually. Monthly 30-second tests verify unit starts. Annual 90-minute test verifies battery has capacity for required duration."},
{id:331,mod:9,cat:"Communications & Emergency",diff:"Medium",q:"Who must be notified before testing a fire alarm system?",opts:["Fire alarm installer and building owner notify the monitoring company — and occupants should be informed","No notification — system automatically signals test condition","Electrical inspector must be present","Only the monitoring company"],ans:0,ref:"NFPA 72 Chapter 14 & NEC 760",exp:"Before fire alarm testing: notify monitoring company (prevents unnecessary fire department dispatch) and notify building occupants and management (prevents panic). Contractor and building owner share responsibility."},
{id:332,mod:9,cat:"Communications & Emergency",diff:"Hard",q:"What is the maximum voltage for Class 3 remote-control circuits under Article 725?",opts:["300V maximum","60V DC","30V AC","150V maximum"],ans:3,ref:"NEC 725.121(B) & Table 11(A)",exp:"Class 3 circuits: maximum 150V with limited power. Class 3 allows higher voltage than Class 2 (30V AC max) but still limits power to reduce fire and shock hazard. Used for some audio, access control, and intercom systems."},
{id:333,mod:9,cat:"Communications & Emergency",diff:"Medium",q:"For a whole-house residential optional standby generator, what transfer method is acceptable?",opts:["Interlock on main breaker never code-compliant","Listed interlock on main breaker is permitted for optional standby systems when properly installed","Listed ATS always required","Listed load management device or ATS required regardless of size"],ans:1,ref:"NEC 702.5",exp:"For optional standby systems (Article 702), a listed breaker interlock is an accepted transfer method. Prevents simultaneous utility and generator connection. Less expensive than ATS, popular for residential whole-house generators."},
{id:334,mod:9,cat:"Communications & Emergency",diff:"Easy",q:"What does a listed transfer switch prevent?",opts:["Overvoltage from generator","Overloads on the generator","Simultaneous connection of utility and generator — preventing dangerous backfeed into power lines","Generator from exceeding its rated kW"],ans:2,ref:"NEC 700.5(D) & 702.5",exp:"Listed transfer switch specifically designed to prevent both sources from connecting simultaneously. Backfeed into utility lines is extremely dangerous to line workers — listed transfer switch prevents this fatal hazard."},
{id:335,mod:9,cat:"Communications & Emergency",diff:"Hard",q:"How often must emergency systems be tested?",opts:["Monthly tests (minimum 30 minutes) and annual tests (minimum 2 hours under simulated load)","Monthly testing only","Quarterly tests of 30 minutes each","Weekly testing"],ans:0,ref:"NEC 700.3(B)(1) & (B)(2)",exp:"Emergency systems: monthly tests of at least 30 minutes under load + annual tests of at least 2 hours under simulated load. Witnessed by building owner or authorized representative with records kept."},
// MODULE 10: CALCULATIONS (60)
{id:336,mod:10,cat:"Calculations",diff:"Easy",q:"The ampacity of 12 AWG THWN copper in the 60°C column of Table 310.16 is _____.",opts:["15A","20A","30A","25A"],ans:1,ref:"NEC Table 310.16 (60°C column)",exp:"12 AWG copper at 60°C = 20A. At 75°C = 20A. At 90°C = 25A. For 60°C terminations (most residential): 20A. Memorize: 14AWG=15A, 12AWG=20A, 10AWG=30A at 60°C."},
{id:337,mod:10,cat:"Calculations",diff:"Easy",q:"The ampacity of 10 AWG copper THWN in the 75°C column of Table 310.16 is _____.",opts:["45A","30A","40A","35A"],ans:3,ref:"NEC Table 310.16 (75°C column)",exp:"10 AWG copper at 75°C = 35A. At 60°C = 30A. At 90°C = 40A. 75°C column used when equipment is rated 75°C (most commercial panelboards and breakers)."},
{id:338,mod:10,cat:"Calculations",diff:"Medium",q:"A 240V single-phase load that draws 30A continuously requires a minimum circuit ampacity of _____.",opts:["40A","30A","37.5A","50A"],ans:2,ref:"NEC 210.20(A)",exp:"Continuous loads = 125% capacity. 30A × 1.25 = 37.5A minimum circuit ampacity. Conductor must be rated ≥ 37.5A; overcurrent device minimum 37.5A (use next standard size = 40A)."},
{id:339,mod:10,cat:"Calculations",diff:"Medium",q:"A 120V circuit with a 24-ohm resistance (per Ohm's Law) carries _____ of current.",opts:["5A","2.88A","10A","2,880A"],ans:0,ref:"Ohm's Law (I=V/R)",exp:"I = V/R = 120/24 = 5A. Ohm's Law: V=IR, I=V/R, R=V/I. Power at this point: P = IV = 5 × 120 = 600 watts."},
{id:340,mod:10,cat:"Calculations",diff:"Medium",q:"How much power is consumed by a 120V, 15A load?",opts:["125 watts","1,800 watts","8 watts","18,000 watts"],ans:1,ref:"Power formula (P=IV)",exp:"P = IV = 15A × 120V = 1,800W (1.8 kW). Maximum power a 15A, 120V circuit can supply. P=IV used constantly in load calculations."},
{id:341,mod:10,cat:"Calculations",diff:"Hard",q:"A 2,400 sq ft dwelling with general lighting at 3 VA/sq ft, two small appliance circuits, and one laundry circuit has a total load of _____ before demand factors.",opts:["7,200 VA","13,200 VA","10,200 VA","11,700 VA"],ans:3,ref:"NEC 220.12 & 220.52",exp:"Lighting: 2,400 × 3 = 7,200 VA. Small appliance: 2 × 1,500 = 3,000 VA. Laundry: 1,500 VA. Total = 11,700 VA (before demand factors). After Table 220.42: first 3,000 at 100%, remainder at 35%."},
{id:342,mod:10,cat:"Calculations",diff:"Medium",q:"What is the voltage drop for a 120V circuit with 20A, a 100-foot one-way run, and 12 AWG copper (K=12.9)?",opts:["3.58%","2.15%","6.6%","8.72%"],ans:2,ref:"NEC 210.19(A)(1) Informational Note",exp:"VD = 2 × 12.9 × 20 × 100 / 6,530 = 51,600/6,530 = 7.9V. VD% = 7.9/120 × 100 = 6.6%. Exceeds 3% recommended. Use 2× for single-phase round trip. The formula: VD = 2×K×I×D/CM."},
{id:343,mod:10,cat:"Calculations",diff:"Hard",q:"What AWG copper conductor limits voltage drop to 3% for 240V, 30A circuit run 150 feet? (K=12.9)",opts:["6 AWG (26,240 CM)","4 AWG (41,740 CM)","2 AWG (66,360 CM)","8 AWG (16,510 CM)"],ans:0,ref:"NEC 210.19(A)(1) Informational Note",exp:"Max VD = 240 × 3% = 7.2V. Required CM = 2 × 12.9 × 30 × 150 / 7.2 = 116,100/7.2 = 16,125 CM. 6 AWG = 26,240 CM (meets requirement). 8 AWG = 16,510 CM (barely meets but 6 AWG provides safety margin)."},
{id:344,mod:10,cat:"Calculations",diff:"Medium",q:"The line current for a three-phase, 208V, 45 kVA load is _____.",opts:["125A","124.9A","216.3A","72.2A"],ans:1,ref:"Three-phase formula",exp:"Three-phase: I = kVA × 1,000 / (V × 1.732) = 45,000 / (208 × 1.732) = 45,000/360.3 = 124.9A ≈ 125A. Always use 1.732 for three-phase current calculations."},
{id:345,mod:10,cat:"Calculations",diff:"Easy",q:"How many 20A circuits are needed for a 5,000 sq ft office at 3.5 VA/sq ft?",opts:["6 circuits","7 circuits","11 circuits","10 circuits"],ans:3,ref:"NEC Table 220.12 & 210.20(A)",exp:"Total = 5,000 × 3.5 = 17,500 VA. Continuous: each 20A, 120V circuit = 1,920 VA (20A × 120V × 80%). Circuits = 17,500/1,920 = 9.1 → 10 circuits minimum."},
{id:346,mod:10,cat:"Calculations",diff:"Hard",q:"The line current for a 480V 3-phase 4-wire wye system with 120 kW at unity power factor is _____.",opts:["83.3A","250A","144.3A","166.7A"],ans:2,ref:"Three-phase power formula",exp:"At unity PF: kVA = kW = 120,000 VA. I = VA/(V × √3) = 120,000/(480 × 1.732) = 120,000/831.4 = 144.3A."},
{id:347,mod:10,cat:"Calculations",diff:"Medium",q:"What is the conduit fill percentage for three 12 AWG THWN conductors in 1/2-inch EMT?",opts:["Within the 40% fill limit","Cannot determine without conductor length","Exactly 40% fill","Exceeds the 40% fill limit"],ans:0,ref:"NEC Annex C, Table C1",exp:"From Annex C Table C1 (EMT): 1/2-inch EMT accommodates up to 7 conductors of 12 AWG THWN. Three conductors = well within limit. Use Annex C tables directly at the exam — fastest method."},
{id:348,mod:10,cat:"Calculations",diff:"Easy",q:"The power factor of a purely resistive load is _____.",opts:["0","1.0","0.5","0.866"],ans:1,ref:"Power factor theory",exp:"Purely resistive loads (incandescent lights, electric heaters) = power factor 1.0 (unity). All apparent power (VA) is real power (watts) — no reactive component."},
{id:349,mod:10,cat:"Calculations",diff:"Medium",q:"The minimum branch circuit conductor ampacity for a 10 HP, 460V, 3-phase motor with 13.6A FLA is _____.",opts:["15A","20A","13.6A","17A"],ans:3,ref:"NEC 430.22(A)",exp:"Motor conductor = FLA × 125% = 13.6 × 1.25 = 17A minimum. 12 AWG THWN = 20A at 75°C — meets 17A requirement."},
{id:350,mod:10,cat:"Calculations",diff:"Hard",q:"A service has lighting of 6,045 VA, appliance load of 8,500 VA, HVAC of 14,400 VA, and water heater of 4,500 VA. What is the total demand at 240V?",opts:["150A","145A","140A","141A"],ans:2,ref:"NEC 220.87 & 230.79",exp:"Total VA = 6,045 + 8,500 + 14,400 + 4,500 = 33,445 VA. Current = 33,445/240 = 139.4A ≈ 140A. Next standard service = 150A or 200A."},
{id:351,mod:10,cat:"Calculations",diff:"Medium",q:"The circular mil area of a 500 kcmil conductor is _____.",opts:["500,000 CM","50,000 CM","5,000 CM","500 CM"],ans:0,ref:"NEC Chapter 9, Table 9",exp:"kcmil = thousand circular mils. 500 kcmil = 500,000 CM. Critical for voltage drop formula where you divide (2 × K × I × D) by CM value. Getting this wrong by 1,000× gives wildly incorrect results."},
{id:352,mod:10,cat:"Calculations",diff:"Hard",q:"What adjustment factor applies when six current-carrying conductors share a conduit?",opts:["50% of table ampacity","80% of table ampacity","No adjustment for 6 conductors","70% of table ampacity"],ans:1,ref:"NEC 2020 Table 310.15(C)(1)",exp:"Table 310.15(C)(1): 4-6 current-carrying conductors = 80% adjustment. 12 AWG THWN normally 20A → derate to 20 × 0.80 = 16A with six conductors in conduit."},
{id:353,mod:10,cat:"Calculations",diff:"Medium",q:"An electric clothes dryer rated 5.5 kW at 240V requires a minimum circuit ampacity of _____.",opts:["37.5A","28.6A","22.9A","30A"],ans:3,ref:"NEC 220.54 & 210.23(B)",exp:"5,500/240 = 22.9A × 125% (continuous) = 28.6A. But NEC minimum for clothes dryers = 30A. The 30A NEC minimum governs regardless of calculation. Always check NEC minimums."},
{id:354,mod:10,cat:"Calculations",diff:"Hard",q:"A temperature correction factor of 0.82 applied to 10 AWG THWN copper (normal ampacity 35A) gives a derated ampacity of _____.",opts:["30A","35A","28.7A","27.5A"],ans:2,ref:"NEC 2020 Table 310.15(B)(1) & Table 310.16",exp:"Derated = table ampacity × correction factor = 35A × 0.82 = 28.7A. If ALSO more than 3 conductors, apply BOTH factors: multiply together then apply to table ampacity."},
{id:355,mod:10,cat:"Calculations",diff:"Medium",q:"In a 120/240V single-phase three-wire service, what does neutral current equal?",opts:["Difference (unbalanced current) between the two hot legs","Sum of all loads","The larger hot leg current","Zero in balanced 240V system"],ans:0,ref:"NEC 220.61",exp:"Neutral carries UNBALANCED current only — the difference between loads on the two 120V legs. Perfectly balanced 240V system = zero neutral current. Why neutral conductors can sometimes be sized smaller than phase conductors."},
{id:356,mod:10,cat:"Calculations",diff:"Hard",q:"A motor drawing 10A at 480V single-phase and consuming 3,840 watts has a power factor of _____.",opts:["0.85","0.80","0.90","1.0"],ans:1,ref:"Power factor formula",exp:"PF = True Power/Apparent Power = 3,840/(10 × 480) = 3,840/4,800 = 0.80. 80% PF means 20% of apparent power is reactive. Low PF motors draw more current than watts would suggest."},
{id:357,mod:10,cat:"Calculations",diff:"Medium",q:"What is the approximate starting current for a motor with 25A FLA?",opts:["50A — approximately 2× FLA","25A — starting equals running","250A — approximately 10× FLA","125A — approximately 5× FLA"],ans:3,ref:"NEC Table 430.251(A)",exp:"Typical locked rotor current ≈ 6-8× FLA, can range 5-10×. For 25A FLA: starting ≈ 125-175A. This high starting current is why motor overcurrent protection is sized much larger than running current."},
{id:358,mod:10,cat:"Calculations",diff:"Easy",q:"A transformer with a 4:1 turns ratio and a 480V primary produces a secondary voltage of _____.",opts:["240V","1,920V","120V","480V"],ans:2,ref:"Transformer ratio",exp:"Secondary = Primary/turns ratio = 480/4 = 120V. Transformer ratios: voltage ratio = turns ratio. Current ratio = inverse of turns ratio."},
{id:359,mod:10,cat:"Calculations",diff:"Medium",q:"A 3/4-inch conduit has an interior area of 0.533 sq in. What is the maximum fill area for 3 or more conductors?",opts:["0.213 sq in","0.533 sq in","0.320 sq in","0.133 sq in"],ans:0,ref:"NEC Chapter 9, Table 1",exp:"Max fill = 0.533 × 0.40 = 0.213 sq in for 3+ conductors (40% fill). Compare to sum of individual conductor cross-sectional areas from Chapter 9 Table 5."},
{id:360,mod:10,cat:"Calculations",diff:"Hard",q:"An 85 kW continuous lighting load is on a 277/480V three-phase feeder. What is the minimum overcurrent device rating?",opts:["102A","All steps correct leading to 150A","150A","127.5A"],ans:1,ref:"NEC 215.2(A)(1) & 210.20(A) & 240.6(A)",exp:"Step 1: I = 85,000/(480 × 1.732) = 102.2A. Step 2: Continuous × 125% = 127.8A minimum conductor. Step 3: Next standard size = 150A overcurrent device. Step 4: 1/0 AWG copper (150A at 75°C) for conductors. All steps in D are correct."},
{id:361,mod:10,cat:"Calculations",diff:"Medium",q:"The calculated load for one 20A small appliance circuit in a residential calculation is _____.",opts:["2,000 VA","1,200 VA","2,400 VA","1,500 VA"],ans:3,ref:"NEC 220.52(A)",exp:"Each 20A small appliance branch circuit = 1,500 VA (not 2,400 VA which would be full capacity). Specified in Article 220. Two required small appliance circuits = 2 × 1,500 = 3,000 VA."},
{id:362,mod:10,cat:"Calculations",diff:"Hard",q:"Three-phase unbalanced loads: Phase A=18A, Phase B=12A, Phase C=15A. What is the neutral current?",opts:["0A","3A (simple subtraction)","Approximately 5.2A (vector calculation required)","45A (sum of all)"],ans:2,ref:"NEC 220.61 & phasor math",exp:"Unbalanced three-phase neutral current requires VECTOR (phasor) addition — not simple arithmetic. Currents are 120° apart. Approximately 5.2A using phasor math. Never simple arithmetic for three-phase neutral calculation."},
{id:363,mod:10,cat:"Calculations",diff:"Medium",q:"A motor has 80% efficiency and a 10 kW input. What is the output?",opts:["8 kW","12.5 kW","10 kW","2 kW"],ans:0,ref:"NEC 430.22 & motor nameplate",exp:"Output = Input × efficiency = 10 × 0.80 = 8 kW. Remaining 20% (2 kW) lost as heat in windings, friction, and other losses. 1 HP = 746 watts of mechanical output."},
{id:364,mod:10,cat:"Calculations",diff:"Hard",q:"The line current for a 10 HP, 208V, 3-phase motor with 90% efficiency and 0.85 power factor is _____.",opts:["29.0A","27.1A","24.6A","40.5A"],ans:1,ref:"NEC Table 430.250",exp:"Input power = 10 × 746/0.90 = 8,289W. Apparent = 8,289/0.85 = 9,752 VA. Line current = 9,752/(208 × 1.732) = 9,752/360.3 = 27.1A. NEC Table value for 10HP 208V ≈ 30.8A."},
{id:365,mod:10,cat:"Calculations",diff:"Easy",q:"How many watts equal one horsepower (HP)?",opts:["1,000 watts","550 watts","1,340 watts","746 watts"],ans:3,ref:"NEC 430.6 & Table 430.248",exp:"1 HP = 746 watts of mechanical power. Used constantly in motor calculations: 10 HP motor delivers 7,460 watts at 100% efficiency. Electrical input always greater than 746 W/HP due to motor losses."},
{id:366,mod:10,cat:"Calculations",diff:"Medium",q:"The K value for copper conductors used in the voltage drop formula is _____.",opts:["10.4","21.2","12.9","17.0"],ans:2,ref:"NEC 210.19(A)(1) Informational Note",exp:"K = 12.9 for copper. K = 21.2 for aluminum. K represents resistivity constant in VD = 2 × K × I × D / CM. Know both values — the exam often specifies K but you should know copper vs aluminum."},
{id:367,mod:10,cat:"Calculations",diff:"Hard",q:"A 200A, 240V single-phase service has a connected load of 48,000 VA at 80% power factor. What is the true power?",opts:["38,400 watts","96,000 watts","48,000 watts","60,000 watts"],ans:0,ref:"Power factor formula",exp:"True Power = Apparent × PF = 48,000 × 0.80 = 38,400W. System sized on VA (conductors carry apparent power current) but utility bills on watts (kWh)."},
{id:368,mod:10,cat:"Calculations",diff:"Medium",q:"A calculated demand is 22,000 VA at 240V. What is the minimum service size?",opts:["125A","100A (NEC minimum)","92A (calculated)","150A"],ans:1,ref:"NEC 230.79(C)",exp:"22,000/240 = 91.7A calculated. NEC minimum for single-family dwelling = 100A. Since 91.7A < 100A minimum, the 100A minimum governs."},
{id:369,mod:10,cat:"Calculations",diff:"Easy",q:"What is the formula for single-phase power in watts?",opts:["P = V²/R only","P = I²R only","P = IV (watts = amperes × volts)","All forms are correct"],ans:3,ref:"Ohm's Law & Power formula",exp:"All three forms are equivalent: P=IV, P=V²/R, P=I²R. P=IV most commonly used in practice. P=I²R when resistance is known. P=V²/R when only voltage and resistance are known."},
{id:370,mod:10,cat:"Calculations",diff:"Hard",q:"Per Table 220.55, what is the demand for 8 household electric ranges rated 8 kW each?",opts:["51,200 VA (80% of total)","64,000 VA (8 × 8,000)","40,000 VA (Table 220.55 column C)","48,000 VA (column C)"],ans:2,ref:"NEC Table 220.55",exp:"Table 220.55 Column C: 8 ranges = 40 kW demand. Significantly less than 64 kW connected load. Table assumes not all ranges fully loaded simultaneously."},
{id:371,mod:10,cat:"Calculations",diff:"Medium",q:"A 90°C rated conductor has a 30A ampacity but is connected to 75°C rated equipment. What ampacity must be used?",opts:["75°C column value for this conductor size","Any value between 25A and 30A","30A — use conductor's full 90°C ampacity","25A from 75°C column"],ans:0,ref:"NEC 110.14(C)(1)",exp:"Termination rule: limited by LOWEST temperature rating. 75°C equipment limits system to 75°C ampacity even though conductor is rated 90°C. 90°C rating only applies if equipment terminations are also 90°C rated."},
{id:372,mod:10,cat:"Calculations",diff:"Medium",q:"How does the NEC treat voltage drop for branch circuits?",opts:["3% voltage drop is a mandatory NEC requirement","3% recommended maximum for branch circuits; 5% total (branch + feeder) recommended","No NEC basis — engineering recommendation only","3% applies to feeders only"],ans:1,ref:"NEC 210.19(A)(1) Informational Note",exp:"NEC recommends (does not require) 3% max voltage drop on branch circuits, 5% total combined branch circuit + feeder. These are informational notes. Some jurisdictions and California Title 24 may effectively enforce voltage drop limits."},
{id:373,mod:10,cat:"Calculations",diff:"Hard",q:"What derating factor applies when 12 current-carrying conductors share a conduit?",opts:["80% (4-6 conductors)","35% (21-30 conductors)","70% (7-9 conductors)","50% (10-20 conductors)"],ans:3,ref:"NEC 2020 Table 310.15(C)(1)",exp:"Table 310.15(C)(1): 10-20 current-carrying conductors = 50% adjustment. Conductor normally rated 30A → derate to 30 × 0.50 = 15A. Better to use multiple smaller conduits than many conductors in one."},
{id:374,mod:10,cat:"Calculations",diff:"Medium",q:"A 120V, 20A circuit runs 75 feet with a 15A continuous load. What is the minimum conductor size to keep voltage drop under 3%?",opts:["12 AWG is sufficient","8 AWG needed","10 AWG needed","Voltage drop not a concern at 75 feet"],ans:2,ref:"NEC 210.19(A)(1) Informational Note",exp:"Max VD = 120 × 3% = 3.6V. CM required = 2 × 12.9 × 15 × 75/3.6 = 29,025/3.6 = 8,063 CM. 12 AWG = 6,530 CM (insufficient). 10 AWG = 10,380 CM (meets requirement). Voltage drop drives conductor sizing on longer runs."},
{id:375,mod:10,cat:"Calculations",diff:"Easy",q:"The total service demand for lighting of 4,470 VA, small appliance of 2,100 VA, and a 5 kW water heater is _____.",opts:["11,570 VA","13,570 VA","9,470 VA","6,570 VA"],ans:0,ref:"NEC 220.82",exp:"Total = 4,470 + 2,100 + 5,000 = 11,570 VA. Water heaters added at 100% — not demand-factored. This is before adding HVAC, dryer, and other appliance loads."},
{id:376,mod:10,cat:"Calculations",diff:"Hard",q:"A 500 kcmil copper THWN at 75°C has 380A ampacity with nine conductors in conduit. What is the derated ampacity?",opts:["304A (80% — wrong count)","266A (70% for 7-9 conductors)","380A — large conductors exempt from derating","190A (50% — wrong count)"],ans:1,ref:"NEC 2020 Table 310.15(C)(1)",exp:"Nine conductors: 7-9 range = 70% adjustment. 380A × 0.70 = 266A. No conductors exempt from derating — large conductors derated same as small ones."},
{id:377,mod:10,cat:"Calculations",diff:"Medium",q:"The general lighting load for a 1,200 sq ft dwelling is _____.",opts:["1,200 VA","2,400 VA","4,800 VA","3,600 VA"],ans:3,ref:"NEC Table 220.12",exp:"Dwelling = 3 VA/sq ft. 1,200 × 3 = 3,600 VA connected load. After Table 220.42 demand: first 3,000 at 100% = 3,000; remainder 600 at 35% = 210; demand = 3,210 VA."},
{id:378,mod:10,cat:"Calculations",diff:"Hard",q:"A 75 kVA transformer with 5% impedance and a 208V secondary has an approximate available fault current of _____.",opts:["2,082A","41,650A","4,164A","20,825A"],ans:2,ref:"NEC 110.9 & 110.10",exp:"Secondary FLA = 75,000/(208 × 1.732) = 208.2A. Available fault current = FLA / %Z = 208.2/0.05 = 4,164A from transformer alone. Primary source impedance would add to this in a complete calculation."},
{id:379,mod:10,cat:"Calculations",diff:"Medium",q:"A 1/2-inch EMT conduit can hold a maximum of _____ 14 AWG THWN conductors.",opts:["4","6","9","12"],ans:2,ref:"NEC Annex C, Table C1",exp:"Annex C Table C1 (EMT): 1/2-inch EMT = 9 conductors of 14 AWG THWN. Direct table lookup. Memorize: 1/2\" EMT = 9×14AWG or 7×12AWG THWN."},
{id:380,mod:10,cat:"Calculations",diff:"Hard",q:"A 240V single-phase motor is rated 10 HP with 50A FLA and SF=1.15. What is the maximum overload relay setting?",opts:["62.5A (125% FLA)","50A (100% FLA)","75A (150% FLA)","57.5A (115% FLA)"],ans:0,ref:"NEC 430.32(A)(1)",exp:"SF ≥ 1.15 → maximum overload = 125% of nameplate FLA. 50A × 1.25 = 62.5A. If SF < 1.15, maximum = 115% = 57.5A."},
{id:381,mod:10,cat:"Calculations",diff:"Medium",q:"Per the NEC demand calculation, what is the demand for one household electric range rated 11 kW?",opts:["11,000 × 80% = 8,800 VA","Column C for one range: 8,000 VA","11,000 VA at 100%","8,000 VA per Table 220.55"],ans:1,ref:"NEC Table 220.55",exp:"For one range 8¾ kW to 12 kW: Table 220.55 Column C = 8,000 VA demand. Actual 11 kW nameplate irrelevant — table value governs. For ranges over 12 kW, add 5% per kW above 12 to the 8 kW base."},
{id:382,mod:10,cat:"Calculations",diff:"Easy",q:"What is the formula for three-phase power?",opts:["P = V × I × 2","P = V × I","P = V × I × 1.732","P = V × I × 1.732 × PF"],ans:3,ref:"Three-phase power formula",exp:"Three-phase true power: P = V × I × 1.732 × PF. Apparent power (VA): VA = V × I × 1.732 (no PF). √3 = 1.732 accounts for the three-phase relationship."},
{id:383,mod:10,cat:"Calculations",diff:"Medium",q:"Four lighting fixtures rated 300W each operate at 120V continuously. What is the minimum circuit rating?",opts:["12A calculated","10A standard circuit","20A — continuous load pushes beyond 15A capacity","15A — fits on standard circuit"],ans:2,ref:"NEC 210.20(A)",exp:"4 × 300W = 1,200W/120V = 10A. Continuous × 125% = 12.5A. 15A circuit continuous limit = 12A (80%). 12.5A > 12A = requires 20A circuit (80% = 16A > 12.5A). Common exam trap."},
{id:384,mod:10,cat:"Calculations",diff:"Hard",q:"The ampacity of 4/0 AWG aluminum THWN at 75°C from Table 310.16 is _____.",opts:["180A","200A","230A","150A"],ans:0,ref:"NEC Table 310.16 (75°C column)",exp:"4/0 AWG aluminum THWN at 75°C = 180A. At 60°C = 150A. At 90°C = 205A. Common for 150A-200A services using aluminum. Always know copper vs aluminum ampacity differences."},
{id:385,mod:10,cat:"Calculations",diff:"Medium",q:"A 20A, 120V GFCI circuit supplies a bathroom with a 1,800W load. Is this compliant?",opts:["No — bathroom circuits limited to 1,440W","Yes — 15A is within 80% (1,920 VA) continuous limit for 20A circuit","No — bathroom circuits limited to 1,500W","Yes — if load is non-continuous"],ans:1,ref:"NEC 210.20(A)",exp:"1,800W/120V = 15A. On 20A circuit, continuous limit = 16A (80%). If continuous, 15A < 16A = compliant. If non-continuous, full 20A capacity available. 80% rule only restricts continuous loads."},
{id:386,mod:10,cat:"Calculations",diff:"Hard",q:"What is the maximum length of 12 AWG copper to stay within a 3% voltage drop limit on a 20A, 120V circuit at 15A (K=12.9)?",opts:["35.7 feet one-way","53.6 feet one-way","71.4 feet one-way","45.6 feet one-way"],ans:3,ref:"NEC 210.19(A)(1) Informational Note",exp:"Max VD = 120 × 3% = 3.6V. D = (VD × CM)/(2 × K × I) = (3.6 × 6,530)/(2 × 12.9 × 15) = 23,508/387 = 60.7 feet. Approximately 45-60 feet depending on exact calculation method."},
{id:387,mod:10,cat:"Calculations",diff:"Medium",q:"A commercial kitchen has 48 kW of connected cooking equipment with a 65% demand factor. What is the feeder demand?",opts:["31,200 VA","72 kW","31.2 kW","48 kW"],ans:2,ref:"NEC 220.56 & Table 220.56",exp:"Demand = 48 kW × 0.65 = 31.2 kW. At 480V three-phase, unity PF: I = 31,200/(480 × 1.732) = 37.5A feeder current. Demand factors reflect not all equipment fully loaded simultaneously."},
{id:388,mod:10,cat:"Calculations",diff:"Easy",q:"What is the resistance of a 100-foot length of 12 AWG copper at 1.98 ohms per 1,000 feet?",opts:["0.198 ohms","1.98 ohms","198 ohms","19.8 ohms"],ans:0,ref:"NEC Chapter 9, Table 9",exp:"R = (100/1,000) × 1.98 = 0.198 ohms. One-way resistance doubled for round-trip voltage drop (total circuit = 2 × one-way = 0.396 ohms for 100-foot circuit)."},
{id:389,mod:10,cat:"Calculations",diff:"Hard",q:"The primary current of a three-phase 75 kVA transformer at 480V is _____.",opts:["104A","90.2A","72.2A","156.3A"],ans:1,ref:"NEC 450.3(B) (sizing basis)",exp:"Primary I = kVA × 1,000/(V × √3) = 75,000/(480 × 1.732) = 75,000/831.4 = 90.2A. Primary protection maximum = 90.2 × 1.25 = 112.7A → use 110A or 100A standard fuse."},
{id:390,mod:10,cat:"Calculations",diff:"Medium",q:"What does the 80% continuous load rule mean for a 15A circuit breaker?",opts:["Breaker derated to 12A for all applications","Breaker handles only 80% of fault current","80% applies only to industrial circuits","Maximum continuous load = 12A (15A × 80%)"],ans:3,ref:"NEC 210.20(A)",exp:"15A × 80% = 12A maximum CONTINUOUS load (loads on for 3+ hours). 1,440 VA maximum continuous on 15A, 120V circuit. Non-continuous loads can use full 15A capacity."},
{id:391,mod:10,cat:"Calculations",diff:"Hard",q:"A 3-phase 480V motor drawing 50A at 0.85 power factor consumes _____ of true power.",opts:["57,600W","41,530W","35,326W","24,000W"],ans:2,ref:"Three-phase power formula",exp:"Apparent = 480 × 50 × 1.732 = 41,568 VA. True Power = 41,568 × 0.85 = 35,333W ≈ 35,326W. The reactive power (41,568 - 35,333 = 6,235 VAR) does no useful work but flows through conductors."},
{id:392,mod:10,cat:"Calculations",diff:"Medium",q:"What limits the number of usable knockouts in a junction box?",opts:["Box fill calculations — conductors through knockouts must fit within box cubic inch capacity","NEC doesn't limit knockout use","Maximum 4 knockouts in any standard box","The number of knockouts provided by manufacturer"],ans:0,ref:"NEC 314.16",exp:"Knockouts limited by box fill. Each knockout used allows conductors to enter — each conductor takes cubic inches. When box fill is at maximum, no additional conductors (or knockouts) may be used."},
{id:393,mod:10,cat:"Calculations",diff:"Easy",q:"What human body resistance value is used in electrical safety calculations?",opts:["100,000 ohms","1,000 ohms","10,000 ohms","500 ohms"],ans:1,ref:"NFPA 70E Annex K",exp:"Typical human body resistance ≈ 1,000 ohms (skin to skin, dry conditions). At 120V: I = 120/1,000 = 120mA — well above 10-50mA that causes ventricular fibrillation. Wet conditions: resistance drops to 300Ω or less."},
{id:394,mod:10,cat:"Calculations",diff:"Hard",q:"What is the optional calculation result for a 2,000 sq ft dwelling with all-electric appliances totaling 25 kVA?",opts:["12,500 VA (50% demand)","10,000 VA minimum","25,000 VA","16,000 VA — first 10 kVA at 100%, remainder at 40%"],ans:3,ref:"NEC 220.82(B)",exp:"Optional method: first 10 kVA at 100% = 10,000; remainder = 15,000 at 40% = 6,000; total = 16,000 VA. Often results in lower calculated demand than standard method."},
{id:395,mod:10,cat:"Calculations",diff:"Medium",q:"When applying both temperature correction AND conduit fill derating factors, how applied?",opts:["Add factors then subtract from 100%","Use larger of two factors only","Multiply both correction factors together, then multiply by table ampacity","Apply sequentially — first temperature, then fill"],ans:2,ref:"NEC 2020 310.15(B)(1) & Table 310.15(C)(1)",exp:"Both factors MULTIPLIED together then applied to table ampacity. Example: temp correction 0.82 × conduit fill 0.80 = 0.656 combined factor. 30A table × 0.656 = 19.7A derated ampacity. Never add the factors — always multiply."},
// MODULE 11: CALIFORNIA-SPECIFIC (50)
// MODULE 12: SAFETY, MAINTENANCE & REPAIR (55)
{id:446,mod:12,cat:"Safety & Maintenance",diff:"Easy",q:"What does LOTO stand for?",opts:["Load Override Transfer Operations","Limitation of Task Output","Lock Out Tag Out — the energy control procedure","Line Outage Test Operations"],ans:2,ref:"8 CCR § 3314",exp:"LOTO = Lockout/Tagout — energy control procedure required by Cal/OSHA (Title 8, Section 3314). Lockout physically prevents operation; tagout uses warning tag when lockout is not feasible."},
{id:447,mod:12,cat:"Safety & Maintenance",diff:"Easy",q:"Who is authorized to remove a lockout or tagout device?",opts:["The foreman or supervisor","Only the employee who applied the device (with limited exceptions)","Any journeyman electrician on the job","The safety officer"],ans:1,ref:"8 CCR § 3314(b)(8)",exp:"Only the employee who applied the LOTO device may remove it, except in documented emergency situations. Prevents someone from inadvertently re-energizing equipment while another worker is still in the danger zone."},
{id:448,mod:12,cat:"Safety & Maintenance",diff:"Medium",q:"What is the correct sequence for a LOTO procedure?",opts:["Shut down, Isolate, Apply LOTO, Release stored energy, Verify, Notify","Apply LOTO, Notify, Verify, Shut down, Release stored energy, Isolate","Notify, Identify, Isolate, Apply LOTO, Verify, Release stored energy","Notify affected employees, Identify all energy sources, Shut down equipment, Isolate energy, Apply LOTO, Release stored energy, Verify de-energized"],ans:3,ref:"8 CCR § 3314(b)(1)-(8)",exp:"Correct LOTO sequence: (1) Notify affected employees, (2) Identify all energy sources, (3) Shut down equipment, (4) Isolate energy, (5) Apply LOTO devices, (6) Release stored energy (bleed pressure, discharge capacitors), (7) Verify de-energized (try-start, voltage test). Verification step is critical."},
{id:449,mod:12,cat:"Safety & Maintenance",diff:"Medium",q:"What PPE is required for working on energized 480V equipment?",opts:["Voltage-rated rubber gloves, arc flash face shield, and FR (flame-resistant) clothing","Hard hat and safety glasses are sufficient","Standard work clothes and safety glasses","Only rubber gloves"],ans:0,ref:"NFPA 70E Table 130.7(C)(15)(a)",exp:"Energized 480V work: rubber insulating gloves rated for voltage (minimum Class 00 for 500V), leather protectors over gloves, arc flash face shield or hood rated for incident energy, FR clothing. Specific PPE determined by arc flash hazard analysis."},
{id:450,mod:12,cat:"Safety & Maintenance",diff:"Medium",q:"What is the arc flash boundary?",opts:["Restricted approach boundary for unqualified persons","Distance where arc flash energy equals zero","Boundary where workers need arc flash PPE — where incident energy could exceed 1.2 cal/cm² (threshold for second-degree burns)","Distance at which arc flash ignites clothing"],ans:2,ref:"NFPA 70E 130.5(B)",exp:"Arc flash boundary = distance from arc source where a person without arc flash PPE would receive onset of second-degree burn (1.2 cal/cm²). Within boundary, arc flash PPE required. Determined by arc flash hazard analysis."},
{id:451,mod:12,cat:"Safety & Maintenance",diff:"Hard",q:"What is the difference between the limited approach boundary and the restricted approach boundary?",opts:["Restricted is for high voltage; limited is for low voltage","Limited approach = where unqualified persons must stop; restricted approach = where even qualified persons need special PPE and precautions","Limited applies during normal operation; restricted during maintenance only","Same — interchangeable terms"],ans:1,ref:"NFPA 70E Table 130.4(D)(a)",exp:"Limited approach: unqualified persons must not cross without escort. Restricted approach: even qualified persons crossing need rubber insulating equipment, appropriate PPE, and energized electrical work permit."},
{id:452,mod:12,cat:"Safety & Maintenance",diff:"Easy",q:"What is the FIRST action to take when witnessing someone receiving an electric shock?",opts:["Begin CPR immediately","Call 911 before doing anything else","Immediately grab victim and pull away","Shut off or disconnect the power source before touching the victim"],ans:3,ref:"NFPA 70E 130.7(C)(1)",exp:"FIRST — shut off or disconnect the power. Touching the victim while in contact with energized conductor will electrocute you too. Use non-conductive object to separate victim from conductor only if power cannot be immediately disconnected. After power off: call 911, then first aid/CPR."},
{id:453,mod:12,cat:"Safety & Maintenance",diff:"Medium",q:"How is a 'qualified person' defined for electrical safety purposes?",opts:["Person with documented training and demonstrated knowledge of energized electrical equipment and hazards at the specific voltage level","Any person with 5 years electrical experience","Certified electrical safety officer only","Any licensed electrician"],ans:0,ref:"NFPA 70E Article 100 & 8 CCR § 2299",exp:"Qualified person: (1) training and knowledge of electrical equipment and hazards, (2) ability to perform work safely, (3) training specific to voltage levels and equipment types encountered. Task-specific and equipment-specific — not universal."},
{id:454,mod:12,cat:"Safety & Maintenance",diff:"Hard",q:"When is an energized electrical work permit required?",opts:["When work is performed alone without second person present","Only for work on circuits above 600V","When justified work must be performed on or near live electrical parts — when de-energizing would create greater hazard or is infeasible","For all work within an electrical room"],ans:2,ref:"NFPA 70E 130.2(A)(3)",exp:"Energized work permit required when work must be performed while energized. Documents: justification (de-energizing creates greater hazard or infeasible), scope of work, all hazards, required PPE, and management authorization."},
{id:455,mod:12,cat:"Safety & Maintenance",diff:"Medium",q:"Voltage-rated rubber insulating gloves must be electrically tested every _____.",opts:["Monthly","Every 6 months","Before each use only — formal testing not required","Annually — before each use if showing visible damage"],ans:1,ref:"NFPA 70E 130.7(C)(11)(a)",exp:"Rubber insulating gloves must be electrically tested EVERY 6 MONTHS and whenever subjected to suspected damage. Visual inspection catches obvious damage; 6-month electrical test (high-voltage proof test) identifies hidden flaws."},
{id:456,mod:12,cat:"Safety & Maintenance",diff:"Easy",q:"What are the correct colors for the DANGER, WARNING, and CAUTION safety label signal words?",opts:["DANGER = yellow; WARNING = red; CAUTION = orange","All use the same red and white","All electrical warnings must use black on white","DANGER = red background; WARNING = orange background; CAUTION = yellow background"],ans:3,ref:"ANSI Z535.4 & NEC labels",exp:"ANSI/ISO: DANGER (red background, white letters) = imminently hazardous — will cause death/serious injury. WARNING (orange, black) = potentially hazardous — could cause death/serious injury. CAUTION (yellow, black) = possibly hazardous — may cause minor injury."},
{id:457,mod:12,cat:"Safety & Maintenance",diff:"Medium",q:"A circuit breaker has been tripping repeatedly. What is the correct first action?",opts:["Identify and correct the cause of tripping before resetting","Immediately replace with larger ampere rating","Reset only after shutting off all loads","Reset it and see if it holds"],ans:0,ref:"NEC 240.4 & NFPA 70E general",exp:"Repeatedly tripping breakers = a problem. Find and fix the cause FIRST. Resetting without investigation = dangerous — may result in conductor overheating or fire. Replacing with larger breaker without correction is extremely dangerous."},
{id:458,mod:12,cat:"Safety & Maintenance",diff:"Hard",q:"How frequently does OSHA require testing of portable GFCI devices on construction sites?",opts:["GFCI devices don't require regular testing","Weekly","Before each use (test button)","Monthly"],ans:2,ref:"8 CCR § 1590(j)",exp:"Portable GFCI devices must be tested before EACH use with the test button. Test button only verifies basic trip mechanism — not ground fault detection circuit. For comprehensive testing, use a GFCI tester that simulates actual ground fault current."},
{id:459,mod:12,cat:"Safety & Maintenance",diff:"Medium",q:"When must an electrician immediately stop work and report a hazard?",opts:["Only if hazard directly affects the electrician's own safety","Whenever they observe a condition that violates safety standards","Only when hazard involves imminent death or serious injury","When directed by foreman to stop"],ans:1,ref:"CA Labor Code § 6310",exp:"Workers have a right and responsibility to stop work when encountering hazardous conditions and report to supervisor. Cal/OSHA prohibits employer retaliation against workers who report safety hazards."},
{id:460,mod:12,cat:"Safety & Maintenance",diff:"Hard",q:"What is an arc flash incident energy analysis?",opts:["Test required before each panel opening","Test measuring brightness of an arc flash","Measurement of voltage available at arc flash location","Engineering calculation determining thermal energy released at a specific working distance during arc flash — used to select appropriate PPE"],ans:3,ref:"NFPA 70E 130.5",exp:"Incident energy analysis uses fault current data, protective device clearing times, and working distances to calculate thermal energy (cal/cm²) at a specific working distance. Determines required PPE category and arc flash boundary distance."},
{id:461,mod:12,cat:"Safety & Maintenance",diff:"Medium",q:"What hazard do electrical hazard (EH) safety shoes protect against?",opts:["Both shock protection and step potential","Step potential — current through ground from downed conductor creating potential difference between feet","Direct shock from energized conductors","No electrical protection — general impact protection only"],ans:0,ref:"ASTM F2413 & NFPA 70E 130.7(C)(8)",exp:"EH-rated safety shoes: (1) secondary protection against shock if worker contacts energized circuit through feet, and (2) some protection against step potential hazards. Non-conductive soles increase resistance to ground. NOT a substitute for GFCI or insulating platforms."},
{id:462,mod:12,cat:"Safety & Maintenance",diff:"Easy",q:"What should you do with a tripped GFCI or ground fault protection device?",opts:["Reset immediately — ground faults are transient","Reset — most ground faults won't recur","Find and correct the ground fault before resetting","Replace breaker with GFCI breaker same amperage"],ans:2,ref:"NEC 210.8 & GFCI theory",exp:"GFCI trip indicates current flowing through unintended path — possibly through a person or damaged insulation. LOCATE and CORRECT the ground fault before resetting. Common causes: damaged cord, water in outlet, wiring fault."},
{id:463,mod:12,cat:"Safety & Maintenance",diff:"Hard",q:"What is the purpose of a non-contact voltage tester (NCVT)?",opts:["Measure exact voltage at a test point","Detect presence or absence of voltage without direct contact with energized conductors","Test GFCI outlets for proper operation","Measure resistance in electrical circuits"],ans:1,ref:"NFPA 70E 110.4(A)(5)",exp:"NCVTs detect AC voltage presence by sensing electromagnetic field around energized conductors. Provide go/no-go indication — NOT actual voltage measurement. Always verify tester works on known live source before AND after testing unknown circuit."},
{id:464,mod:12,cat:"Safety & Maintenance",diff:"Medium",q:"What must Cal/OSHA do when a worker reports an electrical hazard?",opts:["Investigate and document but work may continue","Simply post a warning sign","Only address hazard during next scheduled safety inspection","Immediately correct hazard or provide interim protection, and document the correction"],ans:3,ref:"8 CCR § 3203 & CA Labor Code § 6401.7",exp:"Cal/OSHA: correct identified hazards in timely manner. Imminent hazards: work must stop until corrected. Non-imminent: corrected within reasonable time. All reports and corrections must be documented in IIPP."},
{id:465,mod:12,cat:"Safety & Maintenance",diff:"Easy",q:"What is the minimum safe distance from overhead power lines during construction?",opts:["10 feet for lines up to 50 kV","20 feet for all voltage levels","6 feet","3 feet"],ans:0,ref:"8 CCR § 2941(a)",exp:"Cal/OSHA: minimum 10-foot clearance from overhead power lines up to 50 kV for equipment, personnel, and materials. Higher voltage = greater required clearance. Overhead line contact = leading cause of construction fatalities."},
{id:466,mod:12,cat:"Safety & Maintenance",diff:"Medium",q:"What are the physiological effects of electrical shock?",opts:["Force exerted by electromagnetic field","Voltage difference between two conductors","Physiological effect on body when current passes through it — can cause burns, muscle paralysis, respiratory failure, and cardiac arrest","Any physical contact with electrical equipment"],ans:2,ref:"NFPA 70E Annex K",exp:"Shock = current through body. Effects by level: 1mA = perceptible; 5mA = painful; 10-20mA = can't let go (muscle freeze); 50-100mA = ventricular fibrillation; 100-200mA = nearly certain death. Current kills — voltage drives the current."},
{id:467,mod:12,cat:"Safety & Maintenance",diff:"Hard",q:"What is 'step potential' and when does it present a danger?",opts:["Potential energy stored in elevated cable","Hazardous voltage difference between points on the ground near a fault or downed conductor","Voltage required to start a motor step by step","Voltage between different floors of a building"],ans:1,ref:"NFPA 70E Annex O",exp:"Step potential: fault current through earth creates voltage gradient along ground surface. Points closer to fault at higher potential than points farther away. Person straddling two different-potential points = circuit through body without touching faulted conductor. Shuffle step minimizes exposure."},
{id:468,mod:12,cat:"Safety & Maintenance",diff:"Medium",q:"What is the proper way to use a multimeter to measure voltage in a live panel?",opts:["Always use both hands for accuracy","Insert both probes simultaneously","Use current clamp — avoid inserting probes into live panels","Set meter to highest voltage range, work down to appropriate range; keep one hand behind back or in pocket"],ans:3,ref:"NFPA 70E 130.6(B)",exp:"Safe multimeter technique: set to highest range first (prevents meter damage), then reduce. One hand behind back keeps current from crossing chest (heart) if accidental contact occurs. Use insulated probes and appropriate PPE."},
{id:469,mod:12,cat:"Safety & Maintenance",diff:"Hard",q:"What is the difference between Class 00 and Class 4 rubber insulating gloves?",opts:["Class 00 rated 500V (proof tested 2,500V); Class 4 rated 36,000V (proof tested 40,000V)","Only color differs","Class 00 for wet; Class 4 for dry","Class 4 thicker but same voltage rating as Class 00"],ans:0,ref:"ASTM D120 & NFPA 70E Table 130.7(C)(7)(b)",exp:"Rubber glove classes: 00=500V max (2,500V proof); 0=1,000V; 1=7,500V; 2=17,000V; 3=26,500V; 4=36,000V max (40,000V proof). Glove class must match or exceed voltage of work being performed."},
{id:470,mod:12,cat:"Safety & Maintenance",diff:"Medium",q:"What does FR (Flame Resistant) clothing protect against?",opts:["Only static electricity sparks","Electric shock — FR prevents current through body","Arc flash thermal energy — FR self-extinguishes and doesn't continue burning after arc energy dissipates","Both shock and arc flash protection"],ans:2,ref:"NFPA 70E 130.7(C)(5) & ASTM F1506",exp:"FR clothing protects against arc flash by: (1) not continuing to burn after arc energy dissipates (self-extinguishes), and (2) limiting skin burn injury. FR does NOT protect against shock — rubber insulating equipment required for that. Standard polyester/nylon melts and continues burning, dramatically worsening burn injuries."},
{id:471,mod:12,cat:"Safety & Maintenance",diff:"Easy",q:"What is the first step when finding a circuit that needs repair?",opts:["Notify building owner before doing anything","De-energize the circuit using proper LOTO procedure before beginning work","Begin repairs immediately to restore power quickly","Test circuit with multimeter to understand fault before de-energizing"],ans:1,ref:"8 CCR § 3314 & NFPA 70E 130.2",exp:"Always de-energize with proper LOTO BEFORE beginning work. Rushing to diagnose without de-energizing is how experienced electricians get electrocuted — familiarity breeds dangerous complacency. No exceptions."},
{id:472,mod:12,cat:"Safety & Maintenance",diff:"Medium",q:"What is the test sequence to verify a circuit is de-energized before beginning work?",opts:["Testing only required for circuits above 240V","Visual confirmation breaker is off is all that's needed","Visual inspection of open breaker is sufficient","Test with voltage tester on known live source, test on circuit to verify no voltage, then test on known live source again (test-before-touch)"],ans:3,ref:"NFPA 70E 120.5(7)",exp:"Test-before-touch sequence: (1) Verify tester works on known live source, (2) Test circuit to verify no voltage, (3) Verify tester still works on known live source. Three steps catch both dead circuits AND dead testers."},
{id:473,mod:12,cat:"Safety & Maintenance",diff:"Hard",q:"How does the NFPA 70E PPE category system determine arc flash protection requirements?",opts:["PPE Categories 1-4 based on incident energy levels in cal/cm²","Protection levels based on equipment age","Classes 1-5 based on voltage level","Hazard levels A through D based on fault current"],ans:0,ref:"NFPA 70E Table 130.7(C)(15)(a)",exp:"NFPA 70E PPE Categories 1-4: Cat 1 = min 4 cal/cm² (minimum arc rating); Cat 2 = min 8 cal/cm²; Cat 3 = min 25 cal/cm²; Cat 4 = min 40 cal/cm². Above 40 cal/cm² requires incident energy analysis for specific PPE."},
{id:474,mod:12,cat:"Safety & Maintenance",diff:"Medium",q:"When is a buddy system required in electrical safety?",opts:["Pairing apprentices with journeymen for training","Checking each other's work before energizing","Having a second qualified person present when working on energized electrical equipment — required by Cal/OSHA for certain energized work","Sharing tools between workers"],ans:2,ref:"8 CCR § 2299 & NFPA 70E 130.2",exp:"Buddy system (second qualified person present) required by Cal/OSHA when working on energized equipment above certain voltage levels. Second person can: call for help in emergency, assist with safe rescue, provide additional safety check."},
{id:475,mod:12,cat:"Safety & Maintenance",diff:"Easy",q:"The maximum voltage considered 'low-voltage' for shock hazard purposes per NFPA 70E is _____.",opts:["600V","50V","30V","120V"],ans:1,ref:"NFPA 70E 130.2(A)(4)",exp:"NFPA 70E: 50V is the threshold for electrical shock hazard. Below 50V, shock hazard minimal under normal dry conditions (though GFCI may still be required). Above 50V, all approach boundary, PPE, and qualified person requirements apply."},
{id:476,mod:12,cat:"Safety & Maintenance",diff:"Medium",q:"What must an electrical safety program required by NFPA 70E and Cal/OSHA include?",opts:["Only the LOTO procedure — other requirements optional","Only a list of prohibited actions","List of qualified personnel only","Safety policies, training requirements, PPE selection, energized work permit procedures, LOTO procedures, approach boundaries, and incident investigation"],ans:3,ref:"NFPA 70E 110.3",exp:"Electrical safety program elements: written safety policies, training/retraining requirements, energized work procedures, energized work permit system, LOTO procedures, approach boundary documentation, PPE selection procedures, and incident investigation procedures."},
{id:477,mod:12,cat:"Safety & Maintenance",diff:"Hard",q:"Cal/OSHA requires electrical safety training refresher for electrical workers _____.",opts:["Annually and whenever an electrician demonstrates unsafe practices or is involved in an electrical incident","Once at initial hire — no refresher required","Only when job duties change significantly","Every 3 years aligned with certification renewal"],ans:0,ref:"8 CCR § 3203 & NFPA 70E 110.2",exp:"Cal/OSHA: electrical safety training repeated at regular intervals (typically annually), AND whenever: (1) employee demonstrates unsafe practices, (2) after electrical incident or near-miss. Documentation of all training must be maintained."},
{id:478,mod:12,cat:"Safety & Maintenance",diff:"Medium",q:"What to do with a circuit breaker showing burned or scorched contact marks?",opts:["Test and reinstall if passes test","Clean contacts with electrical contact cleaner and reinstall","Replace the breaker — burned contacts indicate fault operation; internal mechanism may be compromised","Lubricate with dielectric grease"],ans:2,ref:"NEC 240.4 & NFPA 70E general",exp:"Burned/pitted/carbonized contacts = breaker has operated under fault conditions. Internal mechanism may be compromised even if it resets. Replace damaged breakers — never trust a breaker showing signs of fault interruption stress."},
{id:479,mod:12,cat:"Safety & Maintenance",diff:"Easy",q:"What PPE is required when working in a panel that is fully de-energized with the service disconnected?",opts:["No PPE — if verified de-energized, standard work clothes acceptable","Safety glasses minimum; leather gloves and hard hat if risk of dropped tools","No PPE required — panel is de-energized","Arc flash PPE same as energized work"],ans:1,ref:"NFPA 70E 130.2 & 8 CCR § 3314",exp:"De-energized panel: shock hazard eliminated but other hazards remain (dropped tools, sharp metal edges). Minimum: safety glasses, leather gloves for cuts, hard hat for overhead work. Arc flash PPE not required for verified de-energized work."},
{id:480,mod:12,cat:"Safety & Maintenance",diff:"Hard",q:"What tool is used to locate a ground fault on a 480V commercial circuit?",opts:["Standard multimeter set to voltage","Non-contact voltage tester only","Circuit breaker trip mechanism indicates fault location","Megger (insulation resistance tester) to find damaged insulation, combined with clamp meter to trace fault current"],ans:3,ref:"NFPA 70E 110.4 & IEEE 1584",exp:"Finding ground faults: (1) Megohmmeter (Megger) applies high DC test voltage to stress-test conductor insulation to ground, (2) clamp meter measures to trace where fault current flows, (3) visual inspection. Megger testing requires circuit de-energized first."},
{id:481,mod:12,cat:"Safety & Maintenance",diff:"Medium",q:"What is a 'tag' in a tagout system when lockout is not possible?",opts:["Warning tag attached to energy isolation point indicating equipment must not be operated — used when physical lockout device cannot be applied","Property tag indicating equipment ownership","Label indicating circuit amperage","Colored marker on conductors for identification"],ans:0,ref:"8 CCR § 3314(b)",exp:"Tagout device = warning tag applied to energy isolation point when physical lockout is impractical due to equipment design. Tag states 'Do Not Operate' or similar warning. Tagout alone provides LESS protection than lockout — relies on people reading and obeying the tag."},
{id:482,mod:12,cat:"Safety & Maintenance",diff:"Medium",q:"How must mercury-containing fluorescent lamps be disposed of in California?",opts:["Only large quantities (100+) require special disposal","Must be crushed before disposal to reduce volume","Must be recycled through approved lamp recycler — they are hazardous waste in California","May be disposed of in regular trash"],ans:2,ref:"CA H&S Code § 25215 et seq.",exp:"California prohibits fluorescent lamp disposal in regular trash — they are hazardous waste. Must be recycled through: utility-sponsored programs, retail collection (Home Depot, IKEA), mail-in recyclers, or licensed hazardous waste facilities."},
{id:483,mod:12,cat:"Safety & Maintenance",diff:"Easy",q:"What is the proper sequence for restoring an electrical system after completing work?",opts:["Simply restore power and leave","Remove LOTO devices, verify tools and materials are cleared, notify all affected employees, and restore energy in controlled manner","Turn power back on quickly to minimize downtime","Remove lockout and restore power without notification"],ans:1,ref:"8 CCR § 3314(b)(9)-(10)",exp:"Proper energy restoration: (1) verify all work complete, tools/materials cleared, (2) ensure all personnel are clear, (3) notify affected employees, (4) remove LOTO devices (only the person who applied them), (5) restore energy in controlled manner."},
{id:484,mod:12,cat:"Safety & Maintenance",diff:"Hard",q:"What is 'double insulation' and how does it affect grounding requirements?",opts:["Insulating both conductors — required for high voltage only","Method of wrapping junction box connections with two layers of tape","Two layers of electrical insulation on conductors — all conductors must be double insulated","Design where tool enclosure is non-conductive, providing protection without a grounding conductor — double insulated tools don't require third grounding wire"],ans:3,ref:"UL 943 & NFPA 70E 130.7(C)(10)",exp:"Double insulation: non-conductive outer enclosure PLUS individually insulated internal components. No grounding wire (green wire) needed. Marked with square-within-square symbol. No third grounding pin on their plugs."},
{id:485,mod:12,cat:"Safety & Maintenance",diff:"Medium",q:"What requirements apply when electrical work must be performed without de-energizing?",opts:["Energized electrical work permit, appropriate PPE based on arc flash hazard analysis, and qualified person performing the work","GFCI protection must be provided","A second qualified person must be present","No additional requirements — a qualified electrician may work on any energized equipment"],ans:0,ref:"NFPA 70E 130.2(A)(3)",exp:"Energized work: (1) documented justification that de-energizing creates greater hazard or is infeasible, (2) energized electrical work permit authorized by management, (3) appropriate PPE from arc flash hazard analysis, (4) performed by qualified person."},
{id:486,mod:12,cat:"Safety & Maintenance",diff:"Hard",q:"What does OSHA require when opening panels for inspection (not maintenance or repair)?",opts:["Inspection permitted without PPE — no contact with energized parts","Visual inspection from distance requires no PPE","If no inadvertent contact anticipated, minimum PPE; if possible inadvertent contact, appropriate PPE required","Opening panels always requires full arc flash PPE"],ans:2,ref:"NFPA 70E 130.2(A)(2)",exp:"OSHA/NFPA 70E distinguish: inspection from safe distance without possible contact = minimum PPE. Inspection within approach boundaries = appropriate PPE based on incident energy. Opening a panel to read a meter while staying outside approach boundaries doesn't require arc flash PPE."},
{id:487,mod:12,cat:"Safety & Maintenance",diff:"Easy",q:"What are the correct signal word colors for DANGER, WARNING, and CAUTION safety labels?",opts:["All warnings use same red and white","DANGER = red background; WARNING = orange; CAUTION = yellow","DANGER = yellow; WARNING = red; CAUTION = orange","All electrical warnings must be black on white"],ans:1,ref:"ANSI Z535.4",exp:"ANSI/ISO standard: DANGER (red, will cause death/serious injury), WARNING (orange, could cause death/serious injury), CAUTION (yellow, may cause minor injury). Electricians must understand these signal word distinctions."},
{id:488,mod:12,cat:"Safety & Maintenance",diff:"Medium",q:"What does the GFCI test button actually test?",opts:["Proves the circuit is dead and safe to work on","Tests GFCI's response to actual ground fault current","Resets the GFCI after a trip","Tests only the trip mechanism — not the ground fault detection circuitry"],ans:3,ref:"NEC 210.8 & UL 943",exp:"GFCI test button verifies ONLY the internal trip mechanism — NOT whether the device will detect an actual ground fault. A GFCI with failed ground fault sensing but working trip mechanism would pass the button test but fail to protect against ground faults. Use a GFCI tester for comprehensive testing."},
{id:489,mod:12,cat:"Safety & Maintenance",diff:"Hard",q:"What documentation is required for a written LOTO program under Cal/OSHA?",opts:["Written program, equipment-specific energy control procedures for each equipment type, and records of annual inspections and training","Only initial training records for each employee","Only names of authorized employees","No written documentation required — verbal procedures acceptable"],ans:0,ref:"8 CCR § 3314(a)(3)",exp:"Cal/OSHA LOTO documentation: (1) written energy control program, (2) equipment-specific lockout procedures for each equipment type with multiple energy sources, (3) annual inspection records, (4) training records for each authorized and affected employee, (5) records of group LOTO procedures."},
{id:490,mod:12,cat:"Safety & Maintenance",diff:"Medium",q:"What rubber insulating equipment is required when working in an energized 480V panel with exposed bus bars?",opts:["No rubber insulating equipment required for 480V — only 600V+ requires rubber goods","Rubber gloves only","Class 00 rubber gloves with leather protectors, insulated tools, and insulating blankets/barriers to prevent accidental contact","Standard leather gloves provide adequate protection for 480V"],ans:2,ref:"NFPA 70E 130.7(C)(7)",exp:"Working near exposed 480V bus bars: rubber insulating gloves (minimum Class 00, rated 500V) with leather protectors, insulated tools, and insulating barriers/blankets for adjacent energized parts. Leather gloves alone = NO electrical protection."},
{id:491,mod:12,cat:"Safety & Maintenance",diff:"Easy",q:"What is the minimum rubber insulating glove rating required for a 120V, single-phase circuit?",opts:["Class 0 — rated 1,000V","Class 00 — rated 500V max use","Class 1 — rated 7,500V","Any rubber glove provides adequate protection for 120V"],ans:1,ref:"ASTM D120 & NFPA 70E Table 130.7(C)(7)(b)",exp:"Class 00 (500V max use) is minimum for 120V work. Glove voltage rating must exceed circuit voltage. Many safety programs require at least Class 0 (1,000V) for any electrical work for adequate safety margin."},
{id:492,mod:12,cat:"Safety & Maintenance",diff:"Medium",q:"What must be done before performing electrical work in a confined space?",opts:["Only tie off with safety harness","Simply enter and complete work quickly","Confined space permits only required for spaces more than 5 feet deep","Conduct atmospheric testing, obtain required permits, ensure adequate ventilation, and have trained attendant outside"],ans:3,ref:"8 CCR § 5157 & CA Labor Code",exp:"Permit-required confined spaces: (1) atmospheric testing (oxygen, combustible gas, toxic atmosphere), (2) entry permit completed and signed, (3) attendant stationed outside throughout work, (4) rescue equipment available, (5) ventilation as required. Electrical equipment in confined spaces = compounded hazards."},
{id:493,mod:12,cat:"Safety & Maintenance",diff:"Hard",q:"What does 'try-start' verification mean in a LOTO procedure?",opts:["After applying LOTO, attempting to operate equipment at normal control point to verify it cannot start — confirming energy isolation","Starting equipment to verify it runs before locking out","Diagnostic procedure to identify intermittent faults","Testing the lockout device to ensure it cannot be removed without a key"],ans:0,ref:"8 CCR § 3314(b)(5)",exp:"Try-start: after applying all LOTO devices, attempt to operate at normal control point (start button, switch). If it doesn't start = isolation confirmed. Critical verification step before work begins. Then also use voltage tester to verify no voltage at work point."},
{id:494,mod:12,cat:"Safety & Maintenance",diff:"Medium",q:"What is the appropriate action when you discover an unlabeled wire in a junction box?",opts:["Cut it — unlabeled wires are abandoned and safe","Ignore it and work around it","Test with voltage tester while maintaining approach distance — never assume any wire is de-energized based on color or location","Assume it's neutral based on color"],ans:2,ref:"NFPA 70E 120.5(7) & 8 CCR § 3314",exp:"Never assume any conductor is de-energized based on color, location, or assumption. Unlabeled wires may be live circuits, switched legs that energize under certain conditions, or wires with reversed color coding. Test before touch — always."},
{id:495,mod:12,cat:"Safety & Maintenance",diff:"Hard",q:"What does Cal/OSHA require for working on circuits at 600V or less in industrial facilities?",opts:["Only NFPA 70E applies to industrial facilities — Cal/OSHA is for construction only","Cal/OSHA Title 8, Section 2299 et seq. covers electrical safety for general industry — specific requirements for qualified workers, PPE, LOTO, and approach boundaries","Same requirements as commercial buildings","Industrial facilities follow OSHA 1910.303, not Cal/OSHA"],ans:1,ref:"8 CCR §§ 2299-2399 (General Industry Electrical Safety)",exp:"Cal/OSHA Title 8 has separate electrical safety standards for general industry (Article 36, Sections 2299-2399) covering: qualified person requirements, LOTO procedures, approach boundaries, PPE selection. Cal/OSHA standards apply to industrial facilities and often exceed federal OSHA."},
{id:496,mod:12,cat:"Safety & Maintenance",diff:"Medium",q:"What is the proper response when a worker's clothing ignites from arc flash?",opts:["Stand still — moving fans the flames","Run to water source","Remove burning clothing immediately","Stop, drop, and roll — use fire blanket to extinguish flames if available"],ans:3,ref:"NFPA 70E 130.7(A) & first aid",exp:"Clothing ignites: STOP, DROP, ROLL. Running fans flames. Rolling smothers them. FR clothing self-extinguishes and won't melt onto skin, but can still ignite. Fire blanket can smother flames. After extinguishing: call 911, seek immediate medical treatment."},
{id:497,mod:12,cat:"Safety & Maintenance",diff:"Easy",q:"What device allows testing for live voltage without physically touching the conductor?",opts:["A non-contact voltage tester (NCVT)","A clamp meter","A megohmmeter","An analog voltmeter"],ans:0,ref:"NFPA 70E 110.4(A)(5)",exp:"Non-contact voltage tester (NCVT, 'tick tracer,' 'voltage pen') detects AC voltage without contact — senses electromagnetic field around energized conductors. First tool to use when approaching any unknown circuit — quick, safe, simple."},
{id:498,mod:12,cat:"Safety & Maintenance",diff:"Medium",q:"When must electrical contractor's journeyman update safety training records?",opts:["Safety training records are employee's personal responsibility","At each certification renewal (every 3 years)","When job duties change to include new hazards, after incidents, or when employer's safety program changes","Only when changing employers"],ans:2,ref:"8 CCR § 3203 & NFPA 70E 110.2(D)",exp:"Training records updated whenever: (1) job duties change to include new electrical hazards, (2) employee involved in incident or near-miss, (3) changes to employer's safety program or regulations. Employers must maintain training records with dates, content, and employee acknowledgment."},
{id:499,mod:12,cat:"Safety & Maintenance",diff:"Hard",q:"What additional requirements apply for high-voltage maintenance above 600V compared to low-voltage work?",opts:["No additional requirements — same procedures at all voltages","Larger approach boundaries, higher-rated insulating equipment (Class 1-4 gloves), qualified high-voltage workers with specific training, and greater PPE requirements","Only utility employees may work on circuits above 600V","High voltage work simply requires a second person present"],ans:1,ref:"NFPA 70E 130.2 & 8 CCR §§ 2299-2399",exp:"Above 600V: larger approach boundaries, higher-rated rubber insulating equipment (Class 1-4 gloves), specialized high-voltage qualified worker training, and more stringent PPE requirements because higher voltages generate higher fault currents and more severe arc flash hazards."},
{id:500,mod:12,cat:"Safety & Maintenance",diff:"Medium",q:"What is the single most important safety practice an electrician can adopt to prevent electrical shock?",opts:["Always de-energize circuits before working and verify de-energization — treat all conductors as energized until verified otherwise","Always wear rubber gloves","Always work with a partner","Install GFCI on all circuits"],ans:0,ref:"8 CCR § 3314 & NFPA 70E 120.5",exp:"De-energizing before working — and VERIFYING de-energization — is the single most effective electrical safety practice. Most electrical fatalities involve workers who believed circuits were de-energized when they were not. Test-before-touch + proper LOTO eliminates nearly all shock fatality risk."},
{id:501,mod:10,cat:"Calculations",diff:"Easy",q:"Where in the NEC codebook is Table 310.16 (conductor ampacity) located?",opts:["Chapter 3, Article 310","Annex C","Article 100","Chapter 9"],ans:0,ref:"NEC Article 310",exp:"Table 310.16 is in Article 310 — Conductors for General Wiring. It covers ampacity values for copper and aluminum at 60°C, 75°C, and 90°C columns. It's one of the most-referenced tables on the exam — conductor sizing, overcurrent protection, temperature correction all depend on it. Know exactly where it is before exam day."},
{id:502,mod:10,cat:"Calculations",diff:"Easy",q:"Where in the NEC codebook is Table 8 (conductor properties — circular mil areas) located?",opts:["Article 310","Chapter 9","Article 250","Annex A"],ans:1,ref:"NEC Chapter 9, Table 8",exp:"Table 8 is in Chapter 9 — Tables. It lists conductor properties including circular mil (CM) area, needed for the voltage drop formula: VD = 2×K×I×D÷CM. Chapter 9 also contains Table 1 (conduit fill %), Table 5 (conductor cross-sections), and Table 9 (impedance). Tab the whole Chapter 9 section — multiple question types draw from it."},
{id:503,mod:10,cat:"Calculations",diff:"Medium",q:"Which NEC table provides the circular mil area of 6 AWG copper needed for a voltage drop calculation?",opts:["Table 310.16","Annex C, Table C1","Table 250.66","Chapter 9, Table 8"],ans:3,ref:"NEC Chapter 9, Table 8",exp:"Chapter 9, Table 8 lists conductor properties including circular mil area. 6 AWG copper = 26,240 CM. Table 310.16 gives ampacity — not CM area. For voltage drop you need both: Table 310.16 to verify conductor size is adequate, Table 8 for the CM value to plug into the formula."},
{id:504,mod:10,cat:"Calculations",diff:"Easy",q:"What are the NEC Chapter 9 tables primarily used for?",opts:["California-specific code amendments","Conductor ampacity at various temperatures","Conduit fill, conductor properties, and voltage drop data","Equipment grounding conductor sizing"],ans:2,ref:"NEC Chapter 9",exp:"Chapter 9 is the calculation toolbox: Table 1 (conduit fill %), Table 4 (conduit dimensions), Table 5 (conductor cross-section areas), Table 8 (conductor CM area for voltage drop), Table 9 (conductor impedance). If a question requires a number you have to calculate, the data is almost certainly in Chapter 9."},
{id:505,mod:10,cat:"Calculations",diff:"Easy",q:"For what type of exam question is NEC Annex C most useful?",opts:["Conduit fill — maximum number of conductors by conduit type and size","Conductor ampacity questions","Load calculation questions","GFCI and AFCI protection requirements"],ans:0,ref:"NEC Annex C",exp:"Annex C contains conduit and tubing fill tables (C1–C12) for each conduit type — EMT, RMC, PVC, etc. Each table lists maximum conductor counts by conductor size. These are direct lookups: find conduit size and conductor gauge, read the answer. Example: Annex C Table C1, 1/2-inch EMT = 7 conductors of 12 AWG THWN."},
{id:506,mod:1,cat:"Definitions",diff:"Easy",q:"Where are definitions of terms used throughout the NEC located?",opts:["Article 100 — Definitions","Article 90 — Introduction","Annex A","Chapter 9 — Tables"],ans:0,ref:"NEC Article 100",exp:"Article 100 contains definitions for terms used in two or more NEC articles. Terms used in only one article are defined within that article. When a question turns on what a term means — 'feeder,' 'branch circuit,' 'dwelling unit,' 'readily accessible' — Article 100 is the first stop. Tab it."},
{id:507,mod:10,cat:"Calculations",diff:"Medium",q:"Which two NEC tables appear most frequently on the California Journeyman exam?",opts:["Table 220.42 and Table 430.52","Table 310.16 (ampacity) and Chapter 9 Table 8 (conductor properties)","Table 250.66 and Table 314.16(B)","Annex C Table C1 and Table 240.6(A)"],ans:1,ref:"NEC Table 310.16 & Chapter 9 Table 8",exp:"Table 310.16 (conductor ampacity) and Chapter 9 Table 8 (conductor CM area) appear on virtually every exam. Table 310.16 is needed for conductor sizing, overcurrent protection, and temperature correction. Table 8 is needed for voltage drop calculations. Know exactly where both are before you sit down."},
{id:508,mod:10,cat:"Calculations",diff:"Medium",q:"A question asks for box fill requirements for 4 conductors. What is the fastest NEC index lookup path?",opts:["Table 310.16, then cross-reference Chapter 9","Annex C for conductor fill percentages","Scan Chapter 3 until box fill rules appear","NEC index → 'boxes' or 'box fill' → Article 314.16"],ans:3,ref:"NEC 314.16 & NEC Index",exp:"Index → keyword → article is the fastest path for any code lookup. Box fill: index → 'boxes, outlet, device' or 'fill, boxes' → Article 314.16. Table 314.16(B) lists volume allowances per conductor type. Using the index instead of scanning chapters can save 60–90 seconds per question — significant when 110 questions share 270 minutes."},
{id:509,mod:10,cat:"Calculations",diff:"Easy",q:"The NEC index lists 'GFCI protection, garages.' Which article does it point to?",opts:["Article 230.70","Article 250.30","Article 210.8","Article 314.16"],ans:2,ref:"NEC 210.8(A)(2)",exp:"GFCI protection for garage receptacles is in Article 210.8(A)(2). The index workflow — keyword → article → verify — is the fastest way to confirm code requirements on the open-book exam. Practice index lookups during study sessions so the habit is automatic by test day."},
{id:510,mod:10,cat:"Calculations",diff:"Hard",q:"You have 110 questions and 270 minutes. Load calculations take ~3 minutes and code lookups take ~30 seconds. What is the correct time management approach?",opts:["Answer all code lookup questions first, flag calculation questions, return to them at the end","Skip the last 20 questions to reserve time for calculations","Work through questions in order — never skip","Do all calculation questions first while concentration is highest"],ans:0,ref:"DLSE CA Journeyman Exam format",exp:"270 minutes ÷ 110 questions = ~2.5 minutes average. Code lookups (20–40 sec) and calculations (2–3 min) earn identical points. Answering fast code questions first maximizes total correct answers. Flag calculations, sweep the exam for quick points, then return. Never leave a flagged question blank — there is no penalty for guessing."},
{id:511,mod:10,cat:"Calculations",diff:"Medium",q:"What is the correct two-step process for sizing a conductor for a 50A continuous load at 75°C terminations?",opts:["Use Chapter 9 Table 9 for impedance-based sizing","Apply 125% rule (210.20A) → 62.5A minimum, then find first conductor meeting that in Table 310.16 at 75°C column","Look up 50A directly in Table 310.16 and use that conductor size","Estimate from field experience, confirm with inspector"],ans:1,ref:"NEC 210.20(A) & Table 310.16",exp:"Continuous load rule: 50A × 1.25 = 62.5A minimum conductor ampacity (NEC 210.20(A)). Then Table 310.16, 75°C column: 4 AWG copper = 70A — first size meeting 62.5A. This two-step pattern — identify the rule, apply the table — covers the majority of conductor sizing questions on the exam."},
{id:512,mod:10,cat:"Calculations",diff:"Medium",q:"During the exam you reach a complex motor circuit calculation. What is the best approach?",opts:["Flag it, continue answering code lookup questions, return to it at the end","Leave it blank — calculation questions are harder and worth attempting last","Guess immediately without flagging and move on permanently","Spend as much time as needed — one question can change a pass to a fail"],ans:0,ref:"DLSE CA Journeyman Exam format",exp:"All 110 questions carry equal weight. Flagging a hard calculation and returning later is not giving up — it's efficient scoring. A code question answered in 30 seconds earns the same point as a 3-minute calculation. Never leave a flagged question permanently blank: with 4 answer choices and no penalty for wrong answers, a guess is always worth making."},
];

